diffs.replacement:
{
  "name": "EventMaster Pro",
  "description": "Comprehensive event management system with payroll, staff tracking, and full accounting capabilities.",
  "requestFramePermissions": []
}

export type Role = 'Artista' | 'Manager' | 'Doble Voz' | 'DJ' | 'Otro';
export type PaymentType = 'FIXED' | 'PERCENTAGE';
export type TransactionType = 'INCOME' | 'EXPENSE';

export interface Staff {
  id: string;
  name: string;
  role: Role;
  paymentType: PaymentType;
  paymentValue: number; // Amount or Percentage
}

export interface EventStaff {
  staffId: string;
  amountToPay: number;
}

export interface Event {
  id: string;
  title: string;
  date: string;
  time: string;
  totalPrice: number;
  paidAmount: number;
  remainingAmount: number;
  assignedStaff: string[]; // Staff IDs
  status: 'PENDING' | 'PAID' | 'CANCELLED';
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  date: string;
  category: string;
  eventId?: string;
}

export interface PayrollEntry {
  id: string;
  staffId: string;
  eventId: string;
  amount: number;
  date: string;
  status: 'UNPAID' | 'PAID';
}

import { GoogleGenAI } from "@google/genai";
import { Transaction, Event } from "../types";

export const getFinancialInsights = async (transactions: Transaction[], events: Event[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Analiza los siguientes datos financieros de una empresa de gestión de eventos:
    Transacciones: ${JSON.stringify(transactions)}
    Eventos: ${JSON.stringify(events)}

    Por favor, proporciona un resumen corto (en español) sobre:
    1. Salud financiera actual.
    2. Recomendación para optimizar gastos.
    3. Proyección de ingresos basada en eventos pendientes.
    Mantenlo profesional y accionable.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "No se pudo generar el análisis en este momento.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar, 
  Users, 
  Wallet, 
  Plus, 
  Trash2, 
  CheckCircle2, 
  AlertCircle,
  TrendingUp,
  TrendingDown,
  BrainCircuit,
  DollarSign
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell 
} from 'recharts';
import { Staff, Event, Transaction, Role, PaymentType, PayrollEntry } from './types';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'events' | 'staff' | 'accounting' | 'payroll'>('dashboard');

  // Persistence Mock State (In-Memory for Demo)
  const [staff, setStaff] = useState<Staff[]>([
    { id: '1', name: 'DJ Shadow', role: 'DJ', paymentType: 'FIXED', paymentValue: 200 },
    { id: '2', name: 'Ana Manager', role: 'Manager', paymentType: 'PERCENTAGE', paymentValue: 10 },
  ]);

  const [events, setEvents] = useState<Event[]>([
    { 
      id: 'e1', 
      title: 'Boda de Verano', 
      date: '2024-08-20', 
      time: '18:00', 
      totalPrice: 2500, 
      paidAmount: 1000, 
      remainingAmount: 1500, 
      assignedStaff: ['1', '2'],
      status: 'PENDING'
    }
  ]);

  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: 't1', type: 'INCOME', amount: 1000, description: 'Abono Boda Verano', date: '2024-08-01', category: 'Evento' },
    { id: 't2', type: 'EXPENSE', amount: 150, description: 'Alquiler Luces', date: '2024-08-05', category: 'Logística' },
  ]);

  const [aiInsights, setAiInsights] = useState<string>('Haz clic en el botón para analizar tus finanzas con IA...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Computed Values
  const totals = useMemo(() => {
    const income = transactions.filter(t => t.type === 'INCOME').reduce((acc, curr) => acc + curr.amount, 0);
    const expense = transactions.filter(t => t.type === 'EXPENSE').reduce((acc, curr) => acc + curr.amount, 0);
    return { income, expense, balance: income - expense };
  }, [transactions]);

  const chartData = useMemo(() => {
    return [
      { name: 'Ingresos', value: totals.income },
      { name: 'Gastos', value: totals.expense },
    ];
  }, [totals]);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(transactions, events);
    setAiInsights(insights || 'Error al analizar.');
    setIsAnalyzing(false);
  };

  // Renderers
  return (
    <div className="flex h-screen bg-slate-100 font-sans">
      {/* Sidebar */}
      <nav className="w-64 bg-indigo-900 text-white flex flex-col shadow-xl">
        <div className="p-6 text-2xl font-bold border-b border-indigo-800 flex items-center gap-2">
          <Calendar className="w-8 h-8 text-indigo-400" />
          <span>EventMaster</span>
        </div>
        <div className="flex-1 mt-4 space-y-1 px-2">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal" active={activeTab === 'staff'} onClick={() => setActiveTab('staff')} />
          <NavItem icon={<Wallet />} label="Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
          <NavItem icon={<DollarSign />} label="Nómina" active={activeTab === 'payroll'} onClick={() => setActiveTab('payroll')} />
        </div>
        <div className="p-4 bg-indigo-950 text-xs text-indigo-300">
          v1.0.0 - Event Management Suite
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-8">
        <header className="mb-8 flex justify-between items-center">
          <h1 className="text-3xl font-bold text-slate-800">
            {activeTab === 'dashboard' && 'Panel Principal'}
            {activeTab === 'events' && 'Gestión de Eventos'}
            {activeTab === 'staff' && 'Gestión de Personal'}
            {activeTab === 'accounting' && 'Libro de Contabilidad'}
            {activeTab === 'payroll' && 'Cálculo de Nómina'}
          </h1>
          <div className="flex items-center gap-4">
             <div className="bg-white px-4 py-2 rounded-lg shadow-sm flex items-center gap-2 border border-slate-200">
                <span className="text-slate-500 text-sm">Balance:</span>
                <span className={`font-bold ${totals.balance >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  ${totals.balance.toLocaleString()}
                </span>
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' && (
          <Dashboard 
            totals={totals} 
            chartData={chartData} 
            events={events} 
            aiInsights={aiInsights} 
            handleAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing} 
          />
        )}
        {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'staff' && <StaffManager staff={staff} setStaff={setStaff} />}
        {activeTab === 'accounting' && <AccountingManager transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'payroll' && <PayrollManager events={events} staff={staff} />}
      </main>
    </div>
  );
};

// Sub-components
const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${active ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-indigo-800/50 text-indigo-200'}`}
  >
    {React.cloneElement(icon as React.ReactElement, { className: 'w-5 h-5' })}
    <span className="font-medium">{label}</span>
  </button>
);

const Dashboard: React.FC<{ 
  totals: any, 
  chartData: any[], 
  events: Event[], 
  aiInsights: string, 
  handleAnalyze: () => void, 
  isAnalyzing: boolean 
}> = ({ totals, chartData, events, aiInsights, handleAnalyze, isAnalyzing }) => (
  <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
    <div className="lg:col-span-2 space-y-6">
      {/* Cards */}
      <div className="grid grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="text-slate-400 text-sm mb-1 uppercase tracking-wider font-semibold">Ingresos Totales</div>
          <div className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <TrendingUp className="text-green-500" />
            ${totals.income.toLocaleString()}
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="text-slate-400 text-sm mb-1 uppercase tracking-wider font-semibold">Gastos Totales</div>
          <div className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <TrendingDown className="text-red-500" />
            ${totals.expense.toLocaleString()}
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="text-slate-400 text-sm mb-1 uppercase tracking-wider font-semibold">Próximos Eventos</div>
          <div className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <Calendar className="text-indigo-500" />
            {events.filter(e => e.status === 'PENDING').length}
          </div>
        </div>
      </div>

      {/* Chart */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-[350px]">
        <h3 className="text-lg font-bold mb-6 flex items-center gap-2">
          <Wallet className="text-indigo-600" /> Resumen Financiero
        </h3>
        <ResponsiveContainer width="100%" height="80%">
          <BarChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
            <XAxis dataKey="name" axisLine={false} tickLine={false} />
            <YAxis axisLine={false} tickLine={false} />
            <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
            <Bar dataKey="value" radius={[4, 4, 0, 0]}>
              {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={index === 0 ? '#4f46e5' : '#ef4444'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>

    {/* AI Sidebar */}
    <div className="space-y-6">
      <div className="bg-gradient-to-br from-indigo-600 to-violet-700 p-6 rounded-xl text-white shadow-lg">
        <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
          <BrainCircuit className="w-6 h-6" /> IA Insights
        </h3>
        <div className="bg-white/10 p-4 rounded-lg text-sm leading-relaxed mb-4 min-h-[150px] whitespace-pre-wrap italic">
          {aiInsights}
        </div>
        <button 
          onClick={handleAnalyze}
          disabled={isAnalyzing}
          className="w-full bg-white text-indigo-600 py-2 rounded-lg font-bold hover:bg-indigo-50 transition-colors disabled:opacity-50"
        >
          {isAnalyzing ? 'Analizando...' : 'Generar Análisis Inteligente'}
        </button>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="font-bold mb-4">Últimos Eventos</h3>
        <div className="space-y-4">
          {events.slice(0, 3).map(event => (
            <div key={event.id} className="flex justify-between items-center text-sm">
              <div>
                <div className="font-medium text-slate-700">{event.title}</div>
                <div className="text-xs text-slate-400">{event.date}</div>
              </div>
              <div className="font-bold text-slate-600">${event.totalPrice}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  </div>
);

const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, assignedStaff: [] as string[]
  });

  const handleAddEvent = (e: React.FormEvent) => {
    e.preventDefault();
    const newEvent: Event = {
      id: Date.now().toString(),
      ...formData,
      remainingAmount: formData.totalPrice - formData.paidAmount,
      status: 'PENDING'
    };
    setEvents([...events, newEvent]);

    // Auto-create income transaction if paidAmount > 0
    if (formData.paidAmount > 0) {
      const newTransaction: Transaction = {
        id: 't-' + Date.now(),
        type: 'INCOME',
        amount: formData.paidAmount,
        description: `Abono Inicial: ${formData.title}`,
        date: formData.date || new Date().toISOString().split('T')[0],
        category: 'Evento',
        eventId: newEvent.id
      };
      setTransactions([...transactions, newTransaction]);
    }

    setShowForm(false);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, assignedStaff: [] });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-md"
        >
          {showForm ? 'Cancelar' : <><Plus /> Nuevo Evento</>}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleAddEvent} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-slate-600 mb-1">Nombre del Evento</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Fecha</label>
            <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Hora</label>
            <input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Precio Total ($)</label>
            <input required type="number" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Abono Inicial ($)</label>
            <input required type="number" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: Number(e.target.value)})} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div className="col-span-2">
            <label className="block text-sm font-medium text-slate-600 mb-1">Personal Asignado</label>
            <div className="flex flex-wrap gap-2 mt-1">
              {staff.map(s => (
                <label key={s.id} className="flex items-center gap-2 bg-slate-100 px-3 py-1 rounded-full cursor-pointer hover:bg-slate-200 border border-slate-300">
                  <input 
                    type="checkbox" 
                    checked={formData.assignedStaff.includes(s.id)}
                    onChange={(e) => {
                      if (e.target.checked) setFormData({...formData, assignedStaff: [...formData.assignedStaff, s.id]});
                      else setFormData({...formData, assignedStaff: formData.assignedStaff.filter(id => id !== s.id)});
                    }}
                  />
                  <span className="text-xs font-semibold">{s.name} ({s.role})</span>
                </label>
              ))}
            </div>
          </div>
          <button type="submit" className="col-span-2 bg-indigo-600 text-white py-2 rounded-lg font-bold hover:bg-indigo-700 mt-2 shadow-lg">Guardar Evento</button>
        </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {events.map(event => (
          <div key={event.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow">
            <div className="flex justify-between items-start mb-4">
              <div>
                <h3 className="text-xl font-bold text-slate-800">{event.title}</h3>
                <div className="text-sm text-slate-400 flex items-center gap-1 mt-1">
                  <Calendar className="w-4 h-4" /> {event.date} a las {event.time}
                </div>
              </div>
              <span className={`px-2 py-1 rounded text-xs font-bold ${event.status === 'PENDING' ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'}`}>
                {event.status === 'PENDING' ? 'Pendiente' : 'Pagado'}
              </span>
            </div>

            <div className="space-y-3 mb-6">
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Precio Total</span>
                <span className="font-bold">${event.totalPrice.toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">Abonado</span>
                <span className="font-bold text-green-600">${event.paidAmount.toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-sm border-t pt-2 border-dashed">
                <span className="text-slate-500">Resta por pagar</span>
                <span className="font-bold text-red-600">${event.remainingAmount.toLocaleString()}</span>
              </div>
            </div>

            <div className="flex gap-2">
               <button 
                 onClick={() => {
                   setEvents(events.filter(e => e.id !== event.id));
                   setTransactions(transactions.filter(t => t.eventId !== event.id));
                 }} 
                 className="p-2 text-red-500 hover:bg-red-50 rounded-lg"
               >
                 <Trash2 className="w-5 h-5" />
               </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const StaffManager: React.FC<{ staff: Staff[], setStaff: any }> = ({ staff, setStaff }) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState<Omit<Staff, 'id'>>({
    name: '', role: 'Otro', paymentType: 'FIXED', paymentValue: 0
  });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    setStaff([...staff, { ...formData, id: Date.now().toString() }]);
    setShowForm(false);
    setFormData({ name: '', role: 'Otro', paymentType: 'FIXED', paymentValue: 0 });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center">
        <h3 className="font-bold text-lg">Personal Activo</h3>
        <button onClick={() => setShowForm(!showForm)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2">
          {showForm ? 'Cancelar' : <><Plus className="w-4 h-4" /> Agregar Personal</>}
        </button>
      </div>
      {showForm && (
        <form onSubmit={handleAdd} className="p-6 bg-slate-50 border-b border-slate-100 grid grid-cols-4 gap-4 animate-in slide-in-from-top-4">
          <div className="col-span-2">
            <label className="block text-xs font-bold uppercase text-slate-500 mb-1">Nombre</label>
            <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <div>
            <label className="block text-xs font-bold uppercase text-slate-500 mb-1">Rol</label>
            <select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})} className="w-full p-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500">
              <option>Artista</option>
              <option>Manager</option>
              <option>Doble Voz</option>
              <option>DJ</option>
              <option>Otro</option>
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold uppercase text-slate-500 mb-1">Tipo Pago</label>
            <select value={formData.paymentType} onChange={e => setFormData({...formData, paymentType: e.target.value as PaymentType})} className="w-full p-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500">
              <option value="FIXED">Fijo por Evento</option>
              <option value="PERCENTAGE">% del Total</option>
            </select>
          </div>
          <div className="col-span-1">
            <label className="block text-xs font-bold uppercase text-slate-500 mb-1">Monto / %</label>
            <input required type="number" value={formData.paymentValue} onChange={e => setFormData({...formData, paymentValue: Number(e.target.value)})} className="w-full p-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <div className="col-span-3"></div>
          <button type="submit" className="bg-indigo-600 text-white py-2 rounded-lg font-bold hover:bg-indigo-700">Guardar</button>
        </form>
      )}
      <table className="w-full text-left">
        <thead className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider font-bold">
          <tr>
            <th className="px-6 py-4">Nombre</th>
            <th className="px-6 py-4">Rol</th>
            <th className="px-6 py-4">Base Pago</th>
            <th className="px-6 py-4">Acciones</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {staff.map(s => (
            <tr key={s.id} className="hover:bg-slate-50 transition-colors">
              <td className="px-6 py-4 font-medium">{s.name}</td>
              <td className="px-6 py-4">
                <span className="bg-indigo-50 text-indigo-700 px-2 py-1 rounded-md text-xs font-bold uppercase">{s.role}</span>
              </td>
              <td className="px-6 py-4 text-sm">
                {s.paymentType === 'FIXED' ? `$${s.paymentValue} fijo` : `${s.paymentValue}% del total`}
              </td>
              <td className="px-6 py-4">
                <button onClick={() => setStaff(staff.filter(st => st.id !== s.id))} className="text-red-400 hover:text-red-600 transition-colors">
                  <Trash2 className="w-4 h-4" />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({
