          <NavItem icon={<DollarSign />} label="Nómina" active={activeTab === 'payroll'} onClick={() => setActiveTab('payroll')} />
        </div>
        <div className="p-6 border-t border-zinc-800">
          <div className="text-[10px] uppercase font-bold text-zinc-500 mb-2">Moneda Principal</div>
          <select 
            value={primaryCurrency} 
            onChange={(e) => setPrimaryCurrency(e.target.value as Currency)}
            className="w-full bg-zinc-900 border border-zinc-800 text-xs p-2 rounded focus:outline-none"
          >
            <option value="DOP">DOP - Peso Dominicano</option>
            <option value="USD">USD - Dólar Estadounidense</option>
          </select>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-10">
        <header className="mb-12 flex justify-between items-end border-b border-zinc-200 pb-8">
          <div>
            <h1 className="text-4xl font-black text-black tracking-tight mb-2">
              {activeTab === 'dashboard' && 'Visión General'}
              {activeTab === 'events' && 'Eventos'}
              {activeTab === 'staff' && 'Equipo RF'}
              {activeTab === 'accounting' && 'Finanzas'}
              {activeTab === 'payroll' && 'Cierre de Nómina'}
            </h1>
            <p className="text-zinc-400 font-medium">Gestiona tu estudio con precisión y elegancia.</p>
          </div>
          <div className="flex gap-4">
             <div className="bg-white px-6 py-3 rounded-none border border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]">
                <div className="text-[10px] uppercase font-bold text-zinc-400 mb-1">Balance {primaryCurrency}</div>
                <div className={`text-xl font-black ${totals[primaryCurrency].balance >= 0 ? 'text-black' : 'text-red-500'}`}>
                  {primaryCurrency === 'USD' ? '$' : 'RD$'}{totals[primaryCurrency].balance.toLocaleString()}
                </div>
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' && (
          <Dashboard 
            totals={totals} 
            primaryCurrency={primaryCurrency}
            events={events} 
            aiInsights={aiInsights} 
            handleAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing} 
          />
        )}
        {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'staff' && <StaffManager staff={staff} setStaff={setStaff} />}
        {activeTab === 'accounting' && <AccountingManager transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'payroll' && <PayrollManager events={events} staff={staff} />}
      </main>
    </div>
  );
};

