export type TransactionType = 'INCOME' | 'EXPENSE';
export type Currency = 'USD' | 'DOP';

export interface Staff {
  id: string;
  name: string;
  role: Role;
  paymentType: PaymentType;
  paymentValue: number;
  currency: Currency;
}

