    const calc = (curr: Currency) => {
      const income = transactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = transactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [transactions]);

