const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);
  const [formData, setFormData] = useState({
    title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP' as Currency, assignedStaff: [] as string[]
  });

  const [closingExpenses, setClosingExpenses] = useState({
    fuel: 0,
    toll: 0,
    diet: 0,
    others: 0,
    currency: 'DOP' as Currency
  });

  const handleAddEvent = (e: React.FormEvent) => {
    e.preventDefault();
    const newEvent: Event = {
      id: Date.now().toString(),
      ...formData,
      remainingAmount: formData.totalPrice - formData.paidAmount,
      status: 'PENDING',
      completed: false
    };
    setEvents([...events, newEvent]);

    if (formData.paidAmount > 0) {
      const newTransaction: Transaction = {
        id: 't-' + Date.now(),
        type: 'INCOME',
        amount: formData.paidAmount,
        currency: formData.currency,
        description: `Abono: ${formData.title}`,
        date: formData.date || new Date().toISOString().split('T')[0],
        category: 'Evento',
        eventId: newEvent.id
      };
      setTransactions([...transactions, newTransaction]);
    }

    setShowForm(false);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP', assignedStaff: [] });
  };

  const handleCompleteEvent = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;

    const eventDate = closingEvent.date;
    const newTransactions: Transaction[] = [];

    // 1. Add Closing Expenses
    const categories = [
      { key: 'fuel', label: 'Combustible', cat: 'Logística' },
      { key: 'toll', label: 'Peaje', cat: 'Logística' },
      { key: 'diet', label: 'Dieta', cat: 'Operación' },
      { key: 'others', label: 'Otros Gastos', cat: 'Varios' }
    ];

    categories.forEach(c => {
      const val = (closingExpenses as any)[c.key];
      if (val > 0) {
        newTransactions.push({
          id: `exp-${closingEvent.id}-${c.key}-${Date.now()}`,
          type: 'EXPENSE',
          amount: val,
          currency: closingExpenses.currency,
          description: `${c.label}: ${closingEvent.title}`,
          date: new Date().toISOString().split('T')[0],
          category: c.cat,
          eventId: closingEvent.id
        });
      }
    });

    // 2. Auto-generate Payroll Payments as transactions
    closingEvent.assignedStaff.forEach(staffId => {
      const s = staff.find(st => st.id === staffId);
      if (s) {
        const payment = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTransactions.push({
          id: `pay-${closingEvent.id}-${s.id}-${Date.now()}`,
          type: 'EXPENSE',
          amount: payment,
          currency: s.currency,
          description: `Pago Staff (${s.name}): ${closingEvent.title}`,
          date: new Date().toISOString().split('T')[0],
          category: 'Nómina',
          eventId: closingEvent.id
        });
      }
    });

    // 3. Mark event as fully paid (income transaction for remainder)
    if (closingEvent.remainingAmount > 0) {
      newTransactions.push({
        id: `inc-rem-${closingEvent.id}-${Date.now()}`,
        type: 'INCOME',
        amount: closingEvent.remainingAmount,
        currency: closingEvent.currency,
        description: `Liquidación Final: ${closingEvent.title}`,
        date: new Date().toISOString().split('T')[0],
        category: 'Evento',
        eventId: closingEvent.id
      });
    }

    // Update states
    setTransactions([...newTransactions, ...transactions]);
    setEvents(events.map(ev => 
      ev.id === closingEvent.id 
        ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } 
        : ev
    ));

    setClosingEvent(null);
    setClosingExpenses({ fuel: 0, toll: 0, diet: 0, others: 0, currency: 'DOP' });
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-black text-white px-8 py-3 text-xs font-black uppercase tracking-widest hover:bg-zinc-800"
        >
          {showForm ? 'Cerrar' : '+ Agendar Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleAddEvent} className="bg-white p-10 border border-black grid grid-cols-3 gap-6 animate-in fade-in duration-300">
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Nombre del Proyecto</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none" placeholder="EJ: SHOOTING NIKE 2024" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Fecha</label>
            <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Hora</label>
            <input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Moneda</label>
            <select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none">
              <option value="DOP">DOP - Peso Dom.</option>
              <option value="USD">USD - Dólar</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Precio Total</label>
            <input required type="number" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Abono Inicial</label>
            <input required type="number" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none" />
          </div>
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Staff Requerido</label>
            <div className="grid grid-cols-4 gap-4 mt-2">
              {staff.map(s => (
                <label key={s.id} className={`flex items-center gap-3 p-4 border cursor-pointer transition-colors ${formData.assignedStaff.includes(s.id) ? 'border-black bg-zinc-50' : 'border-zinc-100 hover:border-zinc-300'}`}>
                  <input 
                    type="checkbox" 
                    className="accent-black"
                    checked={formData.assignedStaff.includes(s.id)}
                    onChange={(e) => {
                      if (e.target.checked) setFormData({...formData, assignedStaff: [...formData.assignedStaff, s.id]});
                      else setFormData({...formData, assignedStaff: formData.assignedStaff.filter(id => id !== s.id)});
                    }}
                  />
                  <span className="text-[10px] font-black uppercase">{s.name} ({s.role})</span>
                </label>
              ))}
            </div>
          </div>
          <button type="submit" className="col-span-3 bg-black text-white py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 mt-4">Registrar Evento en RFStudio</button>
        </form>
      )}

      {/* Completion Modal */}
      {closingEvent && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white border-2 border-black w-full max-w-lg animate-in zoom-in duration-200">
            <div className="p-8 border-b border-zinc-100 flex justify-between items-center">
              <h2 className="text-xl font-black uppercase tracking-tighter">Cierre de Proyecto: {closingEvent.title}</h2>
              <button onClick={() => setClosingEvent(null)} className="text-zinc-400 hover:text-black">
                <X className="w-6 h-6" />
              </button>
            </div>
            <form onSubmit={handleCompleteEvent} className="p-8 space-y-6">
              <div className="bg-zinc-50 p-4 border border-zinc-200 text-[10px] font-bold uppercase tracking-widest text-zinc-500">
                Al confirmar, se generarán automáticamente los asientos contables de gastos y nómina.
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[8px] font-black uppercase text-zinc-400 mb-1 flex items-center gap-1">
                    <GasStation className="w-3 h-3" /> Combustible
                  </label>
                  <input type="number" value={closingExpenses.fuel} onChange={e => setClosingExpenses({...closingExpenses, fuel: Number(e.target.value)})} className="w-full p-3 border border-zinc-200 text-xs" />
                </div>
                <div>
                  <label className="block text-[8px] font-black uppercase text-zinc-400 mb-1 flex items-center gap-1">
                    <MapPin className="w-3 h-3" /> Peaje
                  </label>
                  <input type="number" value={closingExpenses.toll} onChange={e => setClosingExpenses({...closingExpenses, toll: Number(e.target.value)})} className="w-full p-3 border border-zinc-200 text-xs" />
                </div>
                <div>
                  <label className="block text-[8px] font-black uppercase text-zinc-400 mb-1 flex items-center gap-1">
                    <Utensils className="w-3 h-3" /> Dieta
                  </label>
                  <input type="number" value={closingExpenses.diet} onChange={e => setClosingExpenses({...closingExpenses, diet: Number(e.target.value)})} className="w-full p-3 border border-zinc-200 text-xs" />
                </div>
                <div>
                  <label className="block text-[8px] font-black uppercase text-zinc-400 mb-1">Otros Gastos</label>
                  <input type="number" value={closingExpenses.others} onChange={e => setClosingExpenses({...closingExpenses, others: Number(e.target.value)})} className="w-full p-3 border border-zinc-200 text-xs" />
                </div>
              </div>

              <div>
                <label className="block text-[8px] font-black uppercase text-zinc-400 mb-1">Moneda de Gastos de Cierre</label>
                <select value={closingExpenses.currency} onChange={e => setClosingExpenses({...closingExpenses, currency: e.target.value as Currency})} className="w-full p-3 border border-zinc-200 text-xs">
                  <option value="DOP">DOP</option>
                  <option value="USD">USD</option>
                </select>
              </div>

              <div className="pt-4">
                 <h4 className="text-[10px] font-black uppercase tracking-widest mb-4">Pagos de Staff Incluidos:</h4>
                 <div className="space-y-2">
                    {closingEvent.assignedStaff.map(sid => {
                      const s = staff.find(st => st.id === sid);
                      const payment = s ? (s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100))) : 0;
                      return (
                        <div key={sid} className="flex justify-between text-[10px] font-bold uppercase tracking-tight text-zinc-600">
                          <span>{s?.name} ({s?.role})</span>
                          <span>{s?.currency} {payment.toLocaleString()}</span>
                        </div>
                      );
                    })}
                 </div>
              </div>

              <button type="submit" className="w-full bg-black text-white py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800">
                Finalizar Proyecto y Asentar Finanzas
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {events.map(event => (
          <div key={event.id} className={`bg-white p-10 border group relative transition-all ${event.completed ? 'border-zinc-100 opacity-60' : 'border-zinc-200 hover:border-black'}`}>
            <div className="flex justify-between items-start mb-8">
              <div>
                <h3 className="text-2xl font-black text-black tracking-tighter uppercase flex items-center gap-2">
                  {event.title}
                  {event.completed && <CheckCircle2 className="w-6 h-6 text-black" />}
                </h3>
                <div className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mt-2">{event.date} — {event.time}</div>
              </div>
              <div className="flex flex-col items-end gap-2">
                <span className={`px-3 py-1 text-[8px] font-black uppercase tracking-widest ${event.completed ? 'bg-zinc-100 text-zinc-400' : 'bg-black text-white'}`}>
                  {event.status === 'PENDING' ? 'Pendiente' : 'Liquidado'}
                </span>
                {!event.completed && (
                  <button 
                    onClick={() => setClosingEvent(event)}
                    className="flex items-center gap-1 text-[8px] font-black uppercase tracking-widest text-zinc-400 hover:text-black transition-colors border border-dashed border-zinc-200 px-2 py-1 hover:border-black"
                  >
                    Confirmar Realización <CheckCircle2 className="w-3 h-3" />
                  </button>
                )}
              </div>
            </div>

            <div className="grid grid-cols-3 gap-6 mb-10 border-y border-zinc-100 py-6">
              <div>
                <div className="text-[8px] font-black text-zinc-400 uppercase mb-1">Total</div>
                <div className="text-sm font-black text-black">{event.currency === 'USD' ? '$' : 'RD$'}{event.totalPrice.toLocaleString()}</div>
              </div>
              <div>
                <div className="text-[8px] font-black text-zinc-400 uppercase mb-1">Abonado</div>
                <div className="text-sm font-black text-zinc-800">{event.currency === 'USD' ? '$' : 'RD$'}{event.paidAmount.toLocaleString()}</div>
              </div>
              <div>
                <div className="text-[8px] font-black text-zinc-400 uppercase mb-1">Resta</div>
                <div className="text-sm font-black text-red-500">{event.currency === 'USD' ? '$' : 'RD$'}{event.remainingAmount.toLocaleString()}</div>
              </div>
            </div>

            <div className="flex justify-between items-center">
               <div className="flex -space-x-2">
                  {event.assignedStaff.map(sid => {
                    const s = staff.find(st => st.id === sid);
                    return s ? (
                      <div key={sid} className="w-8 h-8 bg-zinc-100 border border-white flex items-center justify-center text-[10px] font-black uppercase" title={s.name}>
                        {s.name.charAt(0)}
                      </div>
                    ) : null;
                  })}
               </div>
               <button 
                 onClick={() => setEvents(events.filter(e => e.id !== event.id))} 
                 className="p-2 text-zinc-200 hover:text-black transition-colors"
               >
                 <Trash2 className="w-4 h-4" />
               </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

