          </div>
          <div>
            <label className="block text-[8px] font-black uppercase text-zinc-400 mb-2">Rol</label>
            <select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})} className="w-full p-4 border border-zinc-200 rounded-none focus:border-black outline-none text-xs">
