            Importación Masiva
          </button>
          <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase tracking-widest">
            {showForm ? 'Cerrar' : '+ Transacción'}
          </button>
        </div>
      </div>

      {showImport && (
        <div className="p-10 bg-zinc-900 text-white animate-in slide-in-from-top-4">
          <h4 className="text-[10px] font-black uppercase tracking-widest mb-4">Pegar datos CSV</h4>
          <p className="text-[8px] mb-4 opacity-50 uppercase font-black">Formato: fecha,tipo,monto,moneda,descripcion,categoria (ej: 2024-09-10,EXPENSE,150,USD,Comida,Varios)</p>
          <textarea 
            value={importText} 
            onChange={e => setImportText(e.target.value)}
            className="w-full h-32 bg-zinc-800 border border-zinc-700 p-4 text-xs font-mono mb-4 outline-none focus:border-white"
            placeholder="2024-09-10,INCOME,500,USD,Cliente A,Ventas"
