                <div className="space-y-2">
                    {closingEvent.assignedStaff.map(sid => {
                      const s = staff.find(st => st.id === sid);
                      const payment = s ? (s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100))) : 0;
                      return (
                        <div key={sid} className="flex justify-between text-[10px] font-black uppercase tracking-tight border-b border-zinc-100 pb-2 last:border-0">
                          <span className="text-zinc-500">{s?.name} ({s?.role})</span>
                          <span className="text-black">{s?.currency} {payment.toLocaleString()}</span>
                        </div>
                      );
                    })}
                </div>
              </div>

              <button type="submit" className="w-full bg-black text-white py-5 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 shadow-xl transition-all">
