              </button>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {events.map(event => (
          <div key={event.id} className={`bg-white p-10 border relative transition-all duration-300 ${event.completed ? 'border-zinc-100 opacity-50 bg-zinc-50/50' : 'border-zinc-200 hover:border-black hover:shadow-2xl'}`}>
