                </span>
                {!event.completed && (
                  <button 
                    onClick={() => setClosingEvent(event)}
                    className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-zinc-400 hover:text-black transition-colors bg-white border border-zinc-200 px-3 py-2 hover:border-black"
                  >
                    Marcar Completado <CheckCircle2 className="w-4 h-4" />
                  </button>
