            </div>

            <div className="grid grid-cols-3 gap-8 mb-10 border-y border-zinc-100 py-8">
              <div>
                <div className="text-[9px] font-black text-zinc-400 uppercase mb-2 tracking-widest">Contrato</div>
                <div className="text-sm font-black text-black tracking-tighter">{event.currency === 'USD' ? '$' : 'RD$'}{event.totalPrice.toLocaleString()}</div>
              </div>
              <div>
                <div className="text-[9px] font-black text-zinc-400 uppercase mb-2 tracking-widest">Abonado</div>
                <div className="text-sm font-black text-zinc-800 tracking-tighter">{event.currency === 'USD' ? '$' : 'RD$'}{event.paidAmount.toLocaleString()}</div>
              </div>
              <div>
                <div className="text-[9px] font-black text-zinc-400 uppercase mb-2 tracking-widest">Cierre</div>
                <div className="text-sm font-black text-red-500 tracking-tighter">{event.currency === 'USD' ? '$' : 'RD$'}{event.remainingAmount.toLocaleString()}</div>
              </div>
            </div>

            <div className="flex justify-between items-center">
               <div className="flex -space-x-3">
                  {event.assignedStaff.map(sid => {
                    const s = staff.find(st => st.id === sid);
                    return s ? (
                      <div key={sid} className="w-10 h-10 bg-black text-white border-2 border-white flex items-center justify-center text-[11px] font-black uppercase tracking-tighter" title={`${s.name} (${s.role})`}>
                        {s.name.charAt(0)}
                      </div>
                    ) : null;
                  })}
               </div>
               <button 
                 onClick={() => setEvents(events.filter(e => e.id !== event.id))} 
                 className="p-3 text-zinc-300 hover:text-red-500 transition-colors bg-white border border-transparent hover:border-red-100"
               >
                 <Trash2 className="w-5 h-5" />
               </button>
            </div>
          </div>
        ))}
        {events.length === 0 && (
          <div className="col-span-2 py-32 border-2 border-dashed border-zinc-100 flex flex-col items-center justify-center opacity-30">
             <Calendar className="w-16 h-16 mb-4" />
             <p className="font-black uppercase tracking-widest text-sm">No hay eventos registrados</p>
          </div>
        )}
      </div>
    </div>
  );
};

