const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [importText, setImportText] = useState('');
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({
    type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General'
  });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    setTransactions([{ ...formData, id: Date.now().toString() }, ...transactions]);
    setShowForm(false);
  };

  const handleBulkImport = () => {
    try {
      const lines = importText.trim().split('\n');
      const newTransactions: Transaction[] = lines.map((line, index) => {
        const [date, type, amount, currency, description, category] = line.split(',');
        return {
          id: `bulk-${Date.now()}-${index}`,
          date: date.trim(),
          type: type.trim().toUpperCase() as 'INCOME' | 'EXPENSE',
          amount: Number(amount.trim()),
          currency: currency.trim().toUpperCase() as Currency,
          description: description.trim(),
          category: category.trim()
        };
      });
      setTransactions([...newTransactions, ...transactions]);
      setShowImport(false);
      setImportText('');
    } catch (e) {
      alert('Error en el formato. Usa: YYYY-MM-DD,TIPO(INCOME/EXPENSE),MONTO,MONEDA(USD/DOP),DESC,CAT');
    }
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-sm overflow-hidden">
      <div className="p-10 border-b border-zinc-200 flex justify-between items-center bg-white">
        <h3 className="text-xl font-black uppercase tracking-tighter">Libro de Caja y Transacciones</h3>
        <div className="flex gap-4">
          <button onClick={() => setShowImport(!showImport)} className="border-2 border-black px-6 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-50 flex items-center gap-2">
            <Upload className="w-3 h-3" /> Importar CSV
          </button>
          <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-8 py-4 text-[10px] font-black uppercase tracking-widest shadow-lg">
            {showForm ? 'Cerrar' : '+ Registrar Movimiento'}
          </button>
