              </div>
              <button onClick={() => setClosingEvent(null)} className="text-zinc-400 hover:text-black">
                <X className="w-6 h-6" />
              </button>
            </div>
            <form onSubmit={handleCompleteEvent} className="p-10 space-y-8">
              <div className="grid grid-cols-2 gap-8">
                <div>
                  <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2 flex items-center gap-2">
                    <Fuel className="w-3 h-3 text-black" /> Combustible
                  </label>
                  <input type="number" value={closingExpenses.fuel} onChange={e => setClosingExpenses({...closingExpenses, fuel: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 outline-none focus:border-black font-bold" />
                </div>
                <div>
                  <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2 flex items-center gap-2">
                    <MapPin className="w-3 h-3 text-black" /> Peaje
