                </div>
                <div>
                  <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Otros Gastos</label>
                  <input type="number" value={closingExpenses.others} onChange={e => setClosingExpenses({...closingExpenses, others: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 outline-none focus:border-black font-bold" />
