              <div className="bg-zinc-50 p-6 border border-zinc-200 space-y-4">
                <div className="flex justify-between items-center">
                   <h4 className="text-[10px] font-black uppercase tracking-widest">Liquidación Personal:</h4>
                   <select value={closingExpenses.currency} onChange={e => setClosingExpenses({...closingExpenses, currency: e.target.value as Currency})} className="bg-white border border-zinc-200 text-[10px] p-2 outline-none font-bold uppercase tracking-widest">
                    <option value="DOP">DOP</option>
                    <option value="USD">USD</option>
                  </select>
                </div>
                <div className="space-y-2">
                    {closingEvent.assignedStaff.map(sid => {
                      const s = staff.find(st => st.id === sid);
                      const payment = s ? (s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100))) : 0;
                      return (
                        <div key={sid} className="flex justify-between text-[10px] font-black uppercase tracking-tight border-b border-zinc-100 pb-2 last:border-0">
                          <span className="text-zinc-500">{s?.name} ({s?.role})</span>
                          <span className="text-black">{s?.currency} {payment.toLocaleString()}</span>
                        </div>
                      );
                    })}
                </div>
              </div>

              <button type="submit" className="w-full bg-black text-white py-5 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 shadow-xl transition-all">
                Finalizar y Liquidar Contablemente
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {activeEvents.map(event => (
          <div key={event.id} className="bg-white p-10 border relative transition-all duration-300 border-zinc-200 hover:border-black hover:shadow-2xl">
