    e.preventDefault();
    if (editingStaff) {
      setStaff(staff.map(s => s.id === editingStaff.id ? { ...formData, id: editingStaff.id } : s));
    } else {
      setStaff([...staff, { ...formData, id: Date.now().toString() }]);
    }
    closeForm();
  };

