    { id: '2', name: 'Ana Manager', role: 'Manager', paymentType: 'PERCENTAGE', paymentValue: 10, currency: 'DOP' },
  ]);

  const [events, setEvents] = useState<Event[]>([
    { 
      id: 'e1', 
      title: 'Concierto Gala', 
      date: '2024-12-15', 
      time: '20:00', 
      totalPrice: 5000, 
      paidAmount: 2000, 
      remainingAmount: 3000, 
      currency: 'USD',
      assignedStaff: ['1', '2'],
      status: 'PENDING',
      completed: false
    }
  ]);

  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: 't1', type: 'INCOME', amount: 2000, currency: 'USD', description: 'Reserva Gala', date: '2024-09-01', category: 'Evento' },
    { id: 't2', type: 'EXPENSE', amount: 5000, currency: 'DOP', description: 'Transporte', date: '2024-09-05', category: 'Logística' },
  ]);

  const [aiInsights, setAiInsights] = useState<string>('Haz clic para un análisis profundo de tu flujo multi-moneda...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const totals = useMemo(() => {
    const calc = (curr: Currency) => {
      const income = transactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = transactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [transactions]);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(transactions, events);
    setAiInsights(insights || 'Error al analizar.');
    setIsAnalyzing(false);
  };

  return (
    <div className="flex h-screen bg-[#fafafa] font-sans selection:bg-black selection:text-white">
      {/* Sidebar */}
      <nav className="w-64 bg-black text-white flex flex-col">
        <div className="p-8 text-2xl font-black tracking-tighter border-b border-zinc-800">
          RF<span className="text-zinc-500">STUDIO</span>
        </div>
        <div className="flex-1 mt-6 space-y-1 px-4">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal" active={activeTab === 'personal'} onClick={() => setActiveTab('personal')} />
          <NavItem icon={<Wallet />} label="Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
        </div>
        <div className="p-8 border-t border-zinc-800">
          <div className="text-[9px] font-black text-zinc-500 uppercase tracking-[0.2em]">Management System v2.6</div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-10">
        <header className="mb-12 flex justify-between items-end border-b border-zinc-200 pb-8">
          <div>
            <h1 className="text-4xl font-black text-black tracking-tight mb-2">
              {activeTab === 'dashboard' && 'Panel Multi-Moneda'}
              {activeTab === 'events' && 'Agenda Activa'}
              {activeTab === 'personal' && 'Gestión de Equipo'}
              {activeTab === 'accounting' && 'Flujo de Caja'}
            </h1>
            <p className="text-zinc-400 font-medium tracking-tight">Control total de ingresos y egresos en USD y DOP.</p>
          </div>
          <div className="flex gap-4">
             <div className="bg-white px-6 py-4 rounded-none border border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] flex gap-8">
                <div>
                  <div className="text-[10px] uppercase font-bold text-zinc-400 mb-1">Caja DOP</div>
                  <div className={`text-lg font-black ${totals.DOP.balance >= 0 ? 'text-black' : 'text-red-500'}`}>
                    RD$ {totals.DOP.balance.toLocaleString()}
                  </div>
                </div>
                <div className="border-l border-zinc-100 pl-8">
                  <div className="text-[10px] uppercase font-bold text-zinc-400 mb-1">Caja USD</div>
                  <div className={`text-lg font-black ${totals.USD.balance >= 0 ? 'text-black' : 'text-red-500'}`}>
                    $ {totals.USD.balance.toLocaleString()}
                  </div>
                </div>
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' && (
          <Dashboard 
            transactions={transactions}
            totals={totals} 
            events={events} 
            staff={staff}
            aiInsights={aiInsights} 
            handleAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing} 
          />
        )}
        {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'personal' && <StaffManager staff={staff} setStaff={setStaff} />}
        {activeTab === 'accounting' && <AccountingManager transactions={transactions} setTransactions={setTransactions} />}
      </main>
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 transition-all duration-200 ${active ? 'bg-white text-black' : 'text-zinc-500 hover:text-white hover:bg-zinc-900'}`}
  >
    {React.cloneElement(icon as React.ReactElement, { className: 'w-4 h-4' })}
    <span className="text-xs font-bold uppercase tracking-widest">{label}</span>
  </button>
);

const Dashboard: React.FC<{ 
  transactions: Transaction[],
  totals: any, 
  events: Event[], 
  staff: Staff[],
  aiInsights: string, 
  handleAnalyze: () => void, 
  isAnalyzing: boolean 
}> = ({ transactions, totals, events, staff, aiInsights, handleAnalyze, isAnalyzing }) => {
  const completedCount = events.filter(e => e.completed).length;
  const pendingCount = events.filter(e => !e.completed).length;

  const upcomingEvents = events
    .filter(e => !e.completed && new Date(e.date) >= new Date())
    .sort((a,b) => a.date.localeCompare(b.date));

  const receivableUSD = events.filter(e => !e.completed && e.currency === 'USD').reduce((acc, c) => acc + c.remainingAmount, 0);
  const receivableDOP = events.filter(e => !e.completed && e.currency === 'DOP').reduce((acc, c) => acc + c.remainingAmount, 0);

  const marginUSD = totals.USD.income > 0 ? ((totals.USD.balance / totals.USD.income) * 100).toFixed(1) : '0';
  const marginDOP = totals.DOP.income > 0 ? ((totals.DOP.balance / totals.DOP.income) * 100).toFixed(1) : '0';

  // Stats by category
  const statsByCategory = useMemo(() => {
    const categories: Record<string, { incomeUSD: number, incomeDOP: number, expenseUSD: number, expenseDOP: number }> = {};
    transactions.forEach(t => {
      if (!categories[t.category]) categories[t.category] = { incomeUSD: 0, incomeDOP: 0, expenseUSD: 0, expenseDOP: 0 };
      if (t.type === 'INCOME') {
        if (t.currency === 'USD') categories[t.category].incomeUSD += t.amount;
        else categories[t.category].incomeDOP += t.amount;
      } else {
        if (t.currency === 'USD') categories[t.category].expenseUSD += t.amount;
        else categories[t.category].expenseDOP += t.amount;
      }
    });
    return Object.entries(categories).map(([name, data]) => ({ name, ...data }));
  }, [transactions]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 pb-20">
      {/* Metrics Grid */}
      <div className="lg:col-span-4 grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard label="Ingresos Totales" usd={totals.USD.income} dop={totals.DOP.income} />
        <MetricCard label="Gastos Totales" usd={totals.USD.expense} dop={totals.DOP.expense} />
        <div className="bg-white p-6 border border-zinc-200 shadow-sm">
          <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-400 mb-4">Margen de Beneficio</div>
          <div className="space-y-2">
            <div className="flex justify-between items-end border-b border-zinc-50 pb-2">
              <span className="text-[10px] font-bold text-zinc-400">USD</span>
              <span className="text-xl font-black">{marginUSD}%</span>
            </div>
            <div className="flex justify-between items-end pt-1">
              <span className="text-[10px] font-bold text-zinc-400">DOP</span>
              <span className="text-xl font-black">{marginDOP}%</span>
            </div>
          </div>
        </div>
        <MetricCard label="Cuentas por Cobrar" usd={receivableUSD} dop={receivableDOP} highlightRed />
      </div>

      {/* Main Area */}
      <div className="lg:col-span-3 space-y-8">
        {/* Category breakdown charts */}
        <div className="bg-white p-10 border border-zinc-200">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-10">
              <Filter className="w-4 h-4" /> Desglose por Categoría (Estadísticas)
           </h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
             <div>
               <div className="text-[10px] font-black uppercase text-zinc-400 mb-4">Ingresos por Categoría</div>
               <div className="space-y-4">
                 {statsByCategory.filter(s => s.incomeUSD > 0 || s.incomeDOP > 0).map(s => (
                   <div key={s.name}>
                     <div className="flex justify-between text-[10px] font-black uppercase mb-1">
                       <span>{s.name}</span>
                       <span className="text-zinc-400 text-[8px] tracking-tight">
                         ${s.incomeUSD.toLocaleString()} / RD$ {s.incomeDOP.toLocaleString()}
                       </span>
                     </div>
                     <div className="h-1.5 bg-zinc-50 w-full overflow-hidden">
                       <div 
                        className="h-full bg-black transition-all duration-500" 
                        style={{ width: `${Math.min(100, (s.incomeUSD + (s.incomeDOP/58)) / (totals.USD.income + (totals.DOP.income/58)) * 100)}%` }} 
                       />
                     </div>
                   </div>
                 ))}
               </div>
             </div>
             <div>
               <div className="text-[10px] font-black uppercase text-zinc-400 mb-4">Gastos por Categoría</div>
               <div className="space-y-4">
                 {statsByCategory.filter(s => s.expenseUSD > 0 || s.expenseDOP > 0).map(s => (
                   <div key={s.name}>
                     <div className="flex justify-between text-[10px] font-black uppercase mb-1">
                       <span>{s.name}</span>
                       <span className="text-zinc-400 text-[8px] tracking-tight">
                         ${s.expenseUSD.toLocaleString()} / RD$ {s.expenseDOP.toLocaleString()}
                       </span>
                     </div>
                     <div className="h-1.5 bg-zinc-50 w-full overflow-hidden">
                       <div 
                        className="h-full bg-zinc-300 transition-all duration-500" 
                        style={{ width: `${Math.min(100, (s.expenseUSD + (s.expenseDOP/58)) / (totals.USD.expense + (totals.DOP.expense/58)) * 100)}%` }} 
                       />
                     </div>
                   </div>
                 ))}
               </div>
             </div>
           </div>
        </div>

        <div className="bg-white p-10 border border-zinc-200">
           <div className="flex justify-between items-center mb-10">
              <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2">
                <Calendar className="w-4 h-4" /> Agenda Próximos Eventos ({pendingCount})
              </h3>
              <div className="text-[10px] font-black uppercase text-zinc-300">Resumen Logístico</div>
           </div>
           <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="border-b border-zinc-100 text-[10px] uppercase font-black tracking-widest text-zinc-400">
                <tr>
                  <th className="pb-4">Evento</th>
                  <th className="pb-4">Fecha</th>
                  <th className="pb-4">Presupuesto</th>
                  <th className="pb-4 text-right">Saldo Pendiente</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-50">
                {upcomingEvents.map(event => (
                  <tr key={event.id} className="hover:bg-zinc-50 transition-colors">
                    <td className="py-4 font-black uppercase text-xs">{event.title}</td>
                    <td className="py-4 text-xs text-zinc-500 font-bold">{event.date}</td>
                    <td className="py-4 text-xs font-black">{event.currency} {event.totalPrice.toLocaleString()}</td>
                    <td className="py-4 text-right text-xs font-black text-red-500">
                      {event.currency} {event.remainingAmount.toLocaleString()}
                    </td>
                  </tr>
                ))}
                {upcomingEvents.length === 0 && (
                  <tr>
                    <td colSpan={4} className="py-8 text-center text-[10px] font-black text-zinc-300 uppercase italic">No hay eventos en agenda</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Side column */}
      <div className="lg:col-span-1 space-y-8">
        <div className="bg-black p-8 text-white">
          <h3 className="text-sm font-black uppercase tracking-widest mb-6 flex items-center gap-2">
            <BrainCircuit className="w-5 h-5" /> Análisis RF
          </h3>
          <div className="text-[11px] leading-relaxed mb-8 opacity-70 font-medium italic min-h-[140px]">
            {aiInsights}
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing}
            className="w-full bg-white text-black py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-200 transition-colors disabled:opacity-50"
          >
            {isAnalyzing ? 'Calculando...' : 'Consultar Inteligencia'}
          </button>
        </div>

        <div className="bg-white p-8 border border-zinc-200">
          <h3 className="text-xs font-black uppercase tracking-widest mb-4">Roles en el Equipo</h3>
          <div className="space-y-3">
            {['Artista', 'Manager', 'DJ', 'Doble Voz'].map(role => (
              <div key={role} className="flex justify-between items-center py-2 border-b border-zinc-50 last:border-0">
                <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-tight">{role}</span>
                <span className="text-xs font-black">{staff.filter(s => s.role === role).length}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const MetricCard: React.FC<{ label: string, usd: number, dop: number, highlightRed?: boolean }> = ({ label, usd, dop, highlightRed }) => (
  <div className="bg-white p-6 border border-zinc-200 shadow-sm">
    <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-400 mb-4">{label}</div>
    <div className="space-y-2">
      <div className="flex justify-between items-end border-b border-zinc-50 pb-2">
        <span className="text-[10px] font-bold text-zinc-400 tracking-widest">USD</span>
        <span className={`text-xl font-black ${highlightRed && usd > 0 ? 'text-red-500' : 'text-black'}`}>
          $ {usd.toLocaleString()}
        </span>
      </div>
      <div className="flex justify-between items-end pt-1">
        <span className="text-[10px] font-bold text-zinc-400 tracking-widest">DOP</span>
        <span className={`text-xl font-black ${highlightRed && dop > 0 ? 'text-red-500' : 'text-black'}`}>
          RD$ {dop.toLocaleString()}
        </span>
