  </div>
);

const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingEventId, setEditingEventId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({
    title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP' as Currency, assignedStaff: [] as string[]
  });

  const [closingExpenses, setClosingExpenses] = useState({
    fuel: 0, toll: 0, diet: 0, others: 0, currency: 'DOP' as Currency
  });

  // Strict filtering: Completed events disappear from this view
  const activeEvents = useMemo(() => events.filter(e => !e.completed), [events]);

  const handleEditClick = (event: Event) => {
    setEditingEventId(event.id);
    setFormData({
      title: event.title,
      date: event.date,
      time: event.time,
      totalPrice: event.totalPrice,
      paidAmount: event.paidAmount,
      currency: event.currency,
      assignedStaff: event.assignedStaff
    });
    setShowForm(true);
  };

  const handleSelectAllStaff = () => {
    if (formData.assignedStaff.length === staff.length) {
      setFormData({ ...formData, assignedStaff: [] });
    } else {
      setFormData({ ...formData, assignedStaff: staff.map(s => s.id) });
    }
  };

  const handleSaveEvent = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingEventId) {
      setEvents(events.map(ev => ev.id === editingEventId ? {
        ...ev,
        ...formData,
        remainingAmount: formData.totalPrice - formData.paidAmount,
      } : ev));
    } else {
      const newEvent: Event = {
        id: Date.now().toString(),
        ...formData,
        remainingAmount: formData.totalPrice - formData.paidAmount,
        status: 'PENDING',
        completed: false
      };
      setEvents([...events, newEvent]);

      if (formData.paidAmount > 0) {
        setTransactions([{
          id: 't-' + Date.now(),
          type: 'INCOME',
          amount: formData.paidAmount,
          currency: formData.currency,
          description: `Abono Inicial: ${formData.title}`,
          date: formData.date || new Date().toISOString().split('T')[0],
          category: 'Evento',
          eventId: newEvent.id
        }, ...transactions]);
      }
    }

    closeForm();
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingEventId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP', assignedStaff: [] });
  };

  const handleCompleteEvent = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;

    const newTransactions: Transaction[] = [];

    // 1. Gastos Logísticos
    const expenses = [
      { key: 'fuel', label: 'Combustible', cat: 'Logística' },
      { key: 'toll', label: 'Peaje', cat: 'Logística' },
      { key: 'diet', label: 'Dieta', cat: 'Operación' },
      { key: 'others', label: 'Varios', cat: 'Varios' }
    ];

    expenses.forEach(ex => {
      const val = (closingExpenses as any)[ex.key];
      if (val > 0) {
        newTransactions.push({
          id: `exp-${closingEvent.id}-${ex.key}-${Date.now()}`,
          type: 'EXPENSE',
          amount: val,
          currency: closingExpenses.currency,
          description: `${ex.label}: ${closingEvent.title}`,
          date: new Date().toISOString().split('T')[0],
          category: ex.cat,
          eventId: closingEvent.id
        });
      }
    });

    // 2. Liquidación Personal
    closingEvent.assignedStaff.forEach(staffId => {
      const s = staff.find(st => st.id === staffId);
      if (s) {
        const payment = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTransactions.push({
          id: `pay-${closingEvent.id}-${s.id}-${Date.now()}`,
          type: 'EXPENSE',
          amount: payment,
          currency: s.currency,
          description: `Pago Personal (${s.name}): ${closingEvent.title}`,
          date: new Date().toISOString().split('T')[0],
          category: 'Personal',
          eventId: closingEvent.id
        });
      }
    });

    // 3. Cobro Final
    if (closingEvent.remainingAmount > 0) {
      newTransactions.push({
        id: `inc-rem-${closingEvent.id}-${Date.now()}`,
        type: 'INCOME',
        amount: closingEvent.remainingAmount,
        currency: closingEvent.currency,
        description: `Liquidación Final: ${closingEvent.title}`,
        date: new Date().toISOString().split('T')[0],
        category: 'Evento',
        eventId: closingEvent.id
      });
    }

    setTransactions([...newTransactions, ...transactions]);
    setEvents(events.map(ev => 
      ev.id === closingEvent.id 
        ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } 
        : ev
    ));

    setClosingEvent(null);
    setClosingExpenses({ fuel: 0, toll: 0, diet: 0, others: 0, currency: 'DOP' });
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-black text-white px-8 py-3 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition-all"
        >
          {showForm ? 'Cerrar' : '+ Nuevo Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSaveEvent} className="bg-white p-10 border border-black grid grid-cols-3 gap-6 animate-in fade-in duration-300 shadow-xl">
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Proyecto / Cliente</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none focus:border-black" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Fecha</label>
            <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Hora</label>
            <input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Moneda</label>
            <select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold outline-none">
              <option value="DOP">DOP</option>
              <option value="USD">USD</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Total Contrato</label>
            <input required type="number" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Reserva Pagada</label>
            <input required type="number" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold outline-none" />
          </div>
          <div className="col-span-3">
            <div className="flex justify-between items-center mb-4">
               <label className="text-[10px] font-black uppercase text-zinc-400">Equipo Designado</label>
               <button 
                 type="button" 
                 onClick={handleSelectAllStaff} 
                 className="text-[9px] font-black uppercase border border-zinc-200 px-3 py-1 hover:bg-black hover:text-white transition-all"
               >
                 {formData.assignedStaff.length === staff.length ? 'Deseleccionar Todo' : 'Seleccionar Todo'}
               </button>
            </div>
            <div className="grid grid-cols-4 gap-4">
              {staff.map(s => (
