                  <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">Presupuesto</div>
                  <div className="text-sm font-black">{event.currency} {event.totalPrice.toLocaleString()}</div>
               </div>
               <div>
                  <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">Abonado</div>
                  <div className="text-sm font-black">{event.currency} {event.paidAmount.toLocaleString()}</div>
               </div>
               <div>
                  <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">Resta</div>
                  <div className="text-sm font-black text-red-500">{event.currency} {event.remainingAmount.toLocaleString()}</div>
               </div>
            </div>

            <div className="flex justify-between items-center">
               <div className="flex -space-x-2">
                  {event.assignedStaff.map(sid => {
                    const s = staff.find(st => st.id === sid);
                    return s ? (
                      <div key={sid} className="w-8 h-8 bg-black text-white border-2 border-white flex items-center justify-center text-[10px] font-black uppercase" title={s.name}>
                        {s.name.charAt(0)}
