                  })}
               </div>
               <button onClick={() => setEvents(events.filter(e => e.id !== event.id))} className="text-zinc-200 hover:text-red-500 transition-colors">
                 <Trash2 className="w-4 h-4" />
               </button>
            </div>
          </div>
        ))}
        {activeEvents.length === 0 && (
          <div className="col-span-2 py-32 border-2 border-dashed border-zinc-100 flex flex-col items-center justify-center opacity-30">
             <Calendar className="w-16 h-16 mb-4" />
             <p className="font-black uppercase tracking-widest text-sm">No hay eventos activos</p>
          </div>
        )}
      </div>
    </div>
  );
};

