                      <div className="flex items-center gap-4">
                        <MapPin className="w-4 h-4" />
                        <input placeholder="Peaje" type="number" value={closingExpenses.toll} onChange={e => setClosingExpenses({...closingExpenses, toll: Number(e.target.value)})} className="flex-1 p-3 border-b border-zinc-200 outline-none font-bold text-sm" />
                      </div>
                      <div className="flex items-center gap-4">
                        <Utensils className="w-4 h-4" />
                        <input placeholder="Dieta" type="number" value={closingExpenses.diet} onChange={e => setClosingExpenses({...closingExpenses, diet: Number(e.target.value)})} className="flex-1 p-3 border-b border-zinc-200 outline-none font-bold text-sm" />
                      </div>
                   </div>
                </div>
                <div className="bg-zinc-50 p-6 border border-zinc-200">
                   <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400 mb-6">Staff a Liquidar</h4>
                   <div className="space-y-3">
                      {closingEvent.assignedStaff.map(sid => {
                        const s = staff.find(st => st.id === sid);
                        const payment = s ? (s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100))) : 0;
                        return (
                          <div key={sid} className="flex justify-between text-[10px] font-bold uppercase border-b border-zinc-100 pb-2">
                            <span className="text-zinc-500">{s?.name}</span>
                            <span>{s?.currency} {payment.toLocaleString()}</span>
                          </div>
                        );
                      })}
                   </div>
                </div>
              </div>
              <div className="flex items-center justify-between gap-6">
                <div className="flex-1">
                  <label className="text-[9px] font-black uppercase text-zinc-400 block mb-2">Moneda Gastos</label>
                  <select value={closingExpenses.currency} onChange={e => setClosingExpenses({...closingExpenses, currency: e.target.value as Currency})} className="w-full p-3 border border-zinc-200 text-xs font-bold outline-none">
                    <option value="DOP">DOP</option>
                    <option value="USD">USD</option>
                  </select>
                </div>
                <button type="submit" className="flex-[2] bg-black text-white py-5 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 shadow-xl">
                  Liquidar y Archivar Evento
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {activeEvents.map(event => (
          <div key={event.id} className="bg-white p-10 border border-zinc-200 relative transition-all duration-300 hover:border-black hover:shadow-2xl">
            <div className="flex justify-between items-start mb-8">
              <div>
                <h3 className="text-2xl font-black text-black tracking-tighter uppercase">{event.title}</h3>
                <div className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mt-2">
                  {event.date} | {event.time}
                </div>
              </div>
              <div className="flex flex-col items-end gap-3">
                 <span className="px-4 py-1 text-[8px] font-black border border-black bg-black text-white uppercase tracking-widest">Activo</span>
                 <div className="flex gap-4 items-center">
                    <button onClick={() => handleEditClick(event)} className="text-[9px] font-black uppercase text-zinc-400 hover:text-black transition-colors">
                      Editar
                    </button>
                    <button onClick={() => setClosingEvent(event)} className="flex items-center gap-2 text-[9px] font-black uppercase text-zinc-400 hover:text-black border-b border-zinc-100 hover:border-black pb-1 transition-all">
                        Finalizar <CheckCircle2 className="w-3 h-3" />
                    </button>
                 </div>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-6 mb-8 py-6 border-y border-zinc-50">
               <div>
                  <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">Presupuesto</div>
                  <div className="text-sm font-black">{event.currency} {event.totalPrice.toLocaleString()}</div>
               </div>
               <div>
                  <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">Abonado</div>
                  <div className="text-sm font-black">{event.currency} {event.paidAmount.toLocaleString()}</div>
               </div>
               <div>
                  <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">Resta</div>
                  <div className="text-sm font-black text-red-500">{event.currency} {event.remainingAmount.toLocaleString()}</div>
               </div>
            </div>

            <div className="flex justify-between items-center">
               <div className="flex -space-x-2">
                  {event.assignedStaff.map(sid => {
                    const s = staff.find(st => st.id === sid);
                    return s ? (
                      <div key={sid} className="w-8 h-8 bg-black text-white border-2 border-white flex items-center justify-center text-[10px] font-black uppercase" title={s.name}>
                        {s.name.charAt(0)}
                      </div>
                    ) : null;
                  })}
               </div>
               <button onClick={() => setEvents(events.filter(e => e.id !== event.id))} className="text-zinc-200 hover:text-red-500 transition-colors">
                 <Trash2 className="w-4 h-4" />
               </button>
            </div>
          </div>
        ))}
        {activeEvents.length === 0 && (
          <div className="col-span-2 py-32 border-2 border-dashed border-zinc-100 flex flex-col items-center justify-center opacity-30">
             <Calendar className="w-16 h-16 mb-4" />
             <p className="font-black uppercase tracking-widest text-sm">No hay eventos activos</p>
          </div>
        )}
      </div>
    </div>
  );
};

