const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showImport, setShowImport] = useState(false);
  const [importText, setImportText] = useState('');

  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);

  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({
    type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General'
  });

  const handleEdit = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      type: t.type,
      amount: t.amount,
      currency: t.currency,
      description: t.description,
      date: t.date,
      category: t.category
    });
    setShowForm(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      setTransactions(transactions.map(t => t.id === editingId ? { ...formData, id: editingId } : t));
    } else {
      setTransactions([{ ...formData, id: Date.now().toString() }, ...transactions]);
    }
    closeForm();
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;

    const dopReceived = usdToExchange * exchangeRate;
    const date = new Date().toISOString().split('T')[0];

    const usdExpense: Transaction = {
      id: 'ex-usd-' + Date.now(),
      type: 'EXPENSE',
      amount: usdToExchange,
      currency: 'USD',
      description: `Cambio de Divisas: USD a DOP (Tasa: ${exchangeRate})`,
      date: date,
      category: 'Financiero'
    };

    const dopIncome: Transaction = {
      id: 'ex-dop-' + Date.now(),
      type: 'INCOME',
      amount: dopReceived,
      currency: 'DOP',
      description: `Cambio de Divisas: USD a DOP (Tasa: ${exchangeRate})`,
      date: date,
      category: 'Financiero'
    };

    setTransactions([usdExpense, dopIncome, ...transactions]);
    setShowExchange(false);
    setExchangeRate(0);
    setUsdToExchange(0);
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General' });
  };

  const handleDelete = (id: string) => {
    if (window.confirm('¿Deseas eliminar permanentemente este registro contable?')) {
      setTransactions(transactions.filter(t => t.id !== id));
    }
  };

  const handleBulkImport = () => {
    try {
      const lines = importText.trim().split('\n');
      const newTransactions: Transaction[] = lines.map((line, index) => {
        const [date, type, amount, currency, description, category] = line.split(',');
        return {
          id: `bulk-${Date.now()}-${index}`,
          date: date.trim(),
          type: type.trim().toUpperCase() as 'INCOME' | 'EXPENSE',
          amount: Number(amount.trim()),
          currency: currency.trim().toUpperCase() as Currency,
          description: description.trim(),
          category: category.trim()
        };
      });
      setTransactions([...newTransactions, ...transactions]);
      setShowImport(false);
      setImportText('');
    } catch (e) {
      alert('Error en formato CSV. Ejemplo: 2024-12-01,INCOME,2500,USD,Evento X,Ingresos');
    }
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-sm overflow-hidden pb-20">
      <div className="p-10 border-b border-zinc-200 flex justify-between items-center bg-white">
        <h3 className="text-xl font-black uppercase tracking-tighter">Historial Contable</h3>
        <div className="flex gap-4">
          <button onClick={() => setShowExchange(!showExchange)} className="border-2 border-black px-6 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-50 flex items-center gap-2 transition-all">
            <RefreshCcw className="w-3 h-3" /> Cambio Divisas
          </button>
          <button onClick={() => setShowImport(!showImport)} className="border-2 border-black px-6 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-50 flex items-center gap-2 transition-all">
            <Upload className="w-3 h-3" /> Importar CSV
          </button>
          <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-8 py-4 text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">
            {showForm ? 'Cerrar' : '+ Registrar Movimiento'}
          </button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-10 bg-zinc-950 text-white animate-in slide-in-from-top-4 duration-300 grid grid-cols-3 gap-8 border-b border-black">
          <div className="col-span-3 mb-2">
             <h4 className="text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-2">
                <RefreshCcw className="w-4 h-4" /> Intercambio de Divisas (USD → DOP)
             </h4>
          </div>
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Monto USD a Vender</label>
            <input required type="number" step="0.01" value={usdToExchange} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border border-zinc-800 p-4 font-bold text-sm outline-none focus:border-white text-white" />
          </div>
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Tasa de Cambio (DOP x 1 USD)</label>
            <input required type="number" step="0.01" value={exchangeRate} onChange={e => setExchangeRate(Number(e.target.value))} className="w-full bg-zinc-900 border border-zinc-800 p-4 font-bold text-sm outline-none focus:border-white text-white" />
          </div>
          <div className="flex items-end">
            <button type="submit" className="w-full bg-white text-black py-4 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-200 transition-all">
              Procesar Cambio: RD$ {(usdToExchange * exchangeRate).toLocaleString()}
            </button>
          </div>
        </form>
      )}

      {showImport && (
        <div className="p-10 bg-zinc-950 text-white animate-in slide-in-from-top-4 duration-300">
          <h4 className="text-[11px] font-black uppercase tracking-[0.2em] mb-4">Importación Masiva</h4>
          <textarea 
            value={importText} 
            onChange={e => setImportText(e.target.value)}
            className="w-full h-32 bg-zinc-900 border border-zinc-800 p-4 text-xs font-mono mb-4 outline-none focus:border-white transition-all resize-none"
            placeholder="fecha,tipo,monto,moneda,descripcion,categoria"
          />
          <button onClick={handleBulkImport} className="bg-white text-black px-10 py-4 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-200">Importar Registros</button>
        </div>
      )}

      {showForm && (
        <form onSubmit={handleSave} className="p-10 bg-zinc-50 border-b border-zinc-200 grid grid-cols-4 gap-8 animate-in slide-in-from-top-4">
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Tipo</label>
            <select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full p-4 border border-zinc-200 font-bold text-sm outline-none focus:border-black">
              <option value="INCOME">Ingreso (+)</option>
              <option value="EXPENSE">Egreso (-)</option>
            </select>
          </div>
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Moneda</label>
            <select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold text-sm outline-none focus:border-black">
              <option value="DOP">DOP</option>
              <option value="USD">USD</option>
            </select>
          </div>
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Cuantía</label>
            <input required type="number" value={formData.amount} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold text-sm outline-none focus:border-black" />
          </div>
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Categoría</label>
            <input required type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold text-sm outline-none focus:border-black" />
          </div>
          <div className="col-span-2">
            <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Descripción</label>
            <input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold text-sm outline-none focus:border-black" />
          </div>
          <div>
            <label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Fecha</label>
            <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold text-sm outline-none focus:border-black" />
          </div>
          <div className="flex items-end">
            <button type="submit" className="w-full bg-black text-white py-5 text-[10px] font-black uppercase tracking-widest shadow-lg">
              {editingId ? 'Actualizar Registro' : 'Asentar Movimiento'}
