          </div>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b border-zinc-200 font-black text-[10px] uppercase tracking-widest text-zinc-400">
          <tr>
            <th className="px-10 py-6">Fecha</th>
            <th className="px-10 py-6">Operación</th>
            <th className="px-10 py-6">Categoría</th>
            <th className="px-10 py-6 text-right">Monto</th>
            <th className="px-10 py-6 text-right">Acciones</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-zinc-100">
          {transactions.sort((a,b) => b.date.localeCompare(a.date)).map(t => (
            <tr key={t.id} className="hover:bg-zinc-50 transition-all duration-200 group">
              <td className="px-10 py-8 text-[10px] font-black text-zinc-400 uppercase tracking-widest">{t.date}</td>
              <td className="px-10 py-8 font-black text-black uppercase tracking-tighter text-xs">{t.description}</td>
              <td className="px-10 py-8">
                <span className="text-[9px] font-black uppercase tracking-widest border border-zinc-200 px-3 py-1 bg-white">{t.category}</span>
              </td>
              <td className={`px-10 py-8 text-right font-black tracking-tighter text-sm ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-300'}`}>
                {t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}
              </td>
              <td className="px-10 py-8 text-right opacity-0 group-hover:opacity-100 transition-all">
                 <div className="flex justify-end gap-4">
                    <button onClick={() => handleEdit(t)} className="text-zinc-400 hover:text-black transition-colors">
                      <Pencil className="w-3.5 h-3.5" />
                    </button>
                    <button onClick={() => handleDelete(t.id)} className="text-zinc-200 hover:text-red-500 transition-colors">
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                 </div>
              </td>
            </tr>
          ))}
          {transactions.length === 0 && (
            <tr>
              <td colSpan={5} className="py-24 text-center text-[11px] font-black text-zinc-200 uppercase tracking-widest italic">No hay registros contables</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

