const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP' as Currency, assignedStaff: [] as string[] });

  const handleEdit = (event: Event) => {
    setEditingId(event.id);
    setFormData({ title: event.title, date: event.date, time: event.time, totalPrice: event.totalPrice, paidAmount: event.paidAmount, currency: event.currency, assignedStaff: event.assignedStaff });
    setShowForm(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount } : ev));
    } else {
      const newId = Date.now().toString();
      const newEvent: Event = { id: newId, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount, status: 'PENDING', completed: false };
      setEvents([...events, newEvent]);
      if (formData.paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: formData.paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Evento', eventId: newId }, ...transactions]);
      }
    }
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP', assignedStaff: [] });
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-8 py-3 text-xs font-black uppercase tracking-widest">{showForm ? 'Cancelar' : '+ Nuevo Evento'}</button>
      </div>

      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-10 border border-black grid grid-cols-3 gap-6 animate-in fade-in duration-300">
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Proyecto</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none focus:border-black" />
          </div>
          <div className="col-span-1"><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none" /></div>
          <div className="col-span-1"><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold outline-none"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div className="col-span-1"><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Precio Total</label><input required type="number" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold outline-none" /></div>

          <div className="col-span-3">
             <div className="flex justify-between items-center mb-4">
                <label className="text-[10px] font-black uppercase text-zinc-400">Personal Designado</label>
                <button type="button" onClick={() => setFormData({...formData, assignedStaff: formData.assignedStaff.length === staff.length ? [] : staff.map(s => s.id)})} className="text-[9px] font-black uppercase border px-3 py-1 hover:bg-black hover:text-white transition-all">Seleccionar Todo</button>
             </div>
             <div className="grid grid-cols-4 gap-4">
                {staff.map(s => (
                  <label key={s.id} className={`flex items-center gap-3 p-4 border cursor-pointer ${formData.assignedStaff.includes(s.id) ? 'border-black bg-zinc-50' : 'border-zinc-100'}`}>
                    <input type="checkbox" checked={formData.assignedStaff.includes(s.id)} onChange={() => setFormData({...formData, assignedStaff: formData.assignedStaff.includes(s.id) ? formData.assignedStaff.filter(id => id !== s.id) : [...formData.assignedStaff, s.id]})} className="accent-black" />
                    <span className="text-[10px] font-black uppercase">{s.name}</span>
                  </label>
                ))}
             </div>
          </div>
          <button type="submit" className="col-span-3 bg-black text-white py-5 text-xs font-black uppercase tracking-widest">{editingId ? 'Actualizar Evento' : 'Crear Evento'}</button>
        </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {events.filter(e => !e.completed).map(event => (
          <div key={event.id} className="bg-white p-10 border border-zinc-200 group hover:border-black transition-all">
            <div className="flex justify-between items-start mb-8">
              <div>
                <h3 className="text-xl font-black uppercase">{event.title}</h3>
                <div className="text-[9px] font-bold text-zinc-400 uppercase mt-1">{event.date} @ {event.time}</div>
              </div>
              <div className="flex gap-4">
                <button onClick={() => handleEdit(event)} className="text-zinc-400 hover:text-black transition-colors"><Pencil className="w-4 h-4" /></button>
                <button onClick={() => setEvents(events.filter(e => e.id !== event.id))} className="text-zinc-200 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
              </div>
            </div>
            <div className="grid grid-cols-3 gap-4 border-t border-zinc-50 pt-6">
              <div><div className="text-[8px] font-black text-zinc-300 uppercase">Total</div><div className="text-xs font-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
              <div><div className="text-[8px] font-black text-zinc-300 uppercase">Abono</div><div className="text-xs font-black">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
              <div><div className="text-[8px] font-black text-zinc-300 uppercase">Resta</div><div className="text-xs font-black text-red-500">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

