const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) setTransactions(transactions.map(t => t.id === editingId ? { ...formData, id: editingId } : t));
    else setTransactions([{ ...formData, id: Date.now().toString() }, ...transactions]);
    setShowForm(false); setEditingId(null);
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;
    const now = Date.now();
    const usdOut: Transaction = { id: 'ex-out-' + now, type: 'EXPENSE', amount: usdToExchange, currency: 'USD', description: `Venta USD @ ${exchangeRate}`, date: formData.date, category: 'Financiero' };
    const dopIn: Transaction = { id: 'ex-in-' + now, type: 'INCOME', amount: usdToExchange * exchangeRate, currency: 'DOP', description: `Compra DOP @ ${exchangeRate}`, date: formData.date, category: 'Financiero' };
    setTransactions([usdOut, dopIn, ...transactions]);
    setShowExchange(false); setUsdToExchange(0); setExchangeRate(0);
  };

  return (
    <div className="bg-white border border-zinc-200 pb-20">
      <div className="p-10 border-b flex justify-between items-center">
        <h3 className="text-xl font-black uppercase">Flujo de Caja</h3>
        <div className="flex gap-4">
          <button onClick={() => setShowExchange(!showExchange)} className="border-2 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2"><RefreshCcw className="w-3 h-3" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase">{showForm ? 'Cerrar' : '+ Nuevo Movimiento'}</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-10 bg-zinc-950 text-white grid grid-cols-3 gap-8 animate-in slide-in-from-top-4">
           <div><label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Vender (USD)</label><input required type="number" step="0.01" value={usdToExchange} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-800 p-4 font-bold outline-none" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Tasa Cambio</label><input required type="number" step="0.01" value={exchangeRate} onChange={e => setExchangeRate(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-800 p-4 font-bold outline-none" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-4 text-[10px] font-black uppercase">Ejecutar Cambio</button></div>
        </form>
      )}

      {showForm && (
        <form onSubmit={handleSave} className="p-10 bg-zinc-50 grid grid-cols-4 gap-6">
           <div className="col-span-1"><label className="block text-[9px] font-black text-zinc-400 uppercase mb-2">Tipo</label><select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full p-4 border font-bold"><option value="INCOME">Ingreso</option><option value="EXPENSE">Egreso</option></select></div>
           <div className="col-span-1"><label className="block text-[9px] font-black text-zinc-400 uppercase mb-2">Monto</label><input required type="number" value={formData.amount} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className="w-full p-4 border font-bold" /></div>
           <div className="col-span-2"><label className="block text-[9px] font-black text-zinc-400 uppercase mb-2">Descripción</label><input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 border font-bold" /></div>
           <button type="submit" className="col-span-4 bg-black text-white py-4 font-black uppercase text-xs tracking-widest">{editingId ? 'Actualizar Registro' : 'Asentar Movimiento'}</button>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b text-[10px] uppercase tracking-widest text-zinc-400">
          <tr><th className="px-10 py-4">Fecha</th><th className="px-10 py-4">Descripción</th><th className="px-10 py-4 text-right">Monto</th><th className="px-10 py-4 text-right">Acciones</th></tr>
        </thead>
        <tbody className="divide-y divide-zinc-100">
          {transactions.sort((a,b) => b.date.localeCompare(a.date)).map(t => (
            <tr key={t.id} className="hover:bg-zinc-50 group">
              <td className="px-10 py-6 text-[10px] font-bold text-zinc-400">{t.date}</td>
              <td className="px-10 py-6 font-black uppercase text-xs">{t.description}</td>
