const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) setTransactions(transactions.map(t => t.id === editingId ? { ...formData, id: editingId } : t));
    else setTransactions([{ ...formData, id: Date.now().toString() }, ...transactions]);
    setShowForm(false); setEditingId(null);
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdToExchange, currency: 'USD', description: `Cambio Divisas: Venta USD @ ${exchangeRate}`, date, category: 'Financiero' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdToExchange * exchangeRate, currency: 'DOP', description: `Cambio Divisas: Compra DOP @ ${exchangeRate}`, date, category: 'Financiero' };
    setTransactions([usdOut, dopIn, ...transactions]);
    setShowExchange(false); setUsdToExchange(0); setExchangeRate(0);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-sm overflow-hidden pb-20">
      <div className="p-10 border-b border-zinc-200 flex justify-between items-center bg-white">
        <h3 className="text-xl font-black uppercase">Libro Diario</h3>
        <div className="flex gap-4">
          <button onClick={() => setShowExchange(!showExchange)} className="border-2 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all"><RefreshCcw className="w-3 h-3" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest">{showForm ? 'Cerrar' : '+ Nuevo Movimiento'}</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-10 bg-black text-white grid grid-cols-3 gap-8 animate-in slide-in-from-top-4 duration-300">
           <div className="col-span-3 mb-2"><h4 className="text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-2 text-zinc-500">Transacción de Intercambio</h4></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Vender USD</label><input required type="number" step="0.01" value={usdToExchange} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-800 p-4 font-bold outline-none focus:border-white transition-all" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Tasa x 1 USD</label><input required type="number" step="0.01" value={exchangeRate} onChange={e => setExchangeRate(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-800 p-4 font-bold outline-none focus:border-white transition-all" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-4 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-200 transition-all">Procesar: RD$ {(usdToExchange * exchangeRate).toLocaleString()}</button></div>
        </form>
      )}

      {showForm && (
        <form onSubmit={handleSave} className="p-10 bg-zinc-50 border-b border-zinc-200 grid grid-cols-4 gap-8 animate-in slide-in-from-top-4">
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Tipo</label><select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full p-4 border font-bold"><option value="INCOME">Ingreso (+)</option><option value="EXPENSE">Egreso (-)</option></select></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border font-bold"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Monto</label><input required type="number" value={formData.amount} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className="w-full p-4 border font-bold" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Categoría</label><input required type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full p-4 border font-bold" /></div>
           <div className="col-span-2"><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Descripción</label><input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 border font-bold" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border font-bold" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-black text-white py-5 text-[10px] font-black uppercase tracking-widest shadow-lg">{editingId ? 'Actualizar Registro' : 'Asentar Movimiento'}</button></div>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b border-zinc-200 font-black text-[10px] uppercase tracking-widest text-zinc-400"><tr><th className="px-10 py-6">Fecha</th><th className="px-10 py-6">Descripción</th><th className="px-10 py-6">Categoría</th><th className="px-10 py-6 text-right">Monto</th><th className="px-10 py-6 text-right">Acciones</th></tr></thead>
        <tbody className="divide-y divide-zinc-100">
          {transactions.sort((a,b) => b.date.localeCompare(a.date)).map(t => (
            <tr key={t.id} className="hover:bg-zinc-50 group transition-all duration-200">
              <td className="px-10 py-8 text-[10px] font-black text-zinc-400 uppercase tracking-widest">{t.date}</td>
              <td className="px-10 py-8 font-black text-black uppercase tracking-tighter text-xs">{t.description}</td>
              <td className="px-10 py-8"><span className="text-[9px] font-black uppercase border border-zinc-200 px-3 py-1 bg-white">{t.category}</span></td>
              <td className={`px-10 py-8 text-right font-black tracking-tighter text-sm ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-300'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
              <td className="px-10 py-8 text-right opacity-0 group-hover:opacity-100 transition-all flex justify-end gap-4"><button onClick={() => { setEditingId(t.id); setFormData(t); setShowForm(true); }} className="text-zinc-400 hover:text-black"><Pencil className="w-4 h-4" /></button><button onClick={() => setTransactions(transactions.filter(tr => tr.id !== t.id))} className="text-zinc-200 hover:text-red-500"><Trash2 className="w-4 h-4" /></button></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar, 
  Users, 
  Wallet, 
  Plus, 
  Trash2, 
  CheckCircle2, 
  AlertCircle,
  TrendingUp,
  TrendingDown,
  BrainCircuit,
  DollarSign,
  FileDown,
  Upload,
  ChevronDown,
  X,
  Fuel,
  Utensils,
  MapPin,
  Pencil,
  BarChart3,
  PieChart,
  Filter,
  RefreshCcw,
  ClipboardList
} from 'lucide-react';
import { Staff, Event, Transaction, Role, Currency } from './types';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'events' | 'personal' | 'accounting'>('dashboard');

  // --- Filtros de Fecha Globales ---
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  // --- Estados con Persistencia LocalStorage ---
  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('rf_staff_v3');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'DJ Shadow', role: 'DJ', paymentType: 'FIXED', paymentValue: 200, currency: 'USD' },
      { id: '2', name: 'Ana Manager', role: 'Manager', paymentType: 'PERCENTAGE', paymentValue: 10, currency: 'DOP' },
    ];
  });

  const [events, setEvents] = useState<Event[]>(() => {
    const saved = localStorage.getItem('rf_events_v3');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('rf_transactions_v3');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => { localStorage.setItem('rf_staff_v3', JSON.stringify(staff)); }, [staff]);
  useEffect(() => { localStorage.setItem('rf_events_v3', JSON.stringify(events)); }, [events]);
  useEffect(() => { localStorage.setItem('rf_transactions_v3', JSON.stringify(transactions)); }, [transactions]);

  const [aiInsights, setAiInsights] = useState<string>('Haz clic para un análisis profundo de tu flujo multi-moneda...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Lógica de Totales con Filtro de Fecha ---
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const date = t.date;
      if (startDate && date < startDate) return false;
      if (endDate && date > endDate) return false;
      return true;
    });
  }, [transactions, startDate, endDate]);

  const totals = useMemo(() => {
    const calc = (curr: Currency) => {
      const income = filteredTransactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = filteredTransactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [filteredTransactions]);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(filteredTransactions, events);
    setAiInsights(insights || 'Error al analizar.');
    setIsAnalyzing(false);
  };

  const clearFilters = () => {
    setStartDate('');
    setEndDate('');
  };

  return (
    <div className="flex h-screen bg-[#fafafa] font-sans selection:bg-black selection:text-white">
      {/* Sidebar */}
      <nav className="w-64 bg-black text-white flex flex-col">
        <div className="p-8 text-2xl font-black tracking-tighter border-b border-zinc-800">
          RF<span className="text-zinc-500">STUDIO</span>
        </div>
        <div className="flex-1 mt-6 space-y-1 px-4">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal" active={activeTab === 'personal'} onClick={() => setActiveTab('personal')} />
          <NavItem icon={<Wallet />} label="Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
        </div>
        <div className="p-8 border-t border-zinc-800">
          <div className="text-[9px] font-black text-zinc-500 uppercase tracking-[0.2em]">Management System v3.1</div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-10">
        <header className="mb-8 flex justify-between items-end border-b border-zinc-200 pb-8">
          <div>
            <h1 className="text-4xl font-black text-black tracking-tight mb-2">
              {activeTab === 'dashboard' && 'Panel de Control'}
              {activeTab === 'events' && 'Agenda de Eventos'}
              {activeTab === 'personal' && 'Gestión de Staff'}
              {activeTab === 'accounting' && 'Contabilidad General'}
            </h1>
            <p className="text-zinc-400 font-medium tracking-tight">Control financiero y logístico centralizado.</p>
          </div>
          <div className="flex gap-4">
             <div className="bg-white px-6 py-4 rounded-none border border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] flex gap-8">
                <div>
                  <div className="text-[10px] uppercase font-bold text-zinc-400 mb-1">Caja DOP</div>
                  <div className={`text-lg font-black ${totals.DOP.balance >= 0 ? 'text-black' : 'text-red-500'}`}>
                    RD$ {totals.DOP.balance.toLocaleString()}
                  </div>
                </div>
                <div className="border-l border-zinc-100 pl-8">
                  <div className="text-[10px] uppercase font-bold text-zinc-400 mb-1">Caja USD</div>
                  <div className={`text-lg font-black ${totals.USD.balance >= 0 ? 'text-black' : 'text-red-500'}`}>
                    $ {totals.USD.balance.toLocaleString()}
                  </div>
                </div>
             </div>
          </div>
        </header>

        {/* Barra de Filtros (Solo Dashboard y Contabilidad) */}
        {(activeTab === 'dashboard' || activeTab === 'accounting') && (
          <div className="mb-10 flex items-center gap-6 bg-white p-4 border border-zinc-200 text-[10px] font-black uppercase tracking-widest">
            <div className="flex items-center gap-3">
              <Filter className="w-4 h-4 text-zinc-400" />
              <span>Filtro de Fechas:</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-zinc-400">Desde</span>
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black" />
            </div>
            <div className="flex items-center gap-2">
              <span className="text-zinc-400">Hasta</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black" />
            </div>
            {(startDate || endDate) && (
              <button onClick={clearFilters} className="text-red-500 hover:text-red-700 transition-colors ml-auto border border-red-100 px-4 py-2">
                Limpiar Filtros
              </button>
            )}
          </div>
        )}

        {activeTab === 'dashboard' && (
          <Dashboard 
            transactions={filteredTransactions}
            totals={totals} 
            events={events} 
            staff={staff}
            aiInsights={aiInsights} 
            handleAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing} 
            startDate={startDate}
            endDate={endDate}
          />
        )}
        {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'personal' && <StaffManager staff={staff} setStaff={setStaff} />}
        {activeTab === 'accounting' && <AccountingManager transactions={filteredTransactions} setTransactions={setTransactions} />}
      </main>
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 transition-all duration-200 ${active ? 'bg-white text-black' : 'text-zinc-500 hover:text-white hover:bg-zinc-900'}`}>
    {React.cloneElement(icon as React.ReactElement, { className: 'w-4 h-4' })}
