const Dashboard: React.FC<{ transactions: Transaction[], totals: any, events: Event[], staff: Staff[], aiInsights: string, handleAnalyze: () => void, isAnalyzing: boolean, startDate: string, endDate: string }> = ({ transactions, totals, events, staff, aiInsights, handleAnalyze, isAnalyzing, startDate, endDate }) => {
  const pendingEvents = events.filter(e => !e.completed);
  const receivableUSD = pendingEvents.filter(e => e.currency === 'USD').reduce((acc, c) => acc + c.remainingAmount, 0);
  const receivableDOP = pendingEvents.filter(e => e.currency === 'DOP').reduce((acc, c) => acc + c.remainingAmount, 0);

  // Estadísticas filtradas por categoría
  const statsByCategory = useMemo(() => {
    const categories: Record<string, { incomeUSD: number, incomeDOP: number, expenseUSD: number, expenseDOP: number }> = {};
    transactions.forEach(t => {
      if (!categories[t.category]) categories[t.category] = { incomeUSD: 0, incomeDOP: 0, expenseUSD: 0, expenseDOP: 0 };
      if (t.type === 'INCOME') {
        if (t.currency === 'USD') categories[t.category].incomeUSD += t.amount;
        else categories[t.category].incomeDOP += t.amount;
      } else {
        if (t.currency === 'USD') categories[t.category].expenseUSD += t.amount;
        else categories[t.category].expenseDOP += t.amount;
      }
    });
    return Object.entries(categories).map(([name, data]) => ({ name, ...data }));
  }, [transactions]);

  // Totales de eventos filtrados por fecha si hay filtro
  const displayEvents = useMemo(() => {
    return events.filter(e => {
      if (startDate && e.date < startDate) return false;
      if (endDate && e.date > endDate) return false;
      return true;
    });
  }, [events, startDate, endDate]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 pb-20">
      <div className="lg:col-span-4 grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard label="Ingresos" usd={totals.USD.income} dop={totals.DOP.income} />
        <MetricCard label="Egresos" usd={totals.USD.expense} dop={totals.DOP.expense} />
        <MetricCard label="Balance Neto" usd={totals.USD.balance} dop={totals.DOP.balance} />
        <div className="bg-white p-6 border border-zinc-200 shadow-sm flex flex-col justify-between">
          <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-400 mb-4">Métricas de Eventos</div>
          <div className="space-y-2">
            <div className="flex justify-between items-end border-b border-zinc-50 pb-2">
              <span className="text-[10px] font-bold text-zinc-400">TOTAL</span>
              <span className="text-xl font-black">{displayEvents.length}</span>
            </div>
            <div className="flex justify-between items-end pt-1">
              <span className="text-[10px] font-bold text-zinc-400">COBRABLE</span>
              <span className="text-xl font-black text-red-500">${receivableUSD.toLocaleString()} / RD${receivableDOP.toLocaleString()}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="lg:col-span-3 space-y-8">
        <div className="bg-white p-10 border border-zinc-200 shadow-sm">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-10"><BarChart3 className="w-4 h-4" /> Distribución Financiera</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <CategoryStats title="Ingresos" type="INCOME" data={statsByCategory} totals={totals} />
              <CategoryStats title="Gastos" type="EXPENSE" data={statsByCategory} totals={totals} />
           </div>
        </div>

        <div className="bg-white p-10 border border-zinc-200">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-8"><Calendar className="w-4 h-4" /> Próximas Fechas</h3>
           <table className="w-full text-left">
              <thead className="border-b border-zinc-100 text-[10px] uppercase font-black tracking-widest text-zinc-400">
                <tr><th className="pb-4">Evento</th><th className="pb-4">Fecha</th><th className="pb-4 text-right">Monto Pendiente</th></tr>
              </thead>
              <tbody className="divide-y divide-zinc-50">
                {pendingEvents.sort((a,b) => a.date.localeCompare(b.date)).slice(0, 5).map(event => (
                  <tr key={event.id} className="hover:bg-zinc-50 transition-colors">
                    <td className="py-4 font-black uppercase text-xs">{event.title}</td>
                    <td className="py-4 text-xs text-zinc-500 font-bold">{event.date}</td>
                    <td className="py-4 text-right text-xs font-black text-red-500">{event.currency} {event.remainingAmount.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
           </table>
        </div>
      </div>

      <div className="lg:col-span-1 space-y-8">
        <div className="bg-black p-8 text-white shadow-xl">
          <h3 className="text-sm font-black uppercase tracking-widest mb-6 flex items-center gap-2"><BrainCircuit className="w-5 h-5 text-zinc-400" /> Analítica AI</h3>
          <div className="text-[11px] leading-relaxed mb-8 opacity-70 italic min-h-[140px] border-l border-zinc-800 pl-4">{aiInsights}</div>
          <button onClick={handleAnalyze} disabled={isAnalyzing} className="w-full bg-white text-black py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-200">{isAnalyzing ? 'Calculando...' : 'Consultar Gemini'}</button>
        </div>
      </div>
    </div>
