);

const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({
    title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP' as Currency, assignedStaff: [] as string[]
  });

  const [closingExpenses, setClosingExpenses] = useState({
    fuel: 0, fuelDetail: '', 
    toll: 0, tollDetail: '', 
    diet: 0, dietDetail: '', 
    others: 0, othersDetail: '', 
    currency: 'DOP' as Currency
  });

  const activeEvents = useMemo(() => events.filter(e => !e.completed), [events]);

  const handleEdit = (event: Event) => {
    setEditingId(event.id);
    setFormData({
      title: event.title, date: event.date, time: event.time, totalPrice: event.totalPrice, paidAmount: event.paidAmount, currency: event.currency, assignedStaff: event.assignedStaff
    });
    setShowForm(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount } : ev));
    } else {
      const newId = Date.now().toString();
      const newEvent: Event = { id: newId, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount, status: 'PENDING', completed: false };
      setEvents([...events, newEvent]);
      if (formData.paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: formData.paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Evento', eventId: newId }, ...transactions]);
      }
    }
    closeForm();
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP', assignedStaff: [] });
  };

  const handleComplete = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;
    const date = new Date().toISOString().split('T')[0];
    const newTrans: Transaction[] = [];

    // Gastos Logística actualizados con detalles
    const exp = [
      { k: 'fuel', d: 'fuelDetail', l: 'Combustible' }, 
      { k: 'toll', d: 'tollDetail', l: 'Peaje' }, 
      { k: 'diet', d: 'dietDetail', l: 'Dieta' }, 
      { k: 'others', d: 'othersDetail', l: 'Otros Gastos' }
    ];

    exp.forEach(x => {
      const val = (closingExpenses as any)[x.k];
      const detail = (closingExpenses as any)[x.d];
      if (val > 0) {
        newTrans.push({ 
          id: `e-${Date.now()}-${x.k}`, 
          type: 'EXPENSE', 
          amount: val, 
          currency: closingExpenses.currency, 
          description: `${x.l} (${detail || 'Sin detalle'}): ${closingEvent.title}`, 
          date, 
          category: 'Logística', 
          eventId: closingEvent.id 
        });
      }
    });

    // Liquidación Staff
    closingEvent.assignedStaff.forEach(sid => {
      const s = staff.find(st => st.id === sid);
      if (s) {
        const pay = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTrans.push({ id: `p-${Date.now()}-${s.id}`, type: 'EXPENSE', amount: pay, currency: s.currency, description: `Nómina (${s.name}): ${closingEvent.title}`, date, category: 'Personal', eventId: closingEvent.id });
      }
    });

    // Cobro Final
    if (closingEvent.remainingAmount > 0) {
      newTrans.push({ id: `c-${Date.now()}`, type: 'INCOME', amount: closingEvent.remainingAmount, currency: closingEvent.currency, description: `Liquidación Final: ${closingEvent.title}`, date, category: 'Evento', eventId: closingEvent.id });
    }

    setTransactions([...newTrans, ...transactions]);
    setEvents(events.map(ev => ev.id === closingEvent.id ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } : ev));
    setClosingEvent(null);
    setClosingExpenses({ fuel: 0, fuelDetail: '', toll: 0, tollDetail: '', diet: 0, dietDetail: '', others: 0, othersDetail: '', currency: 'DOP' });
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-8 py-3 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition-all">
          {showForm ? 'Cancelar' : '+ Registrar Nuevo Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-10 border border-black grid grid-cols-3 gap-6 animate-in fade-in duration-300 shadow-xl">
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Cliente / Evento</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none focus:border-black" />
          </div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Hora</label><input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold outline-none"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Precio Total</label><input required type="number" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Abono Inicial</label><input required type="number" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold outline-none" /></div>
          <div className="flex items-end text-[11px] font-black uppercase text-zinc-400 p-4 font-mono">Saldo Pendiente: {formData.currency} {(formData.totalPrice - formData.paidAmount).toLocaleString()}</div>
          <div className="col-span-3">
             <div className="flex justify-between items-center mb-4">
                <label className="text-[10px] font-black uppercase text-zinc-400">Personal Designado</label>
                <button type="button" onClick={() => setFormData({...formData, assignedStaff: formData.assignedStaff.length === staff.length ? [] : staff.map(s => s.id)})} className="text-[9px] font-black uppercase border px-3 py-1 hover:bg-black hover:text-white transition-all">Seleccionar Todo</button>
             </div>
             <div className="grid grid-cols-4 gap-4">
                {staff.map(s => (
                  <label key={s.id} className={`flex items-center gap-3 p-4 border cursor-pointer transition-all ${formData.assignedStaff.includes(s.id) ? 'border-black bg-zinc-50' : 'border-zinc-100 hover:border-zinc-300'}`}>
                    <input type="checkbox" checked={formData.assignedStaff.includes(s.id)} onChange={() => setFormData({...formData, assignedStaff: formData.assignedStaff.includes(s.id) ? formData.assignedStaff.filter(id => id !== s.id) : [...formData.assignedStaff, s.id]})} className="accent-black" />
                    <span className="text-[10px] font-black uppercase">{s.name}</span>
                  </label>
                ))}
             </div>
          </div>
          <button type="submit" className="col-span-3 bg-black text-white py-5 text-xs font-black uppercase tracking-widest hover:shadow-2xl transition-all">{editingId ? 'Actualizar Evento' : 'Confirmar Reserva'}</button>
        </form>
      )}

      {/* Modal de Liquidación Detallada */}
      {closingEvent && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white border-2 border-black w-full max-w-2xl shadow-2xl overflow-hidden">
            <div className="p-8 border-b border-zinc-100 flex justify-between items-center bg-zinc-50">
              <div>
                <h2 className="text-xl font-black uppercase tracking-widest">Liquidación Final</h2>
                <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">{closingEvent.title}</p>
              </div>
              <button onClick={() => setClosingEvent(null)} className="text-zinc-400 hover:text-black"><X className="w-6 h-6" /></button>
            </div>
            <form onSubmit={handleComplete} className="p-10 space-y-6">
              <div className="grid grid-cols-2 gap-8">
                 <div className="space-y-4">
                    <h4 className="text-[10px] font-black uppercase text-zinc-300 tracking-[0.2em]">Gastos Adicionales</h4>
                    <div className="space-y-4">
                      {/* Combustible */}
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-4"><Fuel className="w-4 h-4 text-zinc-400" /><input placeholder="Monto Combustible" type="number" value={closingExpenses.fuel} onChange={e => setClosingExpenses({...closingExpenses, fuel: Number(e.target.value)})} className="flex-1 p-2 border-b border-zinc-100 outline-none font-bold text-sm" /></div>
                        <input placeholder="Detalle (ej: Viaje a Santiago)" value={closingExpenses.fuelDetail} onChange={e => setClosingExpenses({...closingExpenses, fuelDetail: e.target.value})} className="text-[10px] ml-8 border-none outline-none text-zinc-400 italic" />
                      </div>
                      {/* Peajes */}
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-4"><MapPin className="w-4 h-4 text-zinc-400" /><input placeholder="Monto Peajes" type="number" value={closingExpenses.toll} onChange={e => setClosingExpenses({...closingExpenses, toll: Number(e.target.value)})} className="flex-1 p-2 border-b border-zinc-100 outline-none font-bold text-sm" /></div>
                        <input placeholder="Detalle peajes" value={closingExpenses.tollDetail} onChange={e => setClosingExpenses({...closingExpenses, tollDetail: e.target.value})} className="text-[10px] ml-8 border-none outline-none text-zinc-400 italic" />
                      </div>
                      {/* Dietas */}
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-4"><Utensils className="w-4 h-4 text-zinc-400" /><input placeholder="Monto Dietas" type="number" value={closingExpenses.diet} onChange={e => setClosingExpenses({...closingExpenses, diet: Number(e.target.value)})} className="flex-1 p-2 border-b border-zinc-100 outline-none font-bold text-sm" /></div>
                        <input placeholder="Detalle comidas" value={closingExpenses.dietDetail} onChange={e => setClosingExpenses({...closingExpenses, dietDetail: e.target.value})} className="text-[10px] ml-8 border-none outline-none text-zinc-400 italic" />
                      </div>
                      {/* Otros (Campo recuperado) */}
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-4"><Plus className="w-4 h-4 text-zinc-400" /><input placeholder="Monto Otros" type="number" value={closingExpenses.others} onChange={e => setClosingExpenses({...closingExpenses, others: Number(e.target.value)})} className="flex-1 p-2 border-b border-zinc-100 outline-none font-bold text-sm" /></div>
                        <input placeholder="Detalle otros gastos" value={closingExpenses.othersDetail} onChange={e => setClosingExpenses({...closingExpenses, othersDetail: e.target.value})} className="text-[10px] ml-8 border-none outline-none text-zinc-400 italic" />
                      </div>
                    </div>
                 </div>
                 <div className="bg-zinc-50 p-6 border border-zinc-200">
                    <h4 className="text-[10px] font-black uppercase text-zinc-400 tracking-[0.2em] mb-4">Pagos a Staff</h4>
                    <div className="space-y-2 overflow-y-auto max-h-[180px]">
                       {closingEvent.assignedStaff.map(sid => {
                         const s = staff.find(st => st.id === sid);
                         const p = s ? (s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100))) : 0;
                         return (s && <div key={sid} className="flex justify-between text-[10px] font-bold uppercase border-b border-zinc-100 pb-2"><span>{s.name}</span><span className="font-black">{s.currency} {p.toLocaleString()}</span></div>);
                       })}
                    </div>
                    <div className="mt-6 pt-4 border-t border-zinc-200">
                       <div className="flex justify-between text-[10px] font-black uppercase">
                         <span>Cobro Final:</span>
                         <span className="text-black">{closingEvent.currency} {closingEvent.remainingAmount.toLocaleString()}</span>
                       </div>
                    </div>
                 </div>
              </div>
              <div className="flex items-center justify-between gap-6 pt-4">
                <div className="flex-1"><label className="text-[9px] font-black uppercase text-zinc-400 block mb-2">Moneda Egresos</label><select value={closingExpenses.currency} onChange={e => setClosingExpenses({...closingExpenses, currency: e.target.value as Currency})} className="w-full p-3 border border-zinc-200 text-xs font-bold outline-none"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
                <button type="submit" className="flex-[2] bg-black text-white py-5 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 shadow-xl">Confirmar y Cerrar Evento</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {activeEvents.map(event => (
          <div key={event.id} className="bg-white p-10 border border-zinc-200 relative group hover:border-black transition-all duration-300">
            <div className="flex justify-between items-start mb-8">
              <div>
                <h3 className="text-2xl font-black text-black tracking-tighter uppercase">{event.title}</h3>
                <div className="text-[10px] font-black text-zinc-400 uppercase mt-2">{event.date} | {event.time}</div>
              </div>
              <div className="flex flex-col items-end gap-3">
                 <span className="px-4 py-1 text-[8px] font-black border border-black bg-black text-white uppercase tracking-widest">Activo</span>
                 <div className="flex gap-4">
                    <button onClick={() => handleEdit(event)} className="text-zinc-400 hover:text-black" title="Editar"><Pencil className="w-4 h-4" /></button>
                    <button onClick={() => setClosingEvent(event)} className="text-zinc-400 hover:text-black flex items-center gap-2 text-[9px] font-black uppercase border-b border-zinc-100 hover:border-black transition-all">Liquidar <CheckCircle2 className="w-3 h-3" /></button>
                 </div>
              </div>
            </div>
            <div className="grid grid-cols-3 gap-6 mb-8 py-6 border-y border-zinc-50">
               <div><div className="text-[8px] font-black uppercase text-zinc-300 mb-1">Total</div><div className="text-sm font-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
               <div><div className="text-[8px] font-black uppercase text-zinc-300 mb-1">Pagado</div><div className="text-sm font-black">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
               <div><div className="text-[8px] font-black uppercase text-zinc-300 mb-1">Resta</div><div className="text-sm font-black text-red-500">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>
            <div className="flex justify-between items-center">
               <div className="flex -space-x-2">
                  {event.assignedStaff.map(sid => (
                    <div key={sid} className="w-8 h-8 bg-black text-white border-2 border-white flex items-center justify-center text-[10px] font-black uppercase ring-1 ring-zinc-100" title={staff.find(st => st.id === sid)?.name}>
                      {staff.find(st => st.id === sid)?.name.charAt(0)}
                    </div>
                  ))}
               </div>
               <button onClick={() => { if(confirm('¿Seguro que deseas eliminar este evento?')) setEvents(events.filter(e => e.id !== event.id))}} className="text-zinc-100 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
            </div>
          </div>
        ))}
        {activeEvents.length === 0 && <div className="col-span-2 py-32 border-2 border-dashed border-zinc-100 flex flex-col items-center justify-center opacity-30"><ClipboardList className="w-16 h-16 mb-4" /><p className="font-black uppercase tracking-widest text-sm">No hay eventos activos</p></div>}
      </div>
    </div>
  );
};

const StaffManager: React.FC<{ staff: Staff[], setStaff: any }> = ({ staff, setStaff }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Omit<Staff, 'id'>>({ name: '', role: 'Otro', paymentType: 'FIXED', paymentValue: 0, currency: 'DOP' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) setStaff(staff.map(s => s.id === editingId ? { ...formData, id: editingId } : s));
    else setStaff([...staff, { ...formData, id: Date.now().toString() }]);
    setShowForm(false); setEditingId(null); setFormData({ name: '', role: 'Otro', paymentType: 'FIXED', paymentValue: 0, currency: 'DOP' });
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-sm">
      <div className="p-10 border-b border-zinc-200 flex justify-between items-center bg-white">
        <h3 className="text-xl font-black uppercase">Staff Artístico y Técnico</h3>
        <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest">{showForm ? 'Cerrar' : '+ Registrar Personal'}</button>
      </div>
      {showForm && (
        <form onSubmit={handleSave} className="p-10 bg-zinc-50 border-b border-zinc-200 grid grid-cols-5 gap-8 animate-in slide-in-from-top-4 duration-300">
          <div className="col-span-2"><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Nombre Completo</label><input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none font-bold" /></div>
          <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Rol</label><select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})} className="w-full p-4 border border-zinc-200 outline-none font-bold"><option>Artista</option><option>Manager</option><option>Doble Voz</option><option>DJ</option><option>Otro</option></select></div>
          <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Moneda Predeterminada</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 outline-none font-bold"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Valor Base</label><input required type="number" value={formData.paymentValue} onChange={e => setFormData({...formData, paymentValue: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 outline-none font-bold" /></div>
          <div className="col-span-4 flex items-center gap-6"><label className="text-[9px] font-black uppercase text-zinc-400">Modelo de Pago:</label><div className="flex gap-4 flex-1"><button type="button" onClick={() => setFormData({...formData, paymentType: 'FIXED'})} className={`flex-1 py-4 text-[10px] font-black uppercase border transition-all ${formData.paymentType === 'FIXED' ? 'bg-black text-white border-black' : 'border-zinc-200'}`}>Monto Fijo</button><button type="button" onClick={() => setFormData({...formData, paymentType: 'PERCENTAGE'})} className={`flex-1 py-4 text-[10px] font-black uppercase border transition-all ${formData.paymentType === 'PERCENTAGE' ? 'bg-black text-white border-black' : 'border-zinc-200'}`}>Porcentual %</button></div></div>
          <button type="submit" className="w-full bg-black text-white py-5 text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-[0.98] transition-all">{editingId ? 'Actualizar Staff' : 'Registrar Staff'}</button>
        </form>
      )}
      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b border-zinc-200 font-black text-[10px] uppercase tracking-widest text-zinc-400"><tr className="divide-x divide-zinc-200"><th className="px-10 py-6">Nombre</th><th className="px-10 py-6">Rol</th><th className="px-10 py-6">Remuneración</th><th className="px-10 py-6 text-right">Acciones</th></tr></thead>
        <tbody className="divide-y divide-zinc-100 font-bold text-xs">
          {staff.map(s => (
            <tr key={s.id} className="hover:bg-zinc-50 transition-all duration-200 group">
              <td className="px-10 py-6 uppercase font-black tracking-tighter">{s.name}</td>
              <td className="px-10 py-6 uppercase text-[10px] text-zinc-500 font-bold tracking-widest">{s.role}</td>
              <td className="px-10 py-6">{s.paymentType === 'FIXED' ? `${s.currency} ${s.paymentValue.toLocaleString()} fijo` : `${s.paymentValue}% del total`}</td>
              <td className="px-10 py-6 text-right space-x-4 opacity-0 group-hover:opacity-100 transition-all"><button onClick={() => {setEditingId(s.id); setFormData(s); setShowForm(true);}} className="text-zinc-400 hover:text-black" title="Editar"><Pencil className="w-4 h-4" /></button><button onClick={() => setStaff(staff.filter(st => st.id !== s.id))} className="text-zinc-200 hover:text-red-500" title="Eliminar"><Trash2 className="w-4 h-4" /></button></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...formData, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...formData, id: Date.now().toString() }, ...prev]);
    setShowForm(false); setEditingId(null);
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdToExchange, currency: 'USD', description: `Venta Divisas USD @ ${exchangeRate}`, date, category: 'Financiero' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdToExchange * exchangeRate, currency: 'DOP', description: `Compra Divisas DOP @ ${exchangeRate}`, date, category: 'Financiero' };
    setTransactions((prev: Transaction[]) => [usdOut, dopIn, ...prev]);
    setShowExchange(false); setUsdToExchange(0); setExchangeRate(0);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-sm overflow-hidden pb-20">
      <div className="p-10 border-b border-zinc-200 flex justify-between items-center bg-white">
        <h3 className="text-xl font-black uppercase">Libro de Transacciones</h3>
        <div className="flex gap-4">
          <button onClick={() => setShowExchange(!showExchange)} className="border-2 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all"><RefreshCcw className="w-3 h-3" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest">{showForm ? 'Cerrar' : '+ Nuevo Movimiento'}</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-10 bg-black text-white grid grid-cols-3 gap-8 animate-in slide-in-from-top-4 duration-300">
           <div className="col-span-3 mb-2"><h4 className="text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-2 text-zinc-500">Transacción de Intercambio</h4></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Monto USD a Vender</label><input required type="number" step="0.01" value={usdToExchange} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-800 p-4 font-bold outline-none focus:border-white transition-all" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-500 mb-2">Tasa del día (x 1 USD)</label><input required type="number" step="0.01" value={exchangeRate} onChange={e => setExchangeRate(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-800 p-4 font-bold outline-none focus:border-white transition-all" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-4 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-200 transition-all">Generar Asiento: RD$ {(usdToExchange * exchangeRate).toLocaleString()}</button></div>
        </form>
      )}

      {showForm && (
        <form onSubmit={handleSave} className="p-10 bg-zinc-50 border-b border-zinc-200 grid grid-cols-4 gap-8 animate-in slide-in-from-top-4">
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Tipo de Operación</label><select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full p-4 border border-zinc-200 font-bold focus:border-black outline-none transition-all"><option value="INCOME">Ingreso (+)</option><option value="EXPENSE">Egreso (-)</option></select></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold focus:border-black outline-none transition-all"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Importe</label><input required type="number" value={formData.amount} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-bold focus:border-black outline-none transition-all" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Categoría</label><input required type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold focus:border-black outline-none transition-all" /></div>
           <div className="col-span-2"><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Concepto / Descripción</label><input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold focus:border-black outline-none transition-all" /></div>
           <div><label className="block text-[9px] font-black uppercase text-zinc-400 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold focus:border-black outline-none transition-all" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-black text-white py-5 text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">{editingId ? 'Actualizar Registro' : 'Asentar Movimiento'}</button></div>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b border-zinc-200 font-black text-[10px] uppercase tracking-widest text-zinc-400"><tr><th className="px-10 py-6">Fecha</th><th className="px-10 py-6">Descripción</th><th className="px-10 py-6">Categoría</th><th className="px-10 py-6 text-right">Monto</th><th className="px-10 py-6 text-right">Acciones</th></tr></thead>
        <tbody className="divide-y divide-zinc-100 font-medium">
          {transactions.map(t => (
            <tr key={t.id} className="hover:bg-zinc-50 group transition-all duration-200">
              <td className="px-10 py-8 text-[10px] font-black text-zinc-400 uppercase tracking-widest">{t.date}</td>
              <td className="px-10 py-8 font-black text-black uppercase tracking-tighter text-xs">{t.description}</td>
              <td className="px-10 py-8"><span className="text-[9px] font-black uppercase border border-zinc-200 px-3 py-1 bg-white tracking-widest">{t.category}</span></td>
              <td className={`px-10 py-8 text-right font-black tracking-tighter text-sm ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-300'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
              <td className="px-10 py-8 text-right opacity-0 group-hover:opacity-100 transition-all flex justify-end gap-4"><button onClick={() => { setEditingId(t.id); setFormData(t); setShowForm(true); }} className="text-zinc-400 hover:text-black"><Pencil className="w-4 h-4" /></button><button onClick={() => setTransactions((prev: Transaction[]) => prev.filter(tr => tr.id !== t.id))} className="text-zinc-200 hover:text-red-500"><Trash2 className="w-4 h-4" /></button></td>
            </tr>
          ))}
          {transactions.length === 0 && <tr><td colSpan={5} className="py-24 text-center text-zinc-300 uppercase font-black text-[11px] italic tracking-widest">No hay registros en este periodo</td></tr>}
        </tbody>
      </table>
    </div>
  );
};

