                <span className="text-red-500">{pendingCount}</span> / <span className="text-green-600">{completedCount}</span>
              </span>
            </div>
          </div>
        </div>
      </div>

      <div className="lg:col-span-3 space-y-8">
        <div className="bg-white p-10 border border-zinc-200 shadow-sm">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-10"><BarChart3 className="w-4 h-4" /> Análisis Financiero</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
