          <button onClick={handleAnalyze} disabled={isAnalyzing} className="w-full bg-white text-black py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-200 shadow-lg">{isAnalyzing ? 'Procesando...' : 'Obtener Análisis'}</button>
