    e.preventDefault();
    if (editingId) setStaff(staff.map(s => s.id === editingId ? { ...formData, id: editingId } : s));
    else setStaff([...staff, { ...formData, id: Date.now().toString() }]);
    setShowForm(false); setEditingId(null); setFormData({ name: '', role: 'Otro', paymentType: 'FIXED', paymentValue: 0, currency: 'DOP' });
