        <h3 className="text-2xl font-black uppercase tracking-widest">Nómina y Staff</h3>
        <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-10 py-4 text-[11px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">{showForm ? 'Cancelar' : '+ Registrar Personal'}</button>
      </div>
      {showForm && (
        <form onSubmit={handleSave} className="p-12 bg-zinc-50 border-b-2 border-zinc-100 grid grid-cols-5 gap-8 animate-in slide-in-from-top-10 duration-500">
          <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Nombre del Integrante</label><input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 border-2 border-zinc-100 outline-none font-bold focus:border-black transition-all" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Rol / Función</label><select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as Role})} className="w-full p-4 border-2 border-zinc-100 outline-none font-bold"><option>Artista</option><option>Manager</option><option>Doble Voz</option><option>DJ</option><option>Otro</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Moneda Pago</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-100 outline-none font-bold"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Valor</label><input required type="number" value={formData.paymentValue || ''} onChange={e => setFormData({...formData, paymentValue: Number(e.target.value)})} className="w-full p-4 border-2 border-zinc-100 outline-none font-bold" /></div>
          <div className="col-span-4 flex items-center gap-10 bg-white p-6 border-2 border-zinc-100"><label className="text-[10px] font-black uppercase text-zinc-400 tracking-[0.2em]">Tipo de Remuneración:</label><div className="flex gap-6 flex-1"><button type="button" onClick={() => setFormData({...formData, paymentType: 'FIXED'})} className={`flex-1 py-4 text-[11px] font-black uppercase border-2 transition-all ${formData.paymentType === 'FIXED' ? 'bg-black text-white border-black' : 'border-zinc-100 text-zinc-400'}`}>Sueldo Fijo</button><button type="button" onClick={() => setFormData({...formData, paymentType: 'PERCENTAGE'})} className={`flex-1 py-4 text-[11px] font-black uppercase border-2 transition-all ${formData.paymentType === 'PERCENTAGE' ? 'bg-black text-white border-black' : 'border-zinc-100 text-zinc-400'}`}>Porcentaje %</button></div></div>
          <button type="submit" className="w-full bg-black text-white py-6 text-[12px] font-black uppercase tracking-widest shadow-2xl hover:scale-[1.02] transition-all">{editingId ? 'Actualizar Perfil' : 'Dar de Alta'}</button>
        </form>
