};

const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...formData, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...formData, id: Date.now().toString() }, ...prev]);
    setShowForm(false); setEditingId(null);
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdToExchange, currency: 'USD', description: `Cambio Divisas: Venta USD @ ${exchangeRate}`, date, category: 'Financiero' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdToExchange * exchangeRate, currency: 'DOP', description: `Cambio Divisas: Entrada DOP @ ${exchangeRate}`, date, category: 'Financiero' };
    setTransactions((prev: Transaction[]) => [usdOut, dopIn, ...prev]);
    setShowExchange(false); setUsdToExchange(0); setExchangeRate(0);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-xl overflow-hidden pb-20">
      <div className="p-12 border-b-2 border-zinc-50 flex justify-between items-center bg-white">
        <h3 className="text-2xl font-black uppercase tracking-widest">Asientos Contables</h3>
        <div className="flex gap-6">
          <button onClick={() => setShowExchange(!showExchange)} className="border-4 border-black px-8 py-3 text-[11px] font-black uppercase flex items-center gap-3 hover:bg-zinc-50 transition-all"><RefreshCcw className="w-4 h-4" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-10 py-4 text-[11px] font-black uppercase tracking-widest shadow-xl">{showForm ? 'Cancelar' : '+ Nueva Transacción'}</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-12 bg-black text-white grid grid-cols-3 gap-10 animate-in slide-in-from-top-10 duration-500">
           <div className="col-span-3"><h4 className="text-[12px] font-black uppercase tracking-[0.3em] flex items-center gap-3 text-white">Ejecutar Venta de Divisas</h4></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Saldo USD a Liquidar</label><input required type="number" step="0.01" value={usdToExchange || ''} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-700 p-5 font-black text-white outline-none focus:border-white transition-all text-xl" /></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Tasa Pactada (RD$)</label><input required type="number" step="0.01" value={exchangeRate || ''} onChange={e => setExchangeRate(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-700 p-5 font-black text-white outline-none focus:border-white transition-all text-xl" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-6 text-[12px] font-black uppercase tracking-widest hover:bg-zinc-200 shadow-2xl transition-all">Confirmar: RD$ {(usdToExchange * exchangeRate).toLocaleString()}</button></div>
        </form>
      )}

      {showForm && (
        <form onSubmit={handleSave} className="p-12 bg-zinc-50 border-b-2 border-zinc-100 grid grid-cols-4 gap-8 animate-in slide-in-from-top-10 duration-500">
           <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Tipo</label><select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white"><option value="INCOME">Ingreso (+)</option><option value="EXPENSE">Egreso (-)</option></select></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Importe</label><input required type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className="w-full p-4 border-2 border-zinc-200 font-black focus:border-black outline-none bg-white" /></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Categoría</label><input required type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white" /></div>
           <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Concepto</label><input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white" /></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-3 tracking-widest">Fecha Operación</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-black text-white py-6 text-[12px] font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all">{editingId ? 'Actualizar Asiento' : 'Registrar Movimiento'}</button></div>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b-2 border-zinc-100 font-black text-[11px] uppercase tracking-[0.2em] text-zinc-400"><tr><th className="px-12 py-8">Fecha</th><th className="px-12 py-8">Descripción de Operación</th><th className="px-12 py-8">Categoría</th><th className="px-12 py-8 text-right">Balance</th><th className="px-12 py-8 text-right">Gestión</th></tr></thead>
        <tbody className="divide-y divide-zinc-50">
          {transactions.map(t => (
            <tr key={t.id} className="hover:bg-zinc-50 group transition-all duration-300">
              <td className="px-12 py-10 text-[10px] font-black text-zinc-400 uppercase tracking-widest">{t.date}</td>
              <td className="px-12 py-10 font-black text-black uppercase tracking-tight text-xs max-w-xs">{t.description}</td>
              <td className="px-12 py-10"><span className="text-[10px] font-black uppercase border-2 border-zinc-100 px-4 py-2 bg-white tracking-widest">{t.category}</span></td>
              <td className={`px-12 py-10 text-right font-black tracking-tighter text-base ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-300'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
              <td className="px-12 py-10 text-right opacity-0 group-hover:opacity-100 transition-all flex justify-end gap-6"><button onClick={() => { setEditingId(t.id); setFormData(t); setShowForm(true); }} className="text-zinc-400 hover:text-black border-b border-transparent hover:border-black pb-1 uppercase text-[10px] font-black">Editar</button><button onClick={() => setTransactions((prev: Transaction[]) => prev.filter(tr => tr.id !== t.id))} className="text-zinc-300 hover:text-red-500 border-b border-transparent hover:border-red-500 pb-1 uppercase text-[10px] font-black">Eliminar</button></td>
            </tr>
          ))}
          {transactions.length === 0 && <tr><td colSpan={5} className="py-40 text-center text-zinc-300 uppercase font-black text-[14px] italic tracking-widest opacity-30">Libro Diario sin registros</td></tr>}
        </tbody>
      </table>
    </div>
  );
};

