const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({
    title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP' as Currency, assignedStaff: [] as string[]
  });

  const [closingExpenses, setClosingExpenses] = useState({
    fuel: 0, fuelDetail: '', 
    toll: 0, tollDetail: '', 
    diet: 0, dietDetail: '', 
    others: 0, othersDetail: '', 
    currency: 'DOP' as Currency
  });

  const activeEvents = useMemo(() => events.filter(e => !e.completed), [events]);

  const handleEdit = (event: Event) => {
    setEditingId(event.id);
    setFormData({
      title: event.title, date: event.date, time: event.time, totalPrice: event.totalPrice, paidAmount: event.paidAmount, currency: event.currency, assignedStaff: event.assignedStaff
    });
    setShowForm(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount } : ev));
    } else {
      const newId = Date.now().toString();
      const newEvent: Event = { id: newId, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount, status: 'PENDING', completed: false };
      setEvents([...events, newEvent]);
      if (formData.paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: formData.paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Evento', eventId: newId }, ...transactions]);
      }
    }
    closeForm();
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP', assignedStaff: [] });
  };

  const handleComplete = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;

    // Validación de detalle para otros gastos
    if (closingExpenses.others > 0 && !closingExpenses.othersDetail.trim()) {
      alert("Por favor, describe en qué se gastó el monto de 'Otros Gastos'.");
      return;
    }

    const date = new Date().toISOString().split('T')[0];
    const newTrans: Transaction[] = [];

    const exp = [
      { k: 'fuel', d: 'fuelDetail', l: 'Combustible' }, 
      { k: 'toll', d: 'tollDetail', l: 'Peaje' }, 
      { k: 'diet', d: 'dietDetail', l: 'Dieta' }, 
      { k: 'others', d: 'othersDetail', l: 'Otros' }
    ];

    exp.forEach(x => {
      const val = (closingExpenses as any)[x.k];
      const detail = (closingExpenses as any)[x.d];
      if (val > 0) {
        newTrans.push({ 
          id: `e-${Date.now()}-${x.k}`, 
          type: 'EXPENSE', 
          amount: val, 
          currency: closingExpenses.currency, 
          description: `${x.l} (${detail || 'Logística'}): ${closingEvent.title}`, 
          date, 
          category: 'Logística', 
          eventId: closingEvent.id 
        });
      }
    });

    closingEvent.assignedStaff.forEach(sid => {
      const s = staff.find(st => st.id === sid);
      if (s) {
        const pay = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTrans.push({ id: `p-${Date.now()}-${s.id}`, type: 'EXPENSE', amount: pay, currency: s.currency, description: `Nómina (${s.name}): ${closingEvent.title}`, date, category: 'Personal', eventId: closingEvent.id });
      }
    });

    if (closingEvent.remainingAmount > 0) {
      newTrans.push({ id: `c-${Date.now()}`, type: 'INCOME', amount: closingEvent.remainingAmount, currency: closingEvent.currency, description: `Liquidación Final: ${closingEvent.title}`, date, category: 'Evento', eventId: closingEvent.id });
    }

    setTransactions([...newTrans, ...transactions]);
    setEvents(events.map(ev => ev.id === closingEvent.id ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } : ev));
    setClosingEvent(null);
    setClosingExpenses({ fuel: 0, fuelDetail: '', toll: 0, tollDetail: '', diet: 0, dietDetail: '', others: 0, othersDetail: '', currency: 'DOP' });
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-10 py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition-all shadow-xl">
          {showForm ? 'Cerrar Formulario' : '+ Registrar Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-12 border border-black grid grid-cols-3 gap-8 animate-in fade-in zoom-in-95 duration-300 shadow-2xl relative">
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Cliente / Nombre del Evento</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none focus:border-black text-lg" />
          </div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none font-bold" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Hora</label><input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none font-bold" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold outline-none"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Precio Total</label><input required type="number" value={formData.totalPrice || ''} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-black outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Abono Realizado</label><input required type="number" value={formData.paidAmount || ''} onChange={e => setFormData({...formData, paidAmount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-black outline-none" /></div>
          <div className="flex items-center text-xs font-black uppercase text-red-500 bg-red-50 p-4 border-l-4 border-red-500">Saldo Restante: {formData.currency} {(formData.totalPrice - formData.paidAmount).toLocaleString()}</div>
          <div className="col-span-3">
             <div className="flex justify-between items-center mb-6">
                <label className="text-[10px] font-black uppercase text-zinc-400 tracking-widest">Personal Designado para el Evento</label>
                <button type="button" onClick={() => setFormData({...formData, assignedStaff: formData.assignedStaff.length === staff.length ? [] : staff.map(s => s.id)})} className="text-[9px] font-black uppercase border-2 border-zinc-100 px-4 py-2 hover:bg-black hover:text-white transition-all">Alternar Todos</button>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {staff.map(s => (
                  <label key={s.id} className={`flex items-center gap-4 p-5 border-2 cursor-pointer transition-all ${formData.assignedStaff.includes(s.id) ? 'border-black bg-zinc-50' : 'border-zinc-100 hover:border-zinc-300'}`}>
                    <input type="checkbox" checked={formData.assignedStaff.includes(s.id)} onChange={() => setFormData({...formData, assignedStaff: formData.assignedStaff.includes(s.id) ? formData.assignedStaff.filter(id => id !== s.id) : [...formData.assignedStaff, s.id]})} className="accent-black w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-tighter">{s.name}</span>
                  </label>
                ))}
             </div>
          </div>
          <button type="submit" className="col-span-3 bg-black text-white py-6 text-sm font-black uppercase tracking-widest hover:bg-zinc-900 transition-all shadow-xl">{editingId ? 'Actualizar Evento' : 'Confirmar Reserva de Fecha'}</button>
        </form>
      )}

      {/* Modal de Liquidación Final */}
      {closingEvent && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white border-4 border-black w-full max-w-2xl shadow-2xl overflow-hidden">
            <div className="p-8 border-b border-zinc-200 flex justify-between items-center bg-black text-white">
              <div>
                <h2 className="text-2xl font-black uppercase tracking-widest text-white">Liquidar Proyecto</h2>
                <p className="text-[11px] font-bold text-zinc-400 uppercase tracking-widest">{closingEvent.title}</p>
              </div>
              <button onClick={() => setClosingEvent(null)} className="text-zinc-400 hover:text-white"><X className="w-8 h-8" /></button>
            </div>
            <form onSubmit={handleComplete} className="p-10 space-y-8">
              <div className="grid grid-cols-2 gap-10">
                 <div className="space-y-6">
                    <h4 className="text-[11px] font-black uppercase text-zinc-400 tracking-widest border-b pb-2">Gastos Logística</h4>
                    <div className="space-y-6">
                      <div className="flex flex-col gap-2">
                        <div className="flex items-center gap-4 text-zinc-500"><Fuel className="w-5 h-5" /><input placeholder="Combustible" type="number" value={closingExpenses.fuel || ''} onChange={e => setClosingExpenses({...closingExpenses, fuel: Number(e.target.value)})} className="flex-1 p-2 border-b border-zinc-100 outline-none font-bold text-black" /></div>
                        <input placeholder="Detalle trayecto..." value={closingExpenses.fuelDetail} onChange={e => setClosingExpenses({...closingExpenses, fuelDetail: e.target.value})} className="text-[10px] ml-9 border-none outline-none text-zinc-400 italic bg-zinc-50 p-1" />
                      </div>
                      <div className="flex flex-col gap-2">
                        <div className="flex items-center gap-4 text-zinc-500"><MapPin className="w-5 h-5" /><input placeholder="Peajes" type="number" value={closingExpenses.toll || ''} onChange={e => setClosingExpenses({...closingExpenses, toll: Number(e.target.value)})} className="flex-1 p-2 border-b border-zinc-100 outline-none font-bold text-black" /></div>
                        <input placeholder="Ruta peajes..." value={closingExpenses.tollDetail} onChange={e => setClosingExpenses({...closingExpenses, tollDetail: e.target.value})} className="text-[10px] ml-9 border-none outline-none text-zinc-400 italic bg-zinc-50 p-1" />
                      </div>
                      <div className="flex flex-col gap-2">
                        <div className="flex items-center gap-4 text-zinc-500"><Plus className="w-5 h-5 text-red-500" /><input placeholder="Otros Gastos" type="number" value={closingExpenses.others || ''} onChange={e => setClosingExpenses({...closingExpenses, others: Number(e.target.value)})} className="flex-1 p-2 border-b-2 border-red-100 outline-none font-black text-black" /></div>
                        <input required={closingExpenses.others > 0} placeholder="¿EN QUÉ SE GASTÓ ESTO? (Obligatorio)" value={closingExpenses.othersDetail} onChange={e => setClosingExpenses({...closingExpenses, othersDetail: e.target.value})} className={`text-[10px] ml-9 p-2 outline-none font-bold uppercase tracking-tighter ${closingExpenses.others > 0 ? 'bg-red-50 border-b border-red-500 text-red-700' : 'bg-zinc-50 text-zinc-400'}`} />
                      </div>
                    </div>
                 </div>
                 <div className="bg-zinc-50 p-8 border border-zinc-200 shadow-inner">
                    <h4 className="text-[11px] font-black uppercase text-zinc-500 tracking-widest mb-6">Nómina del Evento</h4>
                    <div className="space-y-3 overflow-y-auto max-h-[220px]">
                       {closingEvent.assignedStaff.map(sid => {
                         const s = staff.find(st => st.id === sid);
                         const p = s ? (s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100))) : 0;
                         return (s && <div key={sid} className="flex justify-between text-[11px] font-black uppercase border-b border-zinc-100 pb-3"><span>{s.name}</span><span className="text-black">{s.currency} {p.toLocaleString()}</span></div>);
                       })}
                    </div>
                    <div className="mt-8 pt-6 border-t-2 border-zinc-200">
                       <div className="flex justify-between text-xs font-black uppercase text-zinc-400 mb-2">Restante x Cobrar:</div>
                       <div className="text-xl font-black text-black">{closingEvent.currency} {closingEvent.remainingAmount.toLocaleString()}</div>
                    </div>
                 </div>
              </div>
              <div className="flex items-center justify-between gap-10 pt-6">
                <div className="flex-1"><label className="text-[10px] font-black uppercase text-zinc-400 block mb-3">Divisa de Gastos</label><select value={closingExpenses.currency} onChange={e => setClosingExpenses({...closingExpenses, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-100 text-sm font-black outline-none bg-white"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
                <button type="submit" className="flex-[2] bg-black text-white py-6 text-sm font-black uppercase tracking-[0.2em] hover:bg-zinc-900 shadow-2xl transition-all">Finalizar y Asentar Cuentas</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        {activeEvents.map(event => (
          <div key={event.id} className="bg-white p-12 border border-zinc-200 relative group hover:border-black transition-all duration-500 shadow-sm hover:shadow-xl">
            <div className="flex justify-between items-start mb-10">
              <div>
                <h3 className="text-3xl font-black text-black tracking-tighter uppercase leading-none mb-3">{event.title}</h3>
                <div className="flex items-center gap-4 text-[10px] font-black text-zinc-400 uppercase tracking-widest">
                  <span className="bg-zinc-100 px-3 py-1 rounded-full text-black">{event.date}</span>
                  <span className="bg-zinc-100 px-3 py-1 rounded-full text-black">{event.time}</span>
                </div>
              </div>
              <div className="flex flex-col items-end gap-4">
                 <div className="flex gap-4">
                    <button onClick={() => handleEdit(event)} className="p-3 bg-zinc-50 hover:bg-black hover:text-white transition-all rounded-full border border-zinc-100" title="Editar"><Pencil className="w-4 h-4" /></button>
                    <button onClick={() => setClosingEvent(event)} className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-800 transition-all flex items-center gap-2">Cerrar Proyecto <CheckCircle2 className="w-4 h-4" /></button>
                 </div>
              </div>
            </div>
            <div className="grid grid-cols-3 gap-8 mb-10 py-8 border-y-2 border-zinc-50">
               <div><div className="text-[10px] font-black uppercase text-zinc-300 mb-2 tracking-widest">Contrato</div><div className="text-lg font-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-300 mb-2 tracking-widest">Abonado</div><div className="text-lg font-black text-green-600">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-300 mb-2 tracking-widest">Pendiente</div><div className="text-lg font-black text-red-500">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>
            <div className="flex justify-between items-center">
               <div className="flex -space-x-3">
                  {event.assignedStaff.map(sid => (
                    <div key={sid} className="w-10 h-10 bg-black text-white border-4 border-white flex items-center justify-center text-[12px] font-black uppercase rounded-full shadow-md transition-transform hover:scale-110 cursor-help" title={staff.find(st => st.id === sid)?.name}>
                      {staff.find(st => st.id === sid)?.name.charAt(0)}
                    </div>
                  ))}
               </div>
               <button onClick={() => { if(confirm('¿Eliminar evento permanentemente?')) setEvents(events.filter(e => e.id !== event.id))}} className="text-zinc-200 hover:text-red-500 transition-colors p-2"><Trash2 className="w-5 h-5" /></button>
            </div>
          </div>
        ))}
        {activeEvents.length === 0 && <div className="col-span-2 py-40 border-4 border-dashed border-zinc-100 flex flex-col items-center justify-center opacity-40"><Layers className="w-20 h-20 mb-6 text-zinc-300" /><p className="font-black uppercase tracking-[0.3em] text-lg">Agenda Vacía</p></div>}
      </div>
    </div>
  );
};

const StaffManager: React.FC<{ staff: Staff[], setStaff: any }> = ({ staff, setStaff }) => {
