      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b border-zinc-200 font-black text-[11px] uppercase tracking-[0.2em] text-zinc-400"><tr className="divide-x divide-zinc-200"><th className="px-12 py-8">Integrante</th><th className="px-12 py-8">Rol</th><th className="px-12 py-8">Esquema de Pago</th><th className="px-12 py-8 text-right">Gestión</th></tr></thead>
        <tbody className="divide-y divide-zinc-100 font-bold text-sm">
          {staff.map(s => (
            <tr key={s.id} className="hover:bg-zinc-50 transition-all duration-300 group">
              <td className="px-12 py-8 uppercase font-black tracking-tighter text-black text-base">{s.name}</td>
              <td className="px-12 py-8 uppercase text-[11px] text-zinc-500 font-black tracking-widest">{s.role}</td>
              <td className="px-12 py-8 text-black">{s.paymentType === 'FIXED' ? `${s.currency} ${s.paymentValue.toLocaleString()} por evento` : `${s.paymentValue}% de la facturación`}</td>
