const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any }> = ({ transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: 'General' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...formData, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...formData, id: Date.now().toString() }, ...prev]);
    setShowForm(false); setEditingId(null);
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdToExchange, currency: 'USD', description: `Cambio Divisas: Venta USD @ ${exchangeRate}`, date, category: 'Financiero' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdToExchange * exchangeRate, currency: 'DOP', description: `Cambio Divisas: Entrada DOP @ ${exchangeRate}`, date, category: 'Financiero' };
    setTransactions((prev: Transaction[]) => [usdOut, dopIn, ...prev]);
    setShowExchange(false); setUsdToExchange(0); setExchangeRate(0);
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const rows = text.split('\n');
      const newTransactions: Transaction[] = [];

      // Skip header row if exists. Based on user image:
      // Fecha, CATEGORIA, DESCRIPCION, MONTO, TIPO, METODO DE PAGO, Moneda
      // Format example: 19/11/23, Fiesta, 50% Fiesta 15 DIC, $ 10,000.00, Ingreso, Efectivo, DOP

      rows.forEach((row, index) => {
        if (index === 0 && row.toLowerCase().includes('fecha')) return; // Header detection
        if (!row.trim()) return;

        // Note: CSV splitting can be tricky with quoted values, but for simple spreadsheets:
        const columns = row.split(',').map(c => c.trim().replace(/^"|"$/g, ''));

        if (columns.length >= 5) {
          const dateStr = columns[0]; // 19/11/23
          const category = columns[1];
          const description = columns[2];
          const amountStr = columns[3]; // $ 10,000.00
          const typeStr = columns[4]; // Ingreso / Gasto
          const method = columns[5] || ''; // Efectivo
          const currencyStr = columns[6] || 'DOP';

          // Date conversion: DD/MM/YY -> YYYY-MM-DD
          let finalDate = dateStr;
          const dateParts = dateStr.split('/');
          if (dateParts.length === 3) {
            const day = dateParts[0].padStart(2, '0');
            const month = dateParts[1].padStart(2, '0');
            const year = dateParts[2].length === 2 ? `20${dateParts[2]}` : dateParts[2];
            finalDate = `${year}-${month}-${day}`;
          }

          // Amount cleaning
          const finalAmount = parseFloat(amountStr.replace(/[^\d.-]/g, ''));

          // Type mapping
          const type: 'INCOME' | 'EXPENSE' = typeStr.toLowerCase().includes('ingreso') ? 'INCOME' : 'EXPENSE';

          if (!isNaN(finalAmount)) {
            newTransactions.push({
              id: `import-${Date.now()}-${index}`,
              date: finalDate,
              category,
              description: `${description}${method ? ` (${method})` : ''}`,
              amount: finalAmount,
              type,
              currency: (currencyStr.toUpperCase() === 'USD' ? 'USD' : 'DOP') as Currency
            });
          }
        }
      });

      if (newTransactions.length > 0) {
        setTransactions((prev: Transaction[]) => [...newTransactions, ...prev]);
        alert(`Se importaron ${newTransactions.length} movimientos exitosamente.`);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-xl overflow-hidden pb-20">
      <div className="p-12 border-b-2 border-zinc-50 flex justify-between items-center bg-white">
        <h3 className="text-2xl font-black uppercase tracking-widest">Asientos Contables</h3>
        <div className="flex gap-6">
          <input type="file" ref={fileInputRef} onChange={handleImportCSV} accept=".csv" className="hidden" />
          <button onClick={() => fileInputRef.current?.click()} className="border-4 border-black px-6 py-3 text-[11px] font-black uppercase flex items-center gap-3 hover:bg-zinc-50 transition-all text-black">
            <Upload className="w-4 h-4 text-black" /> Importar CSV
          </button>
          <button onClick={() => setShowExchange(!showExchange)} className="border-4 border-black px-8 py-3 text-[11px] font-black uppercase flex items-center gap-3 hover:bg-zinc-50 transition-all text-black"><RefreshCcw className="w-4 h-4 text-black" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-10 py-4 text-[11px] font-black uppercase tracking-widest shadow-xl text-white">{showForm ? 'Cancelar' : '+ Nueva Transacción'}</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-12 bg-black text-white grid grid-cols-3 gap-10 animate-in slide-in-from-top-10 duration-500">
           <div className="col-span-3"><h4 className="text-[12px] font-black uppercase tracking-[0.3em] flex items-center gap-3 text-white">Ejecutar Venta de Divisas</h4></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Saldo USD a Liquidar</label><input required type="number" step="0.01" value={usdToExchange || ''} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-700 p-5 font-black text-white outline-none focus:border-white transition-all text-xl" /></div>
