import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, 
  Calendar, 
  Users, 
  Wallet, 
  Plus, 
  Trash2, 
  CheckCircle2, 
  AlertCircle,
  TrendingUp,
  TrendingDown,
  BrainCircuit,
  DollarSign,
  FileDown,
  Upload,
  ChevronDown,
  X,
  Fuel,
  Utensils,
  MapPin,
  Pencil,
  BarChart3,
  PieChart,
  Filter,
  RefreshCcw,
  ClipboardList,
  Layers
} from 'lucide-react';
import { Staff, Event, Transaction, Role, Currency } from './types';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'events' | 'personal' | 'accounting'>('dashboard');

  // --- Filtros de Fecha Globales ---
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  // --- Estados con Persistencia LocalStorage ---
  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('rf_staff_v4');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'DJ Shadow', role: 'DJ', paymentType: 'FIXED', paymentValue: 200, currency: 'USD' },
      { id: '2', name: 'Ana Manager', role: 'Manager', paymentType: 'PERCENTAGE', paymentValue: 10, currency: 'DOP' },
    ];
  });

  const [events, setEvents] = useState<Event[]>(() => {
    const saved = localStorage.getItem('rf_events_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('rf_transactions_v4');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => { localStorage.setItem('rf_staff_v4', JSON.stringify(staff)); }, [staff]);
  useEffect(() => { localStorage.setItem('rf_events_v4', JSON.stringify(events)); }, [events]);
  useEffect(() => { localStorage.setItem('rf_transactions_v4', JSON.stringify(transactions)); }, [transactions]);

  const [aiInsights, setAiInsights] = useState<string>('Haz clic para un análisis profundo de tu flujo multi-moneda...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Lógica de Totales con Filtro de Fecha ---
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const date = t.date;
      if (startDate && date < startDate) return false;
      if (endDate && date > endDate) return false;
      return true;
    });
  }, [transactions, startDate, endDate]);

  const totals = useMemo(() => {
    const calc = (curr: Currency) => {
      const income = filteredTransactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = filteredTransactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [filteredTransactions]);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(filteredTransactions, events);
    setAiInsights(insights || 'Error al analizar.');
    setIsAnalyzing(false);
  };

  const clearFilters = () => {
    setStartDate('');
    setEndDate('');
  };

  return (
    <div className="flex h-screen bg-[#fafafa] font-sans selection:bg-black selection:text-white">
      {/* Sidebar */}
      <nav className="w-64 bg-black text-white flex flex-col shadow-2xl z-20">
        <div className="p-8 text-2xl font-black tracking-tighter border-b border-zinc-900 text-white">
          RF<span className="text-zinc-500">STUDIO</span>
        </div>
        <div className="flex-1 mt-6 space-y-1 px-4">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal" active={activeTab === 'personal'} onClick={() => setActiveTab('personal')} />
          <NavItem icon={<Wallet />} label="Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
        </div>
        <div className="p-8 border-t border-zinc-900">
          <div className="text-[9px] font-black text-zinc-400 uppercase tracking-[0.2em]">Management System v4.1</div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-10 bg-[#f8f8f8]">
        <header className="mb-8 flex justify-between items-end border-b border-zinc-200 pb-8">
          <div>
            <h1 className="text-4xl font-black text-black tracking-tight mb-2 uppercase">
              {activeTab === 'dashboard' && 'Panel de Control'}
              {activeTab === 'events' && 'Gestión de Agenda'}
              {activeTab === 'personal' && 'Equipo y Nómina'}
              {activeTab === 'accounting' && 'Caja y Transacciones'}
            </h1>
            <p className="text-zinc-400 font-bold tracking-tight text-sm">Resumen operativo sincronizado con TrueNAS.</p>
          </div>
          <div className="flex gap-4">
             <div className="bg-white px-8 py-5 rounded-none border-2 border-black shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] flex gap-10">
                <div>
                  <div className="text-[10px] uppercase font-black text-zinc-800 mb-2 tracking-widest">Caja DOP</div>
                  <div className={`text-xl font-black ${totals.DOP.balance >= 0 ? 'text-black' : 'text-red-600'}`}>
                    RD$ {totals.DOP.balance.toLocaleString()}
                  </div>
                </div>
                <div className="border-l border-zinc-100 pl-10">
                  <div className="text-[10px] uppercase font-black text-zinc-800 mb-2 tracking-widest">Caja USD</div>
                  <div className={`text-xl font-black ${totals.USD.balance >= 0 ? 'text-black' : 'text-red-600'}`}>
                    $ {totals.USD.balance.toLocaleString()}
                  </div>
                </div>
             </div>
          </div>
        </header>

        {/* Barra de Filtros Global */}
        {(activeTab === 'dashboard' || activeTab === 'accounting') && (
          <div className="mb-10 flex items-center gap-6 bg-white p-5 border border-zinc-200 text-[10px] font-black uppercase tracking-widest shadow-sm">
            <div className="flex items-center gap-3">
              <Filter className="w-4 h-4 text-black" />
              <span>Rango de Auditoría:</span>
            </div>
            <div className="flex items-center gap-4">
              <span className="text-zinc-500">Desde</span>
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black bg-zinc-50" />
            </div>
            <div className="flex items-center gap-4">
              <span className="text-zinc-500">Hasta</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black bg-zinc-50" />
            </div>
            {(startDate || endDate) && (
              <button onClick={clearFilters} className="text-red-600 hover:bg-red-50 transition-colors ml-auto border border-red-200 px-6 py-2">
                Restablecer Vista
              </button>
            )}
          </div>
        )}

        {activeTab === 'dashboard' && (
          <Dashboard 
            transactions={filteredTransactions}
            totals={totals} 
            events={events} 
            staff={staff}
            aiInsights={aiInsights} 
            handleAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing} 
            startDate={startDate}
            endDate={endDate}
          />
        )}
        {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'personal' && <StaffManager staff={staff} setStaff={setStaff} />}
        {activeTab === 'accounting' && <AccountingManager transactions={filteredTransactions} setTransactions={setTransactions} />}
      </main>
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-6 py-4 transition-all duration-300 ${active ? 'bg-white text-black font-black' : 'text-zinc-500 hover:text-white hover:bg-zinc-900'}`}>
    {React.cloneElement(icon as React.ReactElement<{ className?: string }>, { className: `w-4 h-4 ${active ? 'text-black' : 'text-white'}` })}
    <span className={`text-[11px] font-bold uppercase tracking-[0.15em] ${active ? 'text-black' : 'text-zinc-400 group-hover:text-white'}`}>{label}</span>
  </button>
);

const Dashboard: React.FC<{ transactions: Transaction[], totals: any, events: Event[], staff: Staff[], aiInsights: string, handleAnalyze: () => void, isAnalyzing: boolean, startDate: string, endDate: string }> = ({ transactions, totals, events, staff, aiInsights, handleAnalyze, isAnalyzing, startDate, endDate }) => {
  const pendingCount = events.filter(e => !e.completed).length;
  const completedCount = events.filter(e => e.completed).length;

  const pendingEventsList = events.filter(e => !e.completed);
  const receivableUSD = pendingEventsList.filter(e => e.currency === 'USD').reduce((acc, c) => acc + c.remainingAmount, 0);
  const receivableDOP = pendingEventsList.filter(e => e.currency === 'DOP').reduce((acc, c) => acc + c.remainingAmount, 0);

  const statsByCategory = useMemo(() => {
    const categories: Record<string, { incomeUSD: number, incomeDOP: number, expenseUSD: number, expenseDOP: number }> = {};
    transactions.forEach(t => {
      if (!categories[t.category]) categories[t.category] = { incomeUSD: 0, incomeDOP: 0, expenseUSD: 0, expenseDOP: 0 };
      if (t.type === 'INCOME') {
        if (t.currency === 'USD') categories[t.category].incomeUSD += t.amount;
        else categories[t.category].incomeDOP += t.amount;
      } else {
        if (t.currency === 'USD') categories[t.category].expenseUSD += t.amount;
        else categories[t.category].expenseDOP += t.amount;
      }
    });
    return Object.entries(categories).map(([name, data]) => ({ name, ...data }));
  }, [transactions]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 pb-20">
      <div className="lg:col-span-4 grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard label="Ingresos Totales" usd={totals.USD.income} dop={totals.DOP.income} />
        <MetricCard label="Egresos Totales" usd={totals.USD.expense} dop={totals.DOP.expense} />
        <MetricCard label="Saldo del Periodo" usd={totals.USD.balance} dop={totals.DOP.balance} />
        <div className="bg-white p-6 border border-zinc-200 shadow-sm flex flex-col justify-between">
          <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-500 mb-4">Volumen de Eventos</div>
          <div className="space-y-2">
            <div className="flex justify-between items-end border-b border-zinc-50 pb-2">
              <span className="text-[10px] font-bold text-zinc-400">TOTAL</span>
              <span className="text-xl font-black">{events.length}</span>
            </div>
            <div className="flex justify-between items-end pt-1">
              <span className="text-[10px] font-bold text-zinc-400">PENDIENTES / LISTOS</span>
              <span className="text-sm font-black text-black">
                <span className="text-red-600">{pendingCount}</span> / <span className="text-green-700">{completedCount}</span>
              </span>
            </div>
          </div>
        </div>
      </div>

      <div className="lg:col-span-3 space-y-8">
        <div className="bg-white p-10 border border-zinc-200 shadow-sm">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-10"><BarChart3 className="w-4 h-4 text-black" /> Análisis Financiero</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <CategoryStats title="Distribución de Ingresos" type="INCOME" data={statsByCategory} totals={totals} />
              <CategoryStats title="Estructura de Gastos" type="EXPENSE" data={statsByCategory} totals={totals} />
           </div>
        </div>

        <div className="bg-white p-10 border border-zinc-200">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-8"><Calendar className="w-4 h-4 text-black" /> Próximas Fechas en Agenda</h3>
           <table className="w-full text-left">
              <thead className="border-b border-zinc-100 text-[10px] uppercase font-black tracking-widest text-zinc-500">
                <tr><th className="pb-4">Evento</th><th className="pb-4">Fecha</th><th className="pb-4 text-right">Saldo por Cobrar</th></tr>
              </thead>
              <tbody className="divide-y divide-zinc-50">
                {pendingEventsList.sort((a,b) => a.date.localeCompare(b.date)).slice(0, 5).map(event => (
                  <tr key={event.id} className="hover:bg-zinc-50 transition-colors">
                    <td className="py-4 font-black uppercase text-xs">{event.title}</td>
                    <td className="py-4 text-xs text-zinc-600 font-bold">{event.date}</td>
                    <td className="py-4 text-right text-xs font-black text-red-600">{event.currency} {event.remainingAmount.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
           </table>
        </div>
      </div>

      <div className="lg:col-span-1 space-y-8">
        <div className="bg-black p-8 text-white shadow-xl">
          <h3 className="text-sm font-black uppercase tracking-widest mb-6 flex items-center gap-2 text-white"><BrainCircuit className="w-5 h-5 text-white" /> Inteligencia RF</h3>
          <div className="text-[12px] leading-relaxed mb-8 border-l-2 border-white pl-4 text-white font-medium">{aiInsights}</div>
          <button onClick={handleAnalyze} disabled={isAnalyzing} className="w-full bg-white text-black py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-200 shadow-lg text-black">{isAnalyzing ? 'Procesando...' : 'Obtener Análisis'}</button>
        </div>
      </div>
    </div>
  );
};

