             </div>
          </div>
          <button type="submit" className="col-span-3 bg-black text-white py-6 text-sm font-black uppercase tracking-widest hover:bg-zinc-900 transition-all shadow-xl">Confirmar Reserva de Fecha</button>
        </form>
      )}

      {/* Modal de Liquidación Final */}
      {closingEvent && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white border-4 border-black w-full max-w-2xl shadow-2xl overflow-hidden">
