                 </div>
              </div>
            </div>
            <div className="grid grid-cols-3 gap-8 mb-10 py-8 border-y-2 border-zinc-50">
               <div><div className="text-[10px] font-black uppercase text-zinc-400 mb-2 tracking-widest">Contrato</div><div className="text-lg font-black text-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-400 mb-2 tracking-widest">Abonado</div><div className="text-lg font-black text-green-700">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-400 mb-2 tracking-widest">Pendiente</div><div className="text-lg font-black text-red-600">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>
            <div className="flex justify-between items-center">
               <div className="flex -space-x-3">
                  {event.assignedStaff.map(sid => (
                    <div key={sid} className="w-10 h-10 bg-black text-white border-4 border-white flex items-center justify-center text-[12px] font-black uppercase rounded-full shadow-md transition-transform hover:scale-110 cursor-help" title={staff.find(st => st.id === sid)?.name}>
                      {staff.find(st => st.id === sid)?.name.charAt(0)}
                    </div>
                  ))}
               </div>
               <button onClick={() => { if(confirm('¿Eliminar evento permanentemente?')) setEvents(events.filter(e => e.id !== event.id))}} className="text-zinc-300 hover:text-red-600 transition-colors p-2"><Trash2 className="w-5 h-5" /></button>
            </div>
          </div>
        ))}
        {activeEvents.length === 0 && <div className="col-span-2 py-40 border-4 border-dashed border-zinc-100 flex flex-col items-center justify-center opacity-40"><Layers className="w-20 h-20 mb-6 text-zinc-300" /><p className="font-black uppercase tracking-[0.3em] text-lg text-zinc-600">Agenda Vacía</p></div>}
      </div>
    </div>
  );
};

