            </tr>
          ))}
          {transactions.length === 0 && <tr><td colSpan={5} className="py-40 text-center text-zinc-400 uppercase font-black text-[14px] italic tracking-widest opacity-30">Sin movimientos</td></tr>}
        </tbody>
      </table>
    </div>
  );
};

