        </div>
        <div className="p-8 border-t border-zinc-900 text-white">
          <div className="text-[9px] font-black text-zinc-400 uppercase tracking-[0.2em]">Management System v4.2</div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-10 bg-[#f8f8f8]">
