          </div>
          <div className="flex gap-4">
             <div className="bg-white px-8 py-5 rounded-none border-2 border-black shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] flex gap-10">
                <div>
                  <div className="text-[10px] uppercase font-black text-zinc-900 mb-2 tracking-widest">Caja DOP</div>
                  <div className={`text-xl font-black ${totals.DOP.balance >= 0 ? 'text-black' : 'text-red-600'}`}>
                    RD$ {totals.DOP.balance.toLocaleString()}
                  </div>
                </div>
                <div className="border-l border-zinc-100 pl-10">
                  <div className="text-[10px] uppercase font-black text-zinc-900 mb-2 tracking-widest">Caja USD</div>
                  <div className={`text-xl font-black ${totals.USD.balance >= 0 ? 'text-black' : 'text-red-600'}`}>
                    $ {totals.USD.balance.toLocaleString()}
                  </div>
