const CategoryStats: React.FC<{ title: string, type: 'INCOME' | 'EXPENSE', data: any[], totals: any }> = ({ title, type, data, totals }) => (
  <div>
    <div className="text-[10px] font-black uppercase text-zinc-600 mb-6 tracking-[0.2em]">{title}</div>
    <div className="space-y-5">
      {data.filter(d => type === 'INCOME' ? (d.incomeUSD > 0 || d.incomeDOP > 0) : (d.expenseUSD > 0 || d.expenseDOP > 0)).map(d => (
        <div key={d.name}>
          <div className="flex justify-between text-[10px] font-black uppercase mb-2">
            <span className="text-black">{d.name}</span>
            <span className="text-zinc-700 font-bold">
              {type === 'INCOME' ? `$${d.incomeUSD.toLocaleString()} / RD$${d.incomeDOP.toLocaleString()}` : `$${d.expenseUSD.toLocaleString()} / RD$${d.expenseDOP.toLocaleString()}`}
            </span>
          </div>
          <div className="h-1 bg-zinc-50 w-full overflow-hidden">
             <div className={`h-full transition-all duration-1000 ${type === 'INCOME' ? 'bg-black' : 'bg-zinc-500'}`} style={{ width: '100%' }} />
          </div>
        </div>
      ))}
      {data.length === 0 && <p className="text-[9px] uppercase text-zinc-400 italic font-bold">No hay registros</p>}
    </div>
  </div>
);

