const DEFAULT_CATEGORIES = [
  "Fiesta", "Plataformas Dig.", "Prestamo CRV", "Alquiler Vehiculo", "Nomina", 
  "Combustible", "Promociones", "Tiktokers", "Taxi", "Equipos", "Dieta", 
