const AccountingManager: React.FC<{ 
  transactions: Transaction[], 
  setTransactions: any, 
  categories: string[], 
  setCategories: (cats: string[]) => void 
}> = ({ transactions, setTransactions, categories, setCategories }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number>(0);
  const [usdToExchange, setUsdToExchange] = useState<number>(0);
  const [showNewCategoryInput, setShowNewCategoryInput] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ 
    type: 'INCOME', 
    amount: 0, 
    currency: 'DOP', 
    description: '', 
    date: new Date().toISOString().split('T')[0], 
    category: categories[0] || 'General' 
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();

    let finalCategory = formData.category;
    if (showNewCategoryInput && newCategoryName.trim()) {
      finalCategory = newCategoryName.trim();
      if (!categories.includes(finalCategory)) {
        setCategories([...categories, finalCategory]);
      }
    }

    const transactionData = { ...formData, category: finalCategory };

    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...transactionData, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...transactionData, id: Date.now().toString() }, ...prev]);

    resetForm();
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setShowNewCategoryInput(false);
    setNewCategoryName('');
    setFormData({ 
      type: 'INCOME', 
      amount: 0, 
      currency: 'DOP', 
      description: '', 
      date: new Date().toISOString().split('T')[0], 
      category: categories[0] || 'General' 
    });
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    if (usdToExchange <= 0 || exchangeRate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdToExchange, currency: 'USD', description: `Venta USD @ ${exchangeRate}`, date, category: 'Divisas' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdToExchange * exchangeRate, currency: 'DOP', description: `Entrada DOP @ ${exchangeRate}`, date, category: 'Divisas' };
    setTransactions((prev: Transaction[]) => [usdOut, dopIn, ...prev]);
    setShowExchange(false); setUsdToExchange(0); setExchangeRate(0);
  };

  const cleanNumber = (val: string) => {
    let s = val.replace(/[^\d,.-]/g, '');
    if (!s) return 0;
    if (s.includes('.') && s.includes(',')) {
      const lastComma = s.lastIndexOf(',');
      const lastDot = s.lastIndexOf('.');
      if (lastComma > lastDot) s = s.replace(/\./g, '').replace(',', '.');
      else s = s.replace(/,/g, '');
    } else if (s.includes(',')) {
      const parts = s.split(',');
      if (parts[parts.length - 1].length === 3) s = s.replace(/,/g, '');
      else s = s.replace(',', '.');
    } else if (s.includes('.')) {
      const parts = s.split('.');
      if (parts[parts.length - 1].length === 3 && parts.length > 1) s = s.replace(/\./g, ''); 
    }
    return parseFloat(s) || 0;
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const rows = text.split(/\r?\n/);
      const newTransactions: Transaction[] = [];
      const newCats = new Set(categories);

      rows.forEach((row, index) => {
        if (index === 0 && row.toLowerCase().includes('fecha')) return;
        if (!row.trim()) return;
        const columns = row.split(';').map(c => c.trim().replace(/^"|"$/g, ''));
        if (columns.length >= 5) {
          const dateStr = columns[0];
          const cat = columns[1] || 'General';
          const description = columns[2];
          const amountStr = columns[3];
          const typeStr = columns[4];
          const method = columns[5] || '';
          const currencyStr = columns[6] || 'DOP';

          let finalDate = dateStr;
          const dateParts = dateStr.split('/');
          if (dateParts.length === 3) {
            const d = dateParts[0].padStart(2, '0');
            const m = dateParts[1].padStart(2, '0');
            let y = dateParts[2];
            if (y.length === 2) y = `20${y}`;
            finalDate = `${y}-${m}-${d}`;
          }

          const finalAmount = cleanNumber(amountStr);
          const type: 'INCOME' | 'EXPENSE' = typeStr.toLowerCase().includes('ingreso') ? 'INCOME' : 'EXPENSE';
          if (!isNaN(finalAmount)) {
            newTransactions.push({
              id: `imp-${Date.now()}-${index}-${Math.random()}`,
              date: finalDate,
              category: cat,
              description: `${description}${method ? ` [${method}]` : ''}`,
              amount: Math.abs(finalAmount),
              type,
              currency: (currencyStr.toUpperCase() === 'USD' ? 'USD' : 'DOP') as Currency
            });
            if (cat) newCats.add(cat);
          }
        }
      });

      if (newTransactions.length > 0) {
        setTransactions((prev: Transaction[]) => [...newTransactions, ...prev]);
        setCategories(Array.from(newCats));
        alert(`Sincronización completa: ${newTransactions.length} registros importados.`);
      } else {
        alert('Formato de archivo no válido. Asegúrate de usar punto y coma.');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-xl overflow-hidden pb-20">
      <div className="p-12 border-b-2 border-zinc-50 flex justify-between items-center bg-white">
        <h3 className="text-2xl font-black uppercase tracking-widest text-black">Caja y Bancos</h3>
        <div className="flex gap-6">
          <input type="file" ref={fileInputRef} onChange={handleImportCSV} accept=".csv" className="hidden" />
          <button onClick={() => fileInputRef.current?.click()} className="border-4 border-black px-6 py-3 text-[11px] font-black uppercase flex items-center gap-3 hover:bg-zinc-100 transition-all text-black font-black">
            <Upload className="w-4 h-4 text-black" /> Importar CSV (;)
          </button>
          <button onClick={() => setShowExchange(!showExchange)} className="border-4 border-black px-8 py-3 text-[11px] font-black uppercase flex items-center gap-3 hover:bg-zinc-100 transition-all text-black font-black"><RefreshCcw className="w-4 h-4 text-black" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(true); setEditingId(null); }} className="bg-black text-white px-10 py-4 text-[11px] font-black uppercase tracking-widest shadow-xl text-white font-black">Nuevo Movimiento</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-12 bg-black text-white grid grid-cols-3 gap-10 animate-in slide-in-from-top-10 duration-500">
           <div className="col-span-3"><h4 className="text-[12px] font-black uppercase tracking-[0.3em] flex items-center gap-3 text-white">Intercambio de Divisas</h4></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest text-white">Saldo USD</label><input required type="number" step="0.01" value={usdToExchange || ''} onChange={e => setUsdToExchange(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-700 p-5 font-black text-white outline-none focus:border-white transition-all text-xl" /></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest text-white">Tasa RD$</label><input required type="number" step="0.01" value={exchangeRate || ''} onChange={e => setExchangeRate(Number(e.target.value))} className="w-full bg-zinc-900 border-zinc-700 p-5 font-black text-white outline-none focus:border-white transition-all text-xl" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-6 text-[12px] font-black uppercase tracking-widest hover:bg-zinc-200 shadow-2xl transition-all text-black font-black">Ejecutar Operación</button></div>
        </form>
      )}

      {showForm && (
        <form onSubmit={handleSave} className="p-12 bg-zinc-50 border-b-2 border-zinc-100 grid grid-cols-4 gap-8 animate-in slide-in-from-top-10 duration-500">
           <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Tipo</label><select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white text-black"><option value="INCOME">Ingreso (+)</option><option value="EXPENSE">Egreso (-)</option></select></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white text-black"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Importe</label><input required type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className="w-full p-4 border-2 border-zinc-200 font-black focus:border-black outline-none bg-white text-black" /></div>

           <div>
              <label className="block text-[10px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Categoría</label>
              <select 
                value={showNewCategoryInput ? "NEW" : formData.category} 
                onChange={e => {
                  if (e.target.value === "NEW") {
                    setShowNewCategoryInput(true);
                  } else {
                    setShowNewCategoryInput(false);
                    setFormData({...formData, category: e.target.value});
                  }
                }} 
                className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white text-black"
              >
                {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                <option value="NEW">+ Agregar nueva categoría...</option>
              </select>
              {showNewCategoryInput && (
                <input 
                  autoFocus
                  placeholder="Escribe la categoría..."
                  type="text" 
                  value={newCategoryName} 
                  onChange={e => setNewCategoryName(e.target.value)} 
                  className="w-full mt-2 p-3 border-2 border-black font-black uppercase text-[10px] outline-none bg-white text-black placeholder:text-zinc-300"
                />
              )}
           </div>

           <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Concepto</label><input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white text-black" /></div>
           <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold focus:border-black outline-none bg-white text-black" /></div>

           <div className="flex gap-4 items-end">
              <button 
                type="button" 
                onClick={resetForm} 
                className="flex-1 border-2 border-zinc-300 text-zinc-400 py-6 text-[12px] font-black uppercase tracking-widest hover:border-black hover:text-black transition-all font-black"
              >
                Cancelar
              </button>
              <button 
                type="submit" 
                className="flex-[2] bg-black text-white py-6 text-[12px] font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all text-white font-black"
              >
                {editingId ? 'Actualizar' : 'Guardar'}
              </button>
           </div>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b-2 border-zinc-100 font-black text-[11px] uppercase tracking-[0.2em] text-zinc-700"><tr><th className="px-12 py-8">Fecha</th><th className="px-12 py-8">Detalle</th><th className="px-12 py-8">Categoría</th><th className="px-12 py-8 text-right">Monto</th><th className="px-12 py-8 text-right">Gestión</th></tr></thead>
        <tbody className="divide-y divide-zinc-50">
          {transactions.map(t => (
            <tr key={t.id} className="hover:bg-zinc-50 group transition-all duration-300">
              <td className="px-12 py-10 text-[10px] font-black text-zinc-700 uppercase tracking-widest">{t.date}</td>
              <td className="px-12 py-10 font-black text-black uppercase tracking-tight text-xs max-w-xs">{t.description}</td>
              <td className="px-12 py-10"><span className="text-[10px] font-black uppercase border-2 border-zinc-100 px-4 py-2 bg-white tracking-widest text-zinc-900">{t.category}</span></td>
              <td className={`px-12 py-10 text-right font-black tracking-tighter text-base ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-600'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
              <td className="px-12 py-10 text-right opacity-0 group-hover:opacity-100 transition-all flex justify-end gap-6"><button onClick={() => { setEditingId(t.id); setFormData(t); setShowForm(true); setShowNewCategoryInput(false); }} className="text-zinc-500 hover:text-black border-b border-transparent hover:border-black pb-1 uppercase text-[10px] font-black">Editar</button><button onClick={() => setTransactions((prev: Transaction[]) => prev.filter(tr => tr.id !== t.id))} className="text-zinc-400 hover:text-red-600 border-b border-transparent hover:border-red-600 pb-1 uppercase text-[10px] font-black font-black">Eliminar</button></td>
            </tr>
          ))}
          {transactions.length === 0 && <tr><td colSpan={5} className="py-40 text-center text-zinc-400 uppercase font-black text-[14px] italic tracking-widest opacity-30">Sin movimientos registrados</td></tr>}
        </tbody>
      </table>
    </div>
  );
};

