const Dashboard: React.FC<{ transactions: Transaction[], totals: any, events: Event[], staff: Staff[], aiInsights: string, handleAnalyze: () => void, isAnalyzing: boolean }> = ({ transactions, totals, events, staff, aiInsights, handleAnalyze, isAnalyzing }) => {
  const pendingCount = events.filter(e => !e.completed).length;
  const completedCount = events.filter(e => e.completed).length;
  const pendingEventsList = events.filter(e => !e.completed);

  const statsByCategory = useMemo(() => {
    const categories: Record<string, { incomeUSD: number, incomeDOP: number, expenseUSD: number, expenseDOP: number }> = {};
    transactions.forEach(t => {
      if (!categories[t.category]) categories[t.category] = { incomeUSD: 0, incomeDOP: 0, expenseUSD: 0, expenseDOP: 0 };
      if (t.type === 'INCOME') {
        if (t.currency === 'USD') categories[t.category].incomeUSD += t.amount;
        else categories[t.category].incomeDOP += t.amount;
      } else {
        if (t.currency === 'USD') categories[t.category].expenseUSD += t.amount;
        else categories[t.category].expenseDOP += t.amount;
      }
    });
    return Object.entries(categories).map(([name, data]) => ({ name, ...data }));
  }, [transactions]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 pb-20">
      <div className="lg:col-span-4 grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard label="Ingresos Totales" usd={totals.USD.income} dop={totals.DOP.income} />
        <MetricCard label="Egresos Totales" usd={totals.USD.expense} dop={totals.DOP.expense} />
        <MetricCard label="Saldo del Periodo" usd={totals.USD.balance} dop={totals.DOP.balance} />
        <div className="bg-white p-6 border border-zinc-200 shadow-sm flex flex-col justify-between">
          <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-700 mb-4">Volumen de Eventos</div>
          <div className="space-y-2">
            <div className="flex justify-between items-end border-b border-zinc-50 pb-2">
              <span className="text-[10px] font-bold text-zinc-500">TOTAL</span>
              <span className="text-xl font-black">{events.length}</span>
            </div>
            <div className="flex justify-between items-end pt-1">
              <span className="text-[10px] font-bold text-zinc-500">PENDIENTES / LISTOS</span>
              <span className="text-sm font-black text-black">
                <span className="text-red-600">{pendingCount}</span> / <span className="text-green-700">{completedCount}</span>
              </span>
            </div>
          </div>
        </div>
      </div>

      <div className="lg:col-span-3 space-y-8">
        <div className="bg-white p-10 border border-zinc-200 shadow-sm">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 mb-10 text-black"><BarChart3 className="w-4 h-4 text-black" /> Análisis Financiero</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <CategoryStats title="Distribución de Ingresos" type="INCOME" data={statsByCategory} />
              <CategoryStats title="Estructura de Gastos" type="EXPENSE" data={statsByCategory} />
           </div>
        </div>
      </div>

      <div className="lg:col-span-1 space-y-8">
        <div className="bg-black p-8 text-white shadow-xl">
          <h3 className="text-sm font-black uppercase tracking-widest mb-6 flex items-center gap-2 text-white"><BrainCircuit className="w-5 h-5 text-white" /> Inteligencia RF</h3>
          <div className="text-[12px] leading-relaxed mb-8 border-l-2 border-white pl-4 text-white font-medium">{aiInsights}</div>
          <button onClick={handleAnalyze} disabled={isAnalyzing} className="w-full bg-white text-black py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-200 shadow-lg font-black">{isAnalyzing ? 'Procesando...' : 'Obtener Análisis'}</button>
        </div>
      </div>
    </div>
  );
};

