  );
};

const AccountingManager: React.FC<{ 
  transactions: Transaction[], 
  setTransactions: any, 
  categories: string[], 
  setCategories: (cats: string[]) => void 
}> = ({ transactions, setTransactions, categories, setCategories }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [showNewCategoryInput, setShowNewCategoryInput] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ 
    type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' 
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = (e: React.FormEvent, isInline: boolean = false) => {
    e.preventDefault();
    let finalCategory = formData.category;
    if (showNewCategoryInput && newCategoryName.trim()) {
      finalCategory = newCategoryName.trim();
      if (!categories.includes(finalCategory)) setCategories([...categories, finalCategory]);
    }
    const data = { ...formData, category: finalCategory };
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...data, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...data, id: Date.now().toString() }, ...prev]);
    resetForm();
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setShowNewCategoryInput(false);
    setNewCategoryName('');
    setFormData({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' });
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const rows = (event.target?.result as string).split(/\r?\n/);
      const newTransactions: Transaction[] = [];
      const newCats = new Set(categories);
      rows.forEach((row, index) => {
        if (index === 0 && row.toLowerCase().includes('fecha')) return;
        if (!row.trim()) return;
        const col = row.split(';').map(c => c.trim().replace(/^"|"$/g, ''));
        if (col.length >= 5) {
          const amount = parseFloat(col[3].replace(/[^\d,.-]/g, '').replace(',', '.')) || 0;
          const type: 'INCOME' | 'EXPENSE' = col[4].toLowerCase().includes('ingreso') ? 'INCOME' : 'EXPENSE';
          newTransactions.push({ id: `i-${Date.now()}-${index}`, date: col[0], category: col[1], description: col[2], amount: Math.abs(amount), type, currency: (col[6] === 'USD' ? 'USD' : 'DOP') as Currency });
          if (col[1]) newCats.add(col[1]);
        }
      });
      setTransactions((prev: Transaction[]) => [...newTransactions, ...prev]);
      setCategories(Array.from(newCats));
      alert(`Importados ${newTransactions.length} registros.`);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const startEditing = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({ ...t });
    setShowForm(false); // Ocultar formulario superior si estaba abierto
    setShowNewCategoryInput(false);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-xl pb-20 overflow-hidden">
      <div className="p-12 border-b flex justify-between items-center bg-white text-black">
        <h3 className="text-2xl font-black uppercase tracking-widest">Transacciones</h3>
        <div className="flex gap-4">
          <input type="file" ref={fileInputRef} onChange={handleImportCSV} accept=".csv" className="hidden" />
          <button onClick={() => fileInputRef.current?.click()} className="border-4 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all text-black"><Upload className="w-4 h-4" /> Importar CSV</button>
          <button onClick={() => { setShowForm(true); setEditingId(null); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest shadow-lg text-white font-black">+ Nuevo Movimiento</button>
        </div>
      </div>

      {showForm && !editingId && (
        <div className="p-12 bg-zinc-50 border-b animate-in slide-in-from-top-4 duration-300">
          <form onSubmit={e => handleSave(e, false)} className="grid grid-cols-4 gap-6">
            <div className="col-span-4"><h4 className="text-xs font-black uppercase tracking-widest text-zinc-400 mb-2">Nuevo Registro</h4></div>
            <FormFields formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
            <div className="col-span-4 flex gap-4 pt-4">
              <button type="button" onClick={resetForm} className="flex-1 border-2 border-zinc-200 py-4 text-[11px] font-black uppercase text-zinc-400 hover:border-black hover:text-black transition-all font-black">Cancelar</button>
              <button type="submit" className="flex-[2] bg-black text-white py-4 text-[11px] font-black uppercase tracking-widest shadow-xl text-white font-black">Registrar Movimiento</button>
            </div>
          </form>
        </div>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b font-black text-[11px] uppercase tracking-widest text-zinc-500"><tr><th className="px-12 py-6">Fecha</th><th className="px-12 py-6">Descripción</th><th className="px-12 py-6">Categoría</th><th className="px-12 py-6 text-right">Monto</th><th className="px-12 py-6 text-right">Gestión</th></tr></thead>
        <tbody>
          {transactions.map(t => (
            <React.Fragment key={t.id}>
              {editingId === t.id ? (
                <tr className="bg-zinc-900 text-white animate-in fade-in duration-300">
                  <td colSpan={5} className="p-10">
                    <form onSubmit={e => handleSave(e, true)} className="grid grid-cols-4 gap-6">
                      <div className="col-span-4 flex justify-between items-center mb-4">
                        <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-500">Editando Registro en Línea</span>
                        <div className="flex gap-4">
                          <button type="button" onClick={resetForm} className="text-zinc-500 hover:text-white uppercase text-[10px] font-black border border-zinc-700 px-4 py-2 font-black">Cancelar</button>
                          <button type="submit" className="bg-white text-black uppercase text-[10px] font-black px-6 py-2 shadow-lg font-black">Guardar Cambios</button>
                        </div>
                      </div>
                      <FormFields inline formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
                    </form>
                  </td>
                </tr>
              ) : (
                <tr className="hover:bg-zinc-50 group transition-all border-b last:border-0">
                  <td className="px-12 py-8 text-[10px] font-black text-zinc-500 uppercase">{t.date}</td>
                  <td className="px-12 py-8 font-black text-black uppercase text-xs truncate max-w-[200px]">{t.description}</td>
                  <td className="px-12 py-8"><span className="text-[10px] font-black uppercase border-2 border-zinc-100 px-3 py-1 bg-white text-zinc-800">{t.category}</span></td>
                  <td className={`px-12 py-8 text-right font-black text-base ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-500'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
                  <td className="px-12 py-8 text-right space-x-6">
                    <button onClick={() => startEditing(t)} className="text-zinc-400 hover:text-black uppercase text-[10px] font-black transition-all font-black">Editar</button>
                    <button onClick={() => setTransactions((prev: Transaction[]) => prev.filter(tr => tr.id !== t.id))} className="text-zinc-300 hover:text-red-600 uppercase text-[10px] font-black transition-all font-black">Eliminar</button>
                  </td>
                </tr>
              )}
            </React.Fragment>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const FormFields: React.FC<{ 
  inline?: boolean, 
  formData: any, 
  setFormData: any, 
  categories: string[], 
  showNewCategoryInput: boolean, 
  setShowNewCategoryInput: any, 
  newCategoryName: string, 
  setNewCategoryName: any 
}> = ({ inline, formData, setFormData, categories, showNewCategoryInput, setShowNewCategoryInput, newCategoryName, setNewCategoryName }) => {
  const inputClass = `w-full p-4 border-2 font-bold outline-none transition-all ${inline ? 'bg-zinc-800 border-zinc-700 text-white focus:border-white' : 'bg-white border-zinc-200 text-black focus:border-black'}`;
  const labelClass = `block text-[9px] font-black uppercase mb-2 ${inline ? 'text-zinc-500' : 'text-zinc-500'}`;

  return (
    <>
      <div><label className={labelClass}>Tipo</label><select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className={inputClass}><option value="INCOME">Ingreso (+)</option><option value="EXPENSE">Egreso (-)</option></select></div>
      <div><label className={labelClass}>Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className={inputClass}><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
      <div><label className={labelClass}>Importe</label><input required type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: Number(e.target.value)})} className={inputClass} /></div>
      <div>
        <label className={labelClass}>Categoría</label>
        <select value={showNewCategoryInput ? "NEW" : formData.category} onChange={e => { if (e.target.value === "NEW") setShowNewCategoryInput(true); else { setShowNewCategoryInput(false); setFormData({...formData, category: e.target.value}); } }} className={inputClass}>
          {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
          <option value="NEW">+ Otra Categoría...</option>
        </select>
        {showNewCategoryInput && <input autoFocus placeholder="Nombre de categoría..." type="text" value={newCategoryName} onChange={e => setNewCategoryName(e.target.value)} className={`w-full mt-2 p-3 text-[10px] font-black uppercase outline-none border-2 ${inline ? 'bg-black border-zinc-500 text-white' : 'bg-white border-black text-black'}`} />}
      </div>
      <div className="col-span-2"><label className={labelClass}>Concepto</label><input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className={inputClass} /></div>
      <div className="col-span-2"><label className={labelClass}>Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className={inputClass} /></div>
    </>
  );
};

