import { getFinancialInsights } from './services/geminiService';

const DEFAULT_CATEGORIES = [
  "Fiesta", "Plataformas Dig.", "Prestamo CRV", "Alquiler Vehiculo", "Nomina", 
  "Combustible", "Promociones", "Tiktokers", "Taxi", "Equipos", "Dieta", 
  "Otros", "JM", "Ray", "GMB", "Yoan", "JM-Pendiente", "Video", "FT", 
  "Servicios", "Divisas", "1Family", "Impuestos", "Licencias"
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'events' | 'personal' | 'accounting'>('dashboard');

  // --- Filtros de Fecha Globales ---
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  // --- Estados con Persistencia LocalStorage ---
  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('rf_staff_v4');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'DJ Shadow', role: 'DJ', paymentType: 'FIXED', paymentValue: 200, currency: 'USD' },
      { id: '2', name: 'Ana Manager', role: 'Manager', paymentType: 'PERCENTAGE', paymentValue: 10, currency: 'DOP' },
    ];
  });

  const [events, setEvents] = useState<Event[]>(() => {
    const saved = localStorage.getItem('rf_events_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('rf_transactions_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [categories, setCategories] = useState<string[]>(() => {
    const saved = localStorage.getItem('rf_categories_v4');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  useEffect(() => { localStorage.setItem('rf_staff_v4', JSON.stringify(staff)); }, [staff]);
  useEffect(() => { localStorage.setItem('rf_events_v4', JSON.stringify(events)); }, [events]);
  useEffect(() => { localStorage.setItem('rf_transactions_v4', JSON.stringify(transactions)); }, [transactions]);
  useEffect(() => { localStorage.setItem('rf_categories_v4', JSON.stringify(categories)); }, [categories]);

  const [aiInsights, setAiInsights] = useState<string>('Haz clic para un análisis profundo de tu flujo multi-moneda...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Lógica de Totales con Filtro de Fecha ---
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const date = t.date;
      if (startDate && date < startDate) return false;
      if (endDate && date > endDate) return false;
      return true;
    });
  }, [transactions, startDate, endDate]);

  const totals = useMemo(() => {
    const calc = (curr: Currency) => {
      const income = filteredTransactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = filteredTransactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [filteredTransactions]);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(filteredTransactions, events);
    setAiInsights(insights || 'Error al analizar.');
    setIsAnalyzing(false);
  };

  const clearFilters = () => {
    setStartDate('');
    setEndDate('');
  };

  return (
    <div className="flex h-screen bg-[#fafafa] font-sans selection:bg-black selection:text-white">
      {/* Sidebar */}
      <nav className="w-64 bg-black text-white flex flex-col shadow-2xl z-20">
        <div className="p-8 text-2xl font-black tracking-tighter border-b border-zinc-900 text-white">
          RF<span className="text-zinc-500">STUDIO</span>
        </div>
        <div className="flex-1 mt-6 space-y-1 px-4 text-white">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal" active={activeTab === 'personal'} onClick={() => setActiveTab('personal')} />
          <NavItem icon={<Wallet />} label="Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
        </div>
        <div className="p-8 border-t border-zinc-900 text-white">
          <div className="text-[9px] font-black text-zinc-400 uppercase tracking-[0.2em]">Management System v4.5</div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-10 bg-[#f8f8f8]">
        <header className="mb-8 flex justify-between items-end border-b border-zinc-200 pb-8">
          <div>
            <h1 className="text-4xl font-black text-black tracking-tight mb-2 uppercase">
              {activeTab === 'dashboard' && 'Panel de Control'}
              {activeTab === 'events' && 'Gestión de Agenda'}
              {activeTab === 'personal' && 'Equipo y Nómina'}
              {activeTab === 'accounting' && 'Caja y Transacciones'}
            </h1>
            <p className="text-zinc-500 font-bold tracking-tight text-sm">Resumen operativo sincronizado con TrueNAS.</p>
          </div>
          <div className="flex gap-4">
             <div className="bg-white px-8 py-5 rounded-none border-2 border-black shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] flex gap-10">
                <div>
                  <div className="text-[10px] uppercase font-black text-zinc-900 mb-2 tracking-widest">Caja DOP</div>
                  <div className={`text-xl font-black ${totals.DOP.balance >= 0 ? 'text-black' : 'text-red-600'}`}>
                    RD$ {totals.DOP.balance.toLocaleString()}
                  </div>
                </div>
                <div className="border-l border-zinc-100 pl-10">
                  <div className="text-[10px] uppercase font-black text-zinc-900 mb-2 tracking-widest">Caja USD</div>
                  <div className={`text-xl font-black ${totals.USD.balance >= 0 ? 'text-black' : 'text-red-600'}`}>
                    $ {totals.USD.balance.toLocaleString()}
                  </div>
                </div>
             </div>
          </div>
        </header>

        {/* Barra de Filtros Global */}
        {(activeTab === 'dashboard' || activeTab === 'accounting') && (
          <div className="mb-10 flex items-center gap-6 bg-white p-5 border border-zinc-200 text-[10px] font-black uppercase tracking-widest shadow-sm">
            <div className="flex items-center gap-3">
              <Filter className="w-4 h-4 text-black" />
              <span>Rango de Auditoría:</span>
            </div>
            <div className="flex items-center gap-4">
              <span className="text-zinc-600">Desde</span>
              <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black bg-zinc-50 text-black" />
            </div>
            <div className="flex items-center gap-4">
              <span className="text-zinc-600">Hasta</span>
              <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black bg-zinc-50 text-black" />
            </div>
            {(startDate || endDate) && (
              <button onClick={clearFilters} className="text-red-600 hover:bg-red-50 transition-colors ml-auto border border-red-200 px-6 py-2 font-black uppercase">
                Restablecer Vista
              </button>
            )}
          </div>
        )}

        {activeTab === 'dashboard' && (
          <Dashboard 
            transactions={filteredTransactions}
            totals={totals} 
            events={events} 
            staff={staff}
            aiInsights={aiInsights} 
            handleAnalyze={handleAnalyze} 
