const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({
    title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP' as Currency, assignedStaff: [] as string[]
  });

  const [closingExpenses, setClosingExpenses] = useState({
    fuel: 0, fuelDetail: '', 
    toll: 0, tollDetail: '', 
    diet: 0, dietDetail: '', 
    others: 0, othersDetail: '', 
    currency: 'DOP' as Currency
  });

  const activeEvents = useMemo(() => events.filter(e => !e.completed), [events]);

  const handleEdit = (event: Event) => {
    setEditingId(event.id);
    setFormData({
      title: event.title, date: event.date, time: event.time, totalPrice: event.totalPrice, paidAmount: event.paidAmount, currency: event.currency, assignedStaff: event.assignedStaff
    });
    setShowForm(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount } : ev));
    } else {
      const newId = Date.now().toString();
      const newEvent: Event = { id: newId, ...formData, remainingAmount: formData.totalPrice - formData.paidAmount, status: 'PENDING', completed: false };
      setEvents([...events, newEvent]);
      if (formData.paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: formData.paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Fiesta', eventId: newId }, ...transactions]);
      }
    }
    closeForm();
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: 0, paidAmount: 0, currency: 'DOP', assignedStaff: [] });
  };

  const handleComplete = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;
    if (closingExpenses.others > 0 && !closingExpenses.othersDetail.trim()) {
      alert("Describe el gasto 'Otros'.");
      return;
    }
    const date = new Date().toISOString().split('T')[0];
    const newTrans: Transaction[] = [];
    const exp = [{ k: 'fuel', d: 'fuelDetail', l: 'Combustible' }, { k: 'toll', d: 'tollDetail', l: 'Peaje' }, { k: 'others', d: 'othersDetail', l: 'Otros' }];
    exp.forEach(x => {
      const val = (closingExpenses as any)[x.k];
      const detail = (closingExpenses as any)[x.d];
      if (val > 0) {
        newTrans.push({ id: `e-${Date.now()}-${x.k}`, type: 'EXPENSE', amount: val, currency: closingExpenses.currency, description: `${x.l} (${detail || 'Evento'}): ${closingEvent.title}`, date, category: x.l, eventId: closingEvent.id });
      }
    });
    closingEvent.assignedStaff.forEach(sid => {
      const s = staff.find(st => st.id === sid);
      if (s) {
        const pay = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTrans.push({ id: `p-${Date.now()}-${s.id}`, type: 'EXPENSE', amount: pay, currency: s.currency, description: `Nómina (${s.name}): ${closingEvent.title}`, date, category: 'Nomina', eventId: closingEvent.id });
      }
    });
    if (closingEvent.remainingAmount > 0) {
      newTrans.push({ id: `c-${Date.now()}`, type: 'INCOME', amount: closingEvent.remainingAmount, currency: closingEvent.currency, description: `Liquidación Final: ${closingEvent.title}`, date, category: 'Fiesta', eventId: closingEvent.id });
    }
    setTransactions([...newTrans, ...transactions]);
    setEvents(events.map(ev => ev.id === closingEvent.id ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } : ev));
    setClosingEvent(null);
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-10 py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition-all shadow-xl font-black">
          {showForm ? 'Cerrar Formulario' : '+ Registrar Evento'}
        </button>
      </div>
      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-12 border border-black grid grid-cols-3 gap-8 animate-in fade-in zoom-in-95 duration-300 shadow-2xl relative">
          <div className="col-span-3">
            <label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Nombre del Evento</label>
            <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none focus:border-black text-lg text-black" />
          </div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none font-bold text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Hora</label><input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none font-bold text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border border-zinc-200 font-bold outline-none text-black"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Precio Total</label><input required type="number" value={formData.totalPrice || ''} onChange={e => setFormData({...formData, totalPrice: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-black outline-none text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Abono</label><input required type="number" value={formData.paidAmount || ''} onChange={e => setFormData({...formData, paidAmount: Number(e.target.value)})} className="w-full p-4 border border-zinc-200 font-black outline-none text-black" /></div>
          <button type="submit" className="col-span-3 bg-black text-white py-6 text-sm font-black uppercase tracking-widest shadow-xl font-black">Confirmar Fecha</button>
        </form>
      )}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        {activeEvents.map(event => (
          <div key={event.id} className="bg-white p-12 border border-zinc-200 relative group hover:border-black transition-all shadow-sm">
            <h3 className="text-3xl font-black text-black tracking-tighter uppercase mb-6">{event.title}</h3>
            <div className="grid grid-cols-3 gap-8 py-8 border-y border-zinc-50">
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Contrato</div><div className="text-lg font-black text-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Abonado</div><div className="text-lg font-black text-green-700">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Pendiente</div><div className="text-lg font-black text-red-600">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>
            <div className="mt-8 flex justify-between">
               <div className="flex gap-4">
                  <button onClick={() => handleEdit(event)} className="p-2 border border-zinc-200 hover:bg-black hover:text-white transition-all text-black"><Pencil className="w-4 h-4" /></button>
                  <button onClick={() => setClosingEvent(event)} className="bg-black text-white px-6 py-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-2 font-black">Liquidar <CheckCircle2 className="w-4 h-4" /></button>
               </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

