const AccountingManager: React.FC<{ 
  transactions: Transaction[], 
  setTransactions: any, 
  categories: string[], 
  setCategories: (cats: string[]) => void 
}> = ({ transactions, setTransactions, categories, setCategories }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [showNewCategoryInput, setShowNewCategoryInput] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const [formData, setFormData] = useState<Omit<Transaction, 'id'>>({ 
    type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' 
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const cleanNumber = (val: string) => {
    let s = val.replace(/[^\d,.-]/g, '');
    if (!s) return 0;

    // Si tiene comas y puntos, identificar separador decimal
    if (s.includes('.') && s.includes(',')) {
      const lastComma = s.lastIndexOf(',');
      const lastDot = s.lastIndexOf('.');
      if (lastComma > lastDot) {
        // Estilo 1.000,00 -> 1000.00
        s = s.replace(/\./g, '').replace(',', '.');
      } else {
        // Estilo 1,000.00 -> 1000.00
        s = s.replace(/,/g, '');
      }
    } else if (s.includes(',')) {
      const parts = s.split(',');
      // Si después de la coma hay 3 dígitos, es separador de miles (ej. 10,000)
      if (parts[parts.length - 1].length === 3) {
        s = s.replace(/,/g, '');
      } else {
        // Si no, es decimal (ej. 10,50)
        s = s.replace(',', '.');
      }
    } else if (s.includes('.')) {
      const parts = s.split('.');
      // Si después del punto hay 3 dígitos y es el único punto, podría ser miles
      if (parts[parts.length - 1].length === 3 && parts.length === 2) {
        // En muchos contextos latinos "." es miles. Pero para parseFloat necesitamos "." como decimal.
        // Si asumimos que los montos grandes son miles:
        s = s.replace(/\./g, ''); 
      }
    }
    return parseFloat(s) || 0;
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    let finalCategory = formData.category;
    if (showNewCategoryInput && newCategoryName.trim()) {
      finalCategory = newCategoryName.trim();
      if (!categories.includes(finalCategory)) setCategories([...categories, finalCategory]);
    }
    const data = { ...formData, category: finalCategory };
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...data, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...data, id: Date.now().toString() }, ...prev]);
    resetForm();
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setShowNewCategoryInput(false);
    setNewCategoryName('');
    setFormData({ type: 'INCOME', amount: 0, currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' });
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const rows = (event.target?.result as string).split(/\r?\n/);
      const newTransactions: Transaction[] = [];
      const newCats = new Set(categories);
      rows.forEach((row, index) => {
        if (index === 0 && row.toLowerCase().includes('fecha')) return;
        if (!row.trim()) return;
        const col = row.split(';').map(c => c.trim().replace(/^"|"$/g, ''));
        if (col.length >= 5) {
          const rawAmount = col[3];
          const finalAmount = cleanNumber(rawAmount);
          const type: 'INCOME' | 'EXPENSE' = col[4].toLowerCase().includes('ingreso') ? 'INCOME' : 'EXPENSE';

          let dateStr = col[0];
          const dateParts = dateStr.split('/');
          if (dateParts.length === 3) {
            const d = dateParts[0].padStart(2, '0');
            const m = dateParts[1].padStart(2, '0');
            let y = dateParts[2];
            if (y.length === 2) y = `20${y}`;
            dateStr = `${y}-${m}-${d}`;
          }

          newTransactions.push({ 
            id: `i-${Date.now()}-${index}`, 
            date: dateStr, 
            category: col[1] || 'General', 
            description: col[2], 
            amount: Math.abs(finalAmount), 
            type, 
            currency: (col[6]?.toUpperCase() === 'USD' ? 'USD' : 'DOP') as Currency 
          });
          if (col[1]) newCats.add(col[1]);
        }
      });
      setTransactions((prev: Transaction[]) => [...newTransactions, ...prev]);
      setCategories(Array.from(newCats));
      alert(`Importados ${newTransactions.length} registros.`);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const startEditing = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({ ...t });
    setShowForm(false);
    setShowNewCategoryInput(false);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-xl pb-20 overflow-hidden">
      <div className="p-12 border-b flex justify-between items-center bg-white text-black font-black">
        <h3 className="text-2xl font-black uppercase tracking-widest">Contabilidad</h3>
        <div className="flex gap-4">
          <input type="file" ref={fileInputRef} onChange={handleImportCSV} accept=".csv" className="hidden" />
          <button onClick={() => fileInputRef.current?.click()} className="border-4 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all text-black"><Upload className="w-4 h-4" /> Importar CSV</button>
          <button onClick={() => { setShowForm(true); setEditingId(null); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest shadow-lg text-white font-black">+ Nuevo Registro</button>
        </div>
      </div>

      {showForm && !editingId && (
        <div className="p-12 bg-zinc-50 border-b animate-in slide-in-from-top-4 duration-300">
          <form onSubmit={handleSave} className="grid grid-cols-4 gap-6">
            <FormFields formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
            <div className="col-span-4 flex gap-4 pt-4">
              <button type="button" onClick={resetForm} className="flex-1 border-2 border-zinc-200 py-4 text-[11px] font-black uppercase text-zinc-400 font-black">Cancelar</button>
              <button type="submit" className="flex-[2] bg-black text-white py-4 text-[11px] font-black uppercase tracking-widest shadow-xl font-black">Guardar</button>
            </div>
          </form>
        </div>
      )}

      <table className="w-full text-left">
        <thead className="bg-zinc-50 border-b font-black text-[11px] uppercase tracking-widest text-zinc-500"><tr><th className="px-12 py-6">Fecha</th><th className="px-12 py-6">Detalle</th><th className="px-12 py-6">Categoría</th><th className="px-12 py-6 text-right">Monto</th><th className="px-12 py-6 text-right">Gestión</th></tr></thead>
        <tbody>
          {transactions.map(t => (
            <React.Fragment key={t.id}>
              {editingId === t.id ? (
                <tr className="bg-zinc-900 text-white animate-in fade-in duration-300">
                  <td colSpan={5} className="p-10">
                    <form onSubmit={handleSave} className="grid grid-cols-4 gap-6">
                      <div className="col-span-4 flex justify-between items-center mb-4">
                        <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Edición en Línea</span>
                        <div className="flex gap-4">
                          <button type="button" onClick={resetForm} className="text-zinc-500 hover:text-white uppercase text-[10px] font-black px-4 py-2 border border-zinc-700 font-black">Cerrar</button>
                          <button type="submit" className="bg-white text-black uppercase text-[10px] font-black px-6 py-2 shadow-lg font-black">Actualizar</button>
                        </div>
                      </div>
                      <FormFields inline formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
                    </form>
                  </td>
                </tr>
              ) : (
                <tr className="hover:bg-zinc-50 group transition-all border-b last:border-0">
                  <td className="px-12 py-8 text-[10px] font-black text-zinc-500 uppercase">{t.date}</td>
                  <td className="px-12 py-8 font-black text-black uppercase text-xs truncate max-w-[200px]">{t.description}</td>
                  <td className="px-12 py-8"><span className="text-[10px] font-black uppercase border-2 border-zinc-100 px-3 py-1 bg-white text-zinc-800">{t.category}</span></td>
                  <td className={`px-12 py-8 text-right font-black text-base ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-500'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
                  <td className="px-12 py-8 text-right space-x-6">
                    <button onClick={() => startEditing(t)} className="text-zinc-400 hover:text-black uppercase text-[10px] font-black font-black">Editar</button>
