/**
 * Función ultra-robusta para limpiar números con comas y puntos.
 * Maneja formatos como: 10,000 | 10.000 | 10,50 | 10.50 | 1.000.000,00 | 1,000,000.00
 */
const cleanNumber = (val: string | number): number => {
  if (val === undefined || val === null || val === '') return 0;
  if (typeof val === 'number') return val;

  // Eliminar espacios y símbolos de moneda, mantener solo dígitos, comas, puntos y signo menos
  let s = val.replace(/\s/g, '').replace(/[^\d,.-]/g, '');

  const hasComma = s.includes(',');
  const hasDot = s.includes('.');

  if (hasComma && hasDot) {
    // Si tiene ambos, el último es el separador decimal
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) {
      // Formato europeo: 1.000,00 -> 1000.00
      s = s.replace(/\./g, '').replace(',', '.');
    } else {
      // Formato americano: 1,000.00 -> 1000.00
      s = s.replace(/,/g, '');
    }
  } else if (hasComma) {
    // Solo tiene comas: 10,000 o 10,50
    const parts = s.split(',');
    if (parts.length > 2 || parts[1].length === 3) {
      // Caso 1,000,000 o 10,000 (miles)
      s = s.replace(/,/g, '');
    } else {
      // Caso 10,50 (decimal)
      s = s.replace(',', '.');
    }
  } else if (hasDot) {
    // Solo tiene puntos: 10.000 o 10.50
    const parts = s.split('.');
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3 && parseFloat(parts[0]) >= 1)) {
      // Caso 1.000.000 o 1.000 (miles) - El >=1 evita confundir 0.500 con 500
      s = s.replace(/\./g, '');
    }
    // Si es 10.50, parseFloat lo maneja nativamente
  }

  const result = parseFloat(s);
  return isNaN(result) ? 0 : result;
};

