const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP' as Currency, assignedStaff: [] as string[] });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const totalPrice = cleanNumber(formData.totalPrice);
    const paidAmount = cleanNumber(formData.paidAmount);
    const eventData = { ...formData, totalPrice, paidAmount, remainingAmount: totalPrice - paidAmount };

    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...eventData } : ev));
    } else {
      const newId = Date.now().toString();
      setEvents([...events, { ...eventData, id: newId, status: 'PENDING', completed: false }]);
      if (paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Fiesta', eventId: newId }, ...transactions]);
      }
    }
    setShowForm(false);
    setEditingId(null);
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end"><button onClick={() => setShowForm(!showForm)} className="bg-black text-white px-10 py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition-all shadow-xl font-black">{showForm ? 'Cerrar' : '+ Registrar Evento'}</button></div>
      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-12 border border-black grid grid-cols-3 gap-8 animate-in fade-in zoom-in-95 duration-300 shadow-2xl relative">
          <div className="col-span-3"><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Nombre del Evento</label><input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border border-zinc-200 font-bold outline-none focus:border-black text-lg text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border border-zinc-200 outline-none font-bold text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Precio Total</label><input required type="text" inputMode="decimal" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: e.target.value})} className="w-full p-4 border border-zinc-200 font-black outline-none text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-700 mb-2">Abono Inicial</label><input required type="text" inputMode="decimal" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: e.target.value})} className="w-full p-4 border border-zinc-200 font-black outline-none text-black" /></div>
          <button type="submit" className="col-span-3 bg-black text-white py-6 text-sm font-black uppercase tracking-widest shadow-xl font-black">Confirmar Fecha</button>
        </form>
      )}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        {events.filter(e => !e.completed).map(event => (
          <div key={event.id} className="bg-white p-12 border border-zinc-200 relative group hover:border-black transition-all shadow-sm">
            <h3 className="text-3xl font-black text-black tracking-tighter uppercase mb-6">{event.title}</h3>
            <div className="grid grid-cols-3 gap-8 py-8 border-y border-zinc-50">
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Total</div><div className="text-lg font-black text-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Pagado</div><div className="text-lg font-black text-green-700">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Pendiente</div><div className="text-lg font-black text-red-600">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>
            <div className="mt-8 flex justify-end gap-4"><button onClick={() => { setEditingId(event.id); setFormData({ ...event, totalPrice: String(event.totalPrice), paidAmount: String(event.paidAmount) }); setShowForm(true); }} className="p-2 border border-zinc-200 hover:bg-black hover:text-white transition-all text-black"><Pencil className="w-4 h-4" /></button></div>
          </div>
        ))}
      </div>
    </div>
  );
};

