const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({ 
    title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP' as Currency, assignedStaff: [] as string[] 
  });

  const [closingData, setClosingData] = useState({ fuel: '', toll: '', diet: '', other: '', otherDesc: '' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const totalPrice = cleanNumber(formData.totalPrice);
    const paidAmount = cleanNumber(formData.paidAmount);
    const eventData = { ...formData, totalPrice, paidAmount, remainingAmount: totalPrice - paidAmount };

    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...eventData } : ev));
    } else {
      const newId = Date.now().toString();
      setEvents([...events, { ...eventData, id: newId, status: 'PENDING', completed: false }]);
      if (paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Fiesta', eventId: newId }, ...transactions]);
      }
    }
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP', assignedStaff: [] });
  };

  const handleLiquidar = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;

    const date = new Date().toISOString().split('T')[0];
    const newTrans: Transaction[] = [];

    // 1. Cobrar lo restante
    if (closingEvent.remainingAmount > 0) {
      newTrans.push({
        id: `liq-in-${Date.now()}`, type: 'INCOME', amount: closingEvent.remainingAmount, 
        currency: closingEvent.currency, description: `Liquidación Final: ${closingEvent.title}`, 
        date, category: 'Fiesta', eventId: closingEvent.id
      });
    }

    // 2. Gastos operativos
    const exp = [
      { v: closingData.fuel, l: 'Combustible', c: 'Combustible' },
      { v: closingData.toll, l: 'Peaje', c: 'Taxi' },
      { v: closingData.diet, l: 'Dieta', c: 'Dieta' },
      { v: closingData.other, l: closingData.otherDesc || 'Gasto Extra', c: 'Otros' }
    ];
    exp.forEach(x => {
      const val = cleanNumber(x.v);
      if (val > 0) {
        newTrans.push({
          id: `liq-ex-${Date.now()}-${x.l}`, type: 'EXPENSE', amount: val, 
          currency: closingEvent.currency, description: `${x.l}: ${closingEvent.title}`, 
          date, category: x.c, eventId: closingEvent.id
        });
      }
    });

    // 3. Nómina (Pago a staff)
    closingEvent.assignedStaff.forEach(sid => {
      const s = staff.find(st => st.id === sid);
      if (s) {
        const pay = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTrans.push({
          id: `liq-nom-${Date.now()}-${s.id}`, type: 'EXPENSE', amount: pay, 
          currency: s.currency, description: `Nómina (${s.name}): ${closingEvent.title}`, 
          date, category: 'Nomina', eventId: closingEvent.id
        });
      }
    });

    setTransactions([...newTrans, ...transactions]);
    setEvents(events.map(ev => ev.id === closingEvent.id ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } : ev));
    setClosingEvent(null);
    setClosingData({ fuel: '', toll: '', diet: '', other: '', otherDesc: '' });
  };

  const toggleStaff = (id: string) => {
    setFormData(prev => ({
      ...prev,
      assignedStaff: prev.assignedStaff.includes(id) 
        ? prev.assignedStaff.filter(s => s !== id) 
        : [...prev.assignedStaff, id]
    }));
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-10 py-4 text-xs font-black uppercase tracking-widest shadow-xl font-black">
          {showForm ? 'Cerrar' : '+ Registrar Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-12 border border-black grid grid-cols-4 gap-8 animate-in fade-in zoom-in-95 duration-300 shadow-2xl">
          <div className="col-span-4 border-b border-zinc-100 pb-4"><h3 className="text-xl font-black uppercase tracking-widest">{editingId ? 'Editar Evento' : 'Nuevo Evento'}</h3></div>
          <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Nombre del Evento</label><input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold outline-none focus:border-black text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border-2 border-zinc-200 outline-none font-bold text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Hora</label><input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border-2 border-zinc-200 outline-none font-bold text-black" /></div>

          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-200 font-bold outline-none text-black"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Precio Total</label><input required type="text" inputMode="decimal" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Abono Inicial</label><input required type="text" inputMode="decimal" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none text-black" /></div>
          <div className="col-span-4">
            <label className="block text-[10px] font-black uppercase text-zinc-500 mb-4 tracking-widest">Asignar Personal para Nómina</label>
            <div className="grid grid-cols-4 gap-4">
              {staff.map(s => (
                <button type="button" key={s.id} onClick={() => toggleStaff(s.id)} className={`p-4 border-2 text-[10px] font-black uppercase transition-all flex items-center gap-3 ${formData.assignedStaff.includes(s.id) ? 'bg-black text-white border-black' : 'bg-white text-zinc-400 border-zinc-100 hover:border-black'}`}>
                  <Users className="w-3 h-3" /> {s.name} <span className="text-[8px] opacity-50">({s.role})</span>
                </button>
              ))}
            </div>
          </div>
          <button type="submit" className="col-span-4 bg-black text-white py-6 text-sm font-black uppercase tracking-widest shadow-xl font-black">Guardar Evento</button>
        </form>
      )}

      {closingEvent && (
