const cleanNumber = (val: string | number): number => {
  if (val === undefined || val === null || val === '') return 0;
  if (typeof val === 'number') return val;
  let s = val.replace(/\s/g, '').replace(/[^\d,.-]/g, '');
  const hasComma = s.includes(',');
  const hasDot = s.includes('.');
  if (hasComma && hasDot) {
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) s = s.replace(/\./g, '').replace(',', '.');
    else s = s.replace(/,/g, '');
  } else if (hasComma) {
    const parts = s.split(',');
    if (parts.length > 2 || parts[1].length === 3) s = s.replace(/,/g, '');
    else s = s.replace(',', '.');
  } else if (hasDot) {
    const parts = s.split('.');
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3 && parseFloat(parts[0]) >= 1)) s = s.replace(/\./g, '');
  }
  const result = parseFloat(s);
  return isNaN(result) ? 0 : result;
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'events' | 'personal' | 'accounting'>('dashboard');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('rf_staff_v4');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'DJ Shadow', role: 'DJ', paymentType: 'FIXED', paymentValue: 200, currency: 'USD' },
      { id: '2', name: 'Ana Manager', role: 'Manager', paymentType: 'PERCENTAGE', paymentValue: 10, currency: 'DOP' },
    ];
  });

  const [events, setEvents] = useState<Event[]>(() => {
    const saved = localStorage.getItem('rf_events_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('rf_transactions_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [categories, setCategories] = useState<string[]>(() => {
    const saved = localStorage.getItem('rf_categories_v4');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  useEffect(() => { localStorage.setItem('rf_staff_v4', JSON.stringify(staff)); }, [staff]);
  useEffect(() => { localStorage.setItem('rf_events_v4', JSON.stringify(events)); }, [events]);
  useEffect(() => { localStorage.setItem('rf_transactions_v4', JSON.stringify(transactions)); }, [transactions]);
  useEffect(() => { localStorage.setItem('rf_categories_v4', JSON.stringify(categories)); }, [categories]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      if (startDate && t.date < startDate) return false;
      if (endDate && t.date > endDate) return false;
      return true;
    });
  }, [transactions, startDate, endDate]);

  const totals = useMemo(() => {
    const calc = (curr: Currency) => {
      const income = filteredTransactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = filteredTransactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [filteredTransactions]);

  const [aiInsights, setAiInsights] = useState<string>('Haz clic para un análisis profundo...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(filteredTransactions, events);
    setAiInsights(insights || 'Error al analizar.');
    setIsAnalyzing(false);
  };

  return (
    <div className="flex h-screen bg-[#fafafa] font-sans selection:bg-black selection:text-white">
      <nav className="w-64 bg-black text-white flex flex-col shadow-2xl z-20">
        <div className="p-8 text-2xl font-black tracking-tighter border-b border-zinc-900">RF<span className="text-zinc-500">STUDIO</span></div>
        <div className="flex-1 mt-6 space-y-1 px-4">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal" active={activeTab === 'personal'} onClick={() => setActiveTab('personal')} />
          <NavItem icon={<Wallet />} label="Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
        </div>
        <div className="p-8 border-t border-zinc-900">
          <div className="text-[9px] font-black text-zinc-400 uppercase tracking-[0.2em]">Management System v4.9</div>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto p-10 bg-[#f8f8f8]">
        <header className="mb-8 flex justify-between items-end border-b border-zinc-200 pb-8">
          <div>
            <h1 className="text-4xl font-black text-black tracking-tight mb-2 uppercase">
              {activeTab === 'dashboard' && 'Panel de Control'}
              {activeTab === 'events' && 'Gestión de Agenda'}
              {activeTab === 'personal' && 'Equipo y Nómina'}
              {activeTab === 'accounting' && 'Caja y Transacciones'}
            </h1>
            <p className="text-zinc-500 font-bold tracking-tight text-sm uppercase">Sincronización Total de Operaciones.</p>
          </div>
          <div className="bg-white px-8 py-5 border-2 border-black shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] flex gap-10">
            <div><div className="text-[10px] uppercase font-black text-zinc-900 mb-2 tracking-widest">Caja DOP</div><div className={`text-xl font-black ${totals.DOP.balance >= 0 ? 'text-black' : 'text-red-600'}`}>RD$ {totals.DOP.balance.toLocaleString()}</div></div>
            <div className="border-l border-zinc-100 pl-10"><div><div className="text-[10px] uppercase font-black text-zinc-900 mb-2 tracking-widest">Caja USD</div><div className={`text-xl font-black ${totals.USD.balance >= 0 ? 'text-black' : 'text-red-600'}`}>$ {totals.USD.balance.toLocaleString()}</div></div></div>
          </div>
        </header>

        {(activeTab === 'dashboard' || activeTab === 'accounting') && (
          <div className="mb-10 flex items-center gap-6 bg-white p-5 border border-zinc-200 text-[10px] font-black uppercase tracking-widest shadow-sm">
            <Filter className="w-4 h-4 text-black" />
            <div className="flex items-center gap-4"><span>Desde</span><input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black bg-zinc-50 text-black" /></div>
            <div className="flex items-center gap-4"><span>Hasta</span><input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="border border-zinc-200 p-2 font-bold outline-none focus:border-black bg-zinc-50 text-black" /></div>
            {(startDate || endDate) && <button onClick={() => {setStartDate(''); setEndDate('');}} className="text-red-600 ml-auto font-black uppercase">Limpiar</button>}
          </div>
        )}

        {activeTab === 'dashboard' && <Dashboard transactions={filteredTransactions} totals={totals} events={events} staff={staff} aiInsights={aiInsights} handleAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />}
        {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
        {activeTab === 'personal' && <StaffManager staff={staff} setStaff={setStaff} />}
        {activeTab === 'accounting' && <AccountingManager transactions={filteredTransactions} setTransactions={setTransactions} categories={categories} setCategories={setCategories} />}
      </main>
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-6 py-4 transition-all duration-300 ${active ? 'bg-white text-black font-black' : 'text-zinc-500 hover:text-white hover:bg-zinc-900 group'}`}>
    {React.cloneElement(icon as React.ReactElement<{ className?: string }>, { className: `w-4 h-4 ${active ? 'text-black' : 'text-white'}` })}
    <span className={`text-[11px] font-bold uppercase tracking-[0.15em] ${active ? 'text-black' : 'text-zinc-400 group-hover:text-white'}`}>{label}</span>
  </button>
);

const Dashboard: React.FC<{ transactions: Transaction[], totals: any, events: Event[], staff: Staff[], aiInsights: string, handleAnalyze: () => void, isAnalyzing: boolean }> = ({ transactions, totals, events, staff, aiInsights, handleAnalyze, isAnalyzing }) => {
  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 pb-20">
      <div className="lg:col-span-4 grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard label="Ingresos Totales" usd={totals.USD.income} dop={totals.DOP.income} />
        <MetricCard label="Egresos Totales" usd={totals.USD.expense} dop={totals.DOP.expense} />
        <MetricCard label="Saldo Neto" usd={totals.USD.balance} dop={totals.DOP.balance} />
        <div className="bg-white p-6 border border-zinc-200 shadow-sm flex flex-col justify-between">
          <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-700 mb-4">Eventos Activos</div>
          <div className="text-4xl font-black text-black">{events.filter(e => !e.completed).length}</div>
        </div>
      </div>
      <div className="lg:col-span-1 space-y-8">
        <div className="bg-black p-8 text-white shadow-xl">
          <h3 className="text-sm font-black uppercase tracking-widest mb-6 flex items-center gap-2 text-white"><BrainCircuit className="w-5 h-5 text-white" /> Inteligencia RF</h3>
          <div className="text-[12px] leading-relaxed mb-8 border-l-2 border-white pl-4 text-white font-medium italic">{aiInsights}</div>
          <button onClick={handleAnalyze} disabled={isAnalyzing} className="w-full bg-white text-black py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-200 shadow-lg font-black">{isAnalyzing ? 'Procesando...' : 'Obtener Análisis'}</button>
        </div>
      </div>
    </div>
  );
};

const MetricCard: React.FC<{ label: string, usd: number, dop: number, highlightRed?: boolean }> = ({ label, usd, dop, highlightRed }) => (
  <div className="bg-white p-6 border border-zinc-200 shadow-sm">
    <div className="text-[10px] font-black uppercase tracking-tighter text-zinc-700 mb-4">{label}</div>
    <div className="space-y-2">
      <div className="flex justify-between items-end border-b border-zinc-50 pb-2"><span className="text-[10px] font-bold text-zinc-500 tracking-widest">USD</span><span className={`text-xl font-black ${highlightRed && usd > 0 ? 'text-red-600' : 'text-black'}`}>$ {usd.toLocaleString()}</span></div>
      <div className="flex justify-between items-end pt-1"><span className="text-[10px] font-bold text-zinc-500 tracking-widest">DOP</span><span className={`text-xl font-black ${highlightRed && dop > 0 ? 'text-red-600' : 'text-black'}`}>RD$ {dop.toLocaleString()}</span></div>
    </div>
  </div>
);

const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({ 
    title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP' as Currency, assignedStaff: [] as string[] 
  });

  const [closingData, setClosingData] = useState({ fuel: '', toll: '', diet: '', other: '', otherDesc: '' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const totalPrice = cleanNumber(formData.totalPrice);
    const paidAmount = cleanNumber(formData.paidAmount);
    const eventData = { ...formData, totalPrice, paidAmount, remainingAmount: totalPrice - paidAmount };

    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...eventData } : ev));
    } else {
      const newId = Date.now().toString();
      setEvents([...events, { ...eventData, id: newId, status: 'PENDING', completed: false }]);
      if (paidAmount > 0) {
        setTransactions([{ id: 't-' + Date.now(), type: 'INCOME', amount: paidAmount, currency: formData.currency, description: `Abono Inicial: ${formData.title}`, date: formData.date, category: 'Fiesta', eventId: newId }, ...transactions]);
      }
    }
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP', assignedStaff: [] });
  };

  const handleLiquidar = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;

    const date = new Date().toISOString().split('T')[0];
    const newTrans: Transaction[] = [];

    if (closingEvent.remainingAmount > 0) {
      newTrans.push({
        id: `liq-in-${Date.now()}`, type: 'INCOME', amount: closingEvent.remainingAmount, 
        currency: closingEvent.currency, description: `Liquidación Final: ${closingEvent.title}`, 
        date, category: 'Fiesta', eventId: closingEvent.id
      });
    }

    const exp = [
      { v: closingData.fuel, l: 'Combustible', c: 'Combustible' },
      { v: closingData.toll, l: 'Peaje', c: 'Taxi' },
      { v: closingData.diet, l: 'Dieta', c: 'Dieta' },
      { v: closingData.other, l: closingData.otherDesc || 'Gasto Extra', c: 'Otros' }
    ];
    exp.forEach(x => {
      const val = cleanNumber(x.v);
      if (val > 0) {
        newTrans.push({
          id: `liq-ex-${Date.now()}-${x.l}`, type: 'EXPENSE', amount: val, 
          currency: closingEvent.currency, description: `${x.l}: ${closingEvent.title}`, 
          date, category: x.c, eventId: closingEvent.id
        });
      }
    });

    closingEvent.assignedStaff.forEach(sid => {
      const s = staff.find(st => st.id === sid);
      if (s) {
        const pay = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTrans.push({
          id: `liq-nom-${Date.now()}-${s.id}`, type: 'EXPENSE', amount: pay, 
          currency: s.currency, description: `Nómina (${s.name}): ${closingEvent.title}`, 
          date, category: 'Nomina', eventId: closingEvent.id
        });
      }
    });

    setTransactions([...newTrans, ...transactions]);
    setEvents(events.map(ev => ev.id === closingEvent.id ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } : ev));
    setClosingEvent(null);
    setClosingData({ fuel: '', toll: '', diet: '', other: '', otherDesc: '' });
  };

  const toggleStaff = (id: string) => {
    setFormData(prev => ({
      ...prev,
      assignedStaff: prev.assignedStaff.includes(id) 
        ? prev.assignedStaff.filter(s => s !== id) 
        : [...prev.assignedStaff, id]
    }));
  };

  const selectAllStaff = () => {
    setFormData(prev => ({ ...prev, assignedStaff: staff.map(s => s.id) }));
  };

  const deselectAllStaff = () => {
    setFormData(prev => ({ ...prev, assignedStaff: [] }));
  };

  return (
    <div className="space-y-10">
      <div className="flex justify-end">
        <button onClick={() => { setShowForm(!showForm); setEditingId(null); }} className="bg-black text-white px-10 py-4 text-xs font-black uppercase tracking-widest shadow-xl font-black">
          {showForm ? 'Cerrar Formulario' : '+ Registrar Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-12 border border-black grid grid-cols-4 gap-8 animate-in fade-in zoom-in-95 duration-300 shadow-2xl">
          <div className="col-span-4 border-b border-zinc-100 pb-4 flex justify-between items-center">
            <h3 className="text-xl font-black uppercase tracking-widest">{editingId ? 'Editar Evento' : 'Nuevo Evento'}</h3>
            {editingId && <button type="button" onClick={() => setShowForm(false)} className="text-zinc-400 hover:text-black font-black uppercase text-[10px]">Cerrar</button>}
          </div>
          <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Nombre del Evento</label><input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold outline-none focus:border-black text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border-2 border-zinc-200 outline-none font-bold text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Hora</label><input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border-2 border-zinc-200 outline-none font-bold text-black" /></div>

          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-200 font-bold outline-none text-black"><option value="DOP">DOP</option><option value="USD">USD</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Precio Total</label><input required type="text" inputMode="decimal" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none text-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Abono Inicial</label><input required type="text" inputMode="decimal" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none text-black" /></div>
          <div className="col-span-4">
            <div className="flex justify-between items-center mb-4">
              <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Asignar Personal para Nómina</label>
              <div className="flex gap-4">
                <button type="button" onClick={selectAllStaff} className="flex items-center gap-1 text-[9px] font-black uppercase text-zinc-400 hover:text-black transition-colors"><CheckSquare className="w-3 h-3" /> Seleccionar Todo</button>
                <button type="button" onClick={deselectAllStaff} className="flex items-center gap-1 text-[9px] font-black uppercase text-zinc-400 hover:text-black transition-colors"><Square className="w-3 h-3" /> Desmarcar Todo</button>
              </div>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {staff.map(s => (
                <button type="button" key={s.id} onClick={() => toggleStaff(s.id)} className={`p-4 border-2 text-[10px] font-black uppercase transition-all flex items-center justify-between gap-3 ${formData.assignedStaff.includes(s.id) ? 'bg-black text-white border-black' : 'bg-white text-zinc-400 border-zinc-100 hover:border-black'}`}>
                  <div className="flex items-center gap-2">
                    <Users className={`w-3 h-3 ${formData.assignedStaff.includes(s.id) ? 'text-white' : 'text-zinc-300'}`} /> 
                    <span>{s.name} <span className="text-[8px] opacity-60 block">{s.role}</span></span>
                  </div>
                  {formData.assignedStaff.includes(s.id) ? <CheckSquare className="w-4 h-4" /> : <Square className="w-4 h-4" />}
                </button>
              ))}
            </div>
          </div>
          <button type="submit" className="col-span-4 bg-black text-white py-6 text-sm font-black uppercase tracking-widest shadow-xl font-black">Confirmar Datos del Evento</button>
        </form>
      )}

      {closingEvent && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-6">
          <form onSubmit={handleLiquidar} className="bg-white p-12 max-w-2xl w-full border-4 border-black animate-in zoom-in-95 duration-200 shadow-[20px_20px_0px_0px_rgba(0,0,0,1)]">
            <h3 className="text-3xl font-black uppercase tracking-tighter mb-8">Liquidar: {closingEvent.title}</h3>
            <div className="bg-zinc-50 p-6 border-l-8 border-black mb-10">
              <div className="flex justify-between items-center mb-2">
                <span className="text-[10px] font-black uppercase text-zinc-500">Saldo Pendiente a Cobrar</span>
                <span className="text-xl font-black text-green-700">{closingEvent.currency} {closingEvent.remainingAmount.toLocaleString()}</span>
              </div>
              <p className="text-[9px] font-bold text-zinc-400 uppercase italic">El sistema generará los pagos automáticos para {closingEvent.assignedStaff.length} colaboradores.</p>
            </div>
            <div className="grid grid-cols-2 gap-8 mb-10">
              <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Combustible</label><input type="text" inputMode="decimal" value={closingData.fuel} onChange={e => setClosingData({...closingData, fuel: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none focus:border-black" /></div>
              <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Peajes</label><input type="text" inputMode="decimal" value={closingData.toll} onChange={e => setClosingData({...closingData, toll: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none focus:border-black" /></div>
              <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Dietas</label><input type="text" inputMode="decimal" value={closingData.diet} onChange={e => setClosingData({...closingData, diet: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none focus:border-black" /></div>
              <div><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Gasto Extra</label><input type="text" inputMode="decimal" value={closingData.other} onChange={e => setClosingData({...closingData, other: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-black outline-none focus:border-black" /></div>
              <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Motivo Gasto Extra</label><input type="text" value={closingData.otherDesc} onChange={e => setClosingData({...closingData, otherDesc: e.target.value})} className="w-full p-4 border-2 border-zinc-200 font-bold outline-none focus:border-black" /></div>
            </div>
            <div className="flex gap-4">
              <button type="button" onClick={() => setClosingEvent(null)} className="flex-1 py-5 border-2 border-zinc-200 font-black uppercase text-[11px] text-zinc-400 hover:bg-zinc-50 transition-colors">Cancelar</button>
              <button type="submit" className="flex-1 py-5 bg-black text-white font-black uppercase text-[11px] tracking-widest shadow-xl hover:bg-zinc-900 transition-all">Liquidar y Pagar Staff</button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        {events.filter(e => !e.completed).map(event => (
          <div key={event.id} className="bg-white p-12 border border-zinc-200 relative group hover:border-black transition-all shadow-sm">
            <div className="flex justify-between items-start mb-6">
              <h3 className="text-3xl font-black text-black tracking-tighter uppercase">{event.title}</h3>
              <div className="flex items-center gap-2 text-[10px] font-black uppercase bg-zinc-50 px-3 py-1 border border-zinc-100"><Clock className="w-3 h-3 text-black" /> {event.time || '--:--'}</div>
            </div>
            <div className="flex items-center gap-2 text-[10px] font-black uppercase text-zinc-400 mb-8 tracking-widest border-b border-zinc-50 pb-4">
              <Calendar className="w-3 h-3" /> {event.date}
            </div>

            <div className="grid grid-cols-3 gap-8 mb-8">
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Pactado</div><div className="text-lg font-black text-black">{event.currency} {event.totalPrice.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Abonado</div><div className="text-lg font-black text-green-700">{event.currency} {event.paidAmount.toLocaleString()}</div></div>
               <div><div className="text-[10px] font-black uppercase text-zinc-500 mb-2">Resta</div><div className="text-lg font-black text-red-600">{event.currency} {event.remainingAmount.toLocaleString()}</div></div>
            </div>

            <div className="mb-8">
              <div className="text-[9px] font-black uppercase text-zinc-400 mb-3 tracking-widest flex items-center gap-2"><Briefcase className="w-3 h-3 text-zinc-300" /> Nómina Seleccionada</div>
              <div className="flex flex-wrap gap-2">
