          <button onClick={() => {setShowExchange(!showExchange); setShowForm(false);}} className="border-4 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all text-black font-black"><RefreshCcw className="w-4 h-4" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(true); setEditingId(null); setShowExchange(false); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest shadow-lg text-white font-black hover:bg-zinc-900 transition-all">+ Registro Manual</button>
        </div>
      </div>
      {showExchange && (
        <form onSubmit={handleExchange} className="p-12 bg-zinc-900 text-white grid grid-cols-3 gap-10 animate-in slide-in-from-top-10 duration-500">
           <div className="col-span-3 flex justify-between items-center border-b border-zinc-800 pb-4"><h4 className="text-[12px] font-black uppercase tracking-[0.3em] flex items-center gap-3 text-white">Módulo de Intercambio (Venta USD -> DOP)</h4><button type="button" onClick={() => setShowExchange(false)} className="text-zinc-500 hover:text-white uppercase text-[10px] font-black">Cerrar</button></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest text-white">Venta USD</label><input required type="text" inputMode="decimal" value={usdToExchange} onChange={e => setUsdToExchange(e.target.value)} className="w-full bg-zinc-800 border-zinc-700 p-5 font-black text-white outline-none focus:border-white transition-all text-xl" /></div>
