           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-6 text-[12px] font-black uppercase tracking-widest hover:bg-zinc-200 shadow-2xl transition-all text-black font-black">Ejecutar Asiento de Cambio</button></div>
        </form>
      )}
      {showForm && !editingId && (
        <div className="p-12 bg-zinc-50 border-b animate-in slide-in-from-top-4 duration-300">
          <form onSubmit={handleSave} className="grid grid-cols-4 gap-6">
