                    <td className={`px-12 py-8 text-right font-black text-base ${t.type === 'INCOME' ? 'text-green-800' : 'text-zinc-600'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
