];

// Función para limpiar números que permite comas y puntos decimales
const cleanNumber = (val: string | number): number => {
  if (val === undefined || val === null || val === '') return 0;
  if (typeof val === 'number') return val;
  let s = val.replace(/\s/g, '').replace(/[^\d,.-]/g, '');
  const hasComma = s.includes(',');
  const hasDot = s.includes('.');
  if (hasComma && hasDot) {
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) s = s.replace(/\./g, '').replace(',', '.');
    else s = s.replace(/,/g, '');
  } else if (hasComma) {
    const parts = s.split(',');
    if (parts.length > 2 || parts[1].length === 3) s = s.replace(/,/g, '');
    else s = s.replace(',', '.');
  } else if (hasDot) {
    const parts = s.split('.');
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3 && parseFloat(parts[0]) >= 1)) s = s.replace(/\./g, '');
  }
  const result = parseFloat(s);
  return isNaN(result) ? 0 : result;
};

// --- COMPONENTE PRINCIPAL ---
const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'events' | 'personal' | 'accounting'>('dashboard');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  // Estados con Persistencia
  const [staff, setStaff] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('rf_staff_v5');
    return saved ? JSON.parse(saved) : [];
  });

  const [events, setEvents] = useState<Event[]>(() => {
    const saved = localStorage.getItem('rf_events_v5');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('rf_transactions_v5');
    return saved ? JSON.parse(saved) : [];
  });

  const [categories, setCategories] = useState<string[]>(() => {
    const saved = localStorage.getItem('rf_categories_v5');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  useEffect(() => localStorage.setItem('rf_staff_v5', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('rf_events_v5', JSON.stringify(events)), [events]);
  useEffect(() => localStorage.setItem('rf_transactions_v5', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('rf_categories_v5', JSON.stringify(categories)), [categories]);

  // Cálculos de Dashboard
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      if (startDate && t.date < startDate) return false;
      if (endDate && t.date > endDate) return false;
      return true;
    }).sort((a, b) => b.date.localeCompare(a.date));
  }, [transactions, startDate, endDate]);

  const totals = useMemo(() => {
    const calc = (curr: Currency) => {
      const income = filteredTransactions.filter(t => t.type === 'INCOME' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      const expense = filteredTransactions.filter(t => t.type === 'EXPENSE' && t.currency === curr).reduce((acc, c) => acc + c.amount, 0);
      return { income, expense, balance: income - expense };
    };
    return { USD: calc('USD'), DOP: calc('DOP') };
  }, [filteredTransactions]);

  const [aiInsights, setAiInsights] = useState<string>('Esperando análisis...');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const insights = await getFinancialInsights(filteredTransactions, events);
    setAiInsights(insights || 'Error al conectar con la IA.');
    setIsAnalyzing(false);
  };

  return (
    <div className="flex h-screen bg-[#fafafa] font-sans selection:bg-black selection:text-white overflow-hidden">
      {/* Sidebar Navigation */}
      <nav className="w-64 bg-black text-white flex flex-col shadow-2xl z-30">
        <div className="p-8 text-2xl font-black tracking-tighter border-b border-zinc-900">
          RF<span className="text-zinc-500">STUDIO</span>
        </div>
        <div className="flex-1 mt-6 space-y-1 px-4">
          <NavItem icon={<LayoutDashboard />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<Calendar />} label="Agenda de Eventos" active={activeTab === 'events'} onClick={() => setActiveTab('events')} />
          <NavItem icon={<Users />} label="Personal & Nómina" active={activeTab === 'personal'} onClick={() => setActiveTab('personal')} />
          <NavItem icon={<Wallet />} label="Caja & Contabilidad" active={activeTab === 'accounting'} onClick={() => setActiveTab('accounting')} />
        </div>
        <div className="p-8 border-t border-zinc-900">
          <div className="text-[9px] font-black text-zinc-500 uppercase tracking-[0.2em]">Studio Ops v5.0 Final</div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto bg-[#f8f8f8]">
        <div className="max-w-7xl mx-auto p-10">
          <header className="mb-12 flex justify-between items-end border-b border-zinc-200 pb-10">
            <div>
              <h1 className="text-5xl font-black text-black tracking-tighter mb-2 uppercase">
                {activeTab === 'dashboard' && 'Control Central'}
                {activeTab === 'events' && 'Agenda Maestra'}
                {activeTab === 'personal' && 'Staff & Estructura'}
                {activeTab === 'accounting' && 'Flujo de Caja'}
              </h1>
              <div className="flex items-center gap-2 text-zinc-400 font-bold uppercase text-xs tracking-widest">
                <ChevronRight className="w-4 h-4 text-black" /> 
                {activeTab === 'dashboard' ? 'Métricas de rendimiento en tiempo real' : 'Gestión administrativa profesional'}
              </div>
            </div>

            <div className="flex gap-6">
              <BalanceDisplay label="Caja DOP" amount={totals.DOP.balance} currency="RD$" />
              <BalanceDisplay label="Caja USD" amount={totals.USD.balance} currency="$" />
            </div>
          </header>

          {/* Global Filter Bar */}
          {(activeTab === 'dashboard' || activeTab === 'accounting') && (
            <div className="mb-10 flex items-center gap-8 bg-white p-6 border border-zinc-200 shadow-sm rounded-none">
              <div className="flex items-center gap-3 text-black">
                <Filter className="w-5 h-5" />
                <span className="text-[11px] font-black uppercase tracking-widest">Auditoría Temporal:</span>
              </div>
              <div className="flex items-center gap-4">
                <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="border-2 border-zinc-100 p-3 font-bold outline-none focus:border-black bg-zinc-50 text-xs" />
                <span className="text-zinc-300 font-black">/</span>
                <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="border-2 border-zinc-100 p-3 font-bold outline-none focus:border-black bg-zinc-50 text-xs" />
              </div>
              {(startDate || endDate) && (
                <button onClick={() => {setStartDate(''); setEndDate('');}} className="ml-auto text-red-600 font-black uppercase text-[10px] hover:underline">Reiniciar Filtros</button>
              )}
            </div>
          )}

          {/* Module Router */}
          <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
            {activeTab === 'dashboard' && <Dashboard totals={totals} events={events} aiInsights={aiInsights} handleAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />}
            {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
            {activeTab === 'personal' && <StaffManager staff={staff} setStaff={setStaff} />}
            {activeTab === 'accounting' && <AccountingManager transactions={filteredTransactions} setTransactions={setTransactions} categories={categories} setCategories={setCategories} />}
          </div>
        </div>
      </main>
    </div>
  );
};

