const AccountingManager: React.FC<{ transactions: Transaction[], setTransactions: any, categories: string[], setCategories: (cats: string[]) => void }> = ({ transactions, setTransactions, categories, setCategories }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showExchange, setShowExchange] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<string>('');
  const [usdToExchange, setUsdToExchange] = useState<string>('');
  const [showNewCategoryInput, setShowNewCategoryInput] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [formData, setFormData] = useState({ 
    type: 'INCOME', amount: '', currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' 
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    let finalCategory = formData.category;
    if (showNewCategoryInput && newCategoryName.trim()) {
      finalCategory = newCategoryName.trim();
      if (!categories.includes(finalCategory)) setCategories([...categories, finalCategory]);
    }
    const finalAmount = cleanNumber(formData.amount);
    const data = { ...formData, category: finalCategory, amount: finalAmount };
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...data, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...data, id: Date.now().toString() }, ...prev]);
    resetForm();
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    const usdAmount = cleanNumber(usdToExchange);
    const rate = cleanNumber(exchangeRate);
    if (usdAmount <= 0 || rate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdAmount, currency: 'USD', description: `Venta Divisa USD @ ${rate}`, date, category: 'Divisas' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdAmount * rate, currency: 'DOP', description: `Compra Divisa DOP @ ${rate}`, date, category: 'Divisas' };
    setTransactions((prev: Transaction[]) => [usdOut, dopIn, ...prev]);
    setShowExchange(false); setUsdToExchange(''); setExchangeRate('');
  };

  const resetForm = () => {
    setShowForm(false); setEditingId(null); setShowNewCategoryInput(false); setNewCategoryName('');
    setFormData({ type: 'INCOME', amount: '', currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' });
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const rows = (event.target?.result as string).split(/\r?\n/);
      const newTransactions: Transaction[] = [];
      const newCats = new Set(categories);
      rows.forEach((row, index) => {
        if (index === 0 && row.toLowerCase().includes('fecha')) return;
        if (!row.trim()) return;
        const col = row.split(';').map(c => c.trim().replace(/^"|"$/g, ''));
        if (col.length >= 5) {
          const finalAmount = cleanNumber(col[3]);
          const type: 'INCOME' | 'EXPENSE' = col[4].toLowerCase().includes('ingreso') ? 'INCOME' : 'EXPENSE';
          newTransactions.push({ id: `i-${Date.now()}-${index}`, date: col[0], category: col[1] || 'General', description: col[2], amount: Math.abs(finalAmount), type, currency: (col[6]?.toUpperCase() === 'USD' ? 'USD' : 'DOP') as Currency });
          if (col[1]) newCats.add(col[1]);
        }
      });
      setTransactions((prev: Transaction[]) => [...newTransactions, ...prev]);
      setCategories(Array.from(newCats));
      alert(`Importación finalizada.`);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="bg-white border border-zinc-200 shadow-xl pb-20 overflow-hidden">
      <div className="p-12 border-b flex justify-between items-center bg-white font-black">
        <h3 className="text-2xl font-black uppercase tracking-widest">Flujo Contable</h3>
        <div className="flex gap-4">
          <input type="file" ref={fileInputRef} onChange={handleImportCSV} accept=".csv" className="hidden" />
          <button onClick={() => fileInputRef.current?.click()} className="border-2 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all"><Upload className="w-4 h-4" /> Importar CSV</button>
          <button onClick={() => {setShowExchange(!showExchange); setShowForm(false);}} className="border-2 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all"><RefreshCcw className="w-4 h-4" /> Cambio Divisas</button>
          <button onClick={() => { setShowForm(true); setEditingId(null); setShowExchange(false); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest shadow-xl hover:scale-105 transition-all">+ Registro Manual</button>
        </div>
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-12 bg-zinc-900 text-white grid grid-cols-3 gap-10 animate-in slide-in-from-top-10">
           <div className="col-span-3 flex justify-between items-center border-b border-zinc-800 pb-4"><h4 className="text-[11px] font-black uppercase tracking-[0.3em] flex items-center gap-3">Operación de Cambio (USD -> DOP)</h4><button type="button" onClick={() => setShowExchange(false)} className="text-zinc-500 hover:text-white uppercase text-[9px] font-black">Cerrar</button></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">USD a Vender</label><input required type="text" inputMode="decimal" value={usdToExchange} onChange={e => setUsdToExchange(e.target.value)} className="w-full bg-zinc-800 border-none p-5 font-black text-white outline-none focus:ring-2 ring-white transition-all text-xl" /></div>
           <div><label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Tasa de Cambio</label><input required type="text" inputMode="decimal" value={exchangeRate} onChange={e => setExchangeRate(e.target.value)} className="w-full bg-zinc-800 border-none p-5 font-black text-white outline-none focus:ring-2 ring-white transition-all text-xl" /></div>
           <div className="flex items-end"><button type="submit" className="w-full bg-white text-black py-6 text-[11px] font-black uppercase tracking-widest hover:bg-zinc-200 shadow-2xl transition-all">Ejecutar Cambio</button></div>
        </form>
      )}

      {showForm && !editingId && (
        <div className="p-12 bg-zinc-50 border-b animate-in slide-in-from-top-4">
          <form onSubmit={handleSave} className="grid grid-cols-4 gap-6">
            <FormFields formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
            <div className="col-span-4 flex gap-4 pt-4"><button type="button" onClick={resetForm} className="flex-1 border-2 border-zinc-200 py-4 text-[11px] font-black uppercase text-zinc-400">Cancelar</button><button type="submit" className="flex-[2] bg-black text-white py-4 text-[11px] font-black uppercase tracking-widest shadow-xl">Guardar Asiento</button></div>
          </form>
        </div>
      )}

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-zinc-50 border-b font-black text-[11px] uppercase tracking-widest text-zinc-400"><tr><th className="px-12 py-6">Fecha</th><th className="px-12 py-6">Concepto</th><th className="px-12 py-6">Categoría</th><th className="px-12 py-6 text-right">Impacto Caja</th><th className="px-12 py-6 text-right">Gestión</th></tr></thead>
          <tbody>
            {transactions.map(t => (
              <React.Fragment key={t.id}>
                {editingId === t.id ? (
                  <tr className="bg-zinc-900 text-white animate-in fade-in duration-300"><td colSpan={5} className="p-10"><form onSubmit={handleSave} className="grid grid-cols-4 gap-6"><div className="col-span-4 flex justify-between items-center mb-4"><span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Editor de Asiento Contable</span><div className="flex gap-4"><button type="button" onClick={resetForm} className="text-zinc-500 hover:text-white uppercase text-[10px] font-black px-4 py-2 border border-zinc-700">Cancelar</button><button type="submit" className="bg-white text-black uppercase text-[10px] font-black px-6 py-2 shadow-lg">Actualizar</button></div></div><FormFields inline formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} /></form></td></tr>
                ) : (
                  <tr className="hover:bg-zinc-50 group transition-all border-b last:border-0">
                    <td className="px-12 py-8 text-[10px] font-black text-zinc-400 uppercase">{t.date}</td>
                    <td className="px-12 py-8 font-black text-black uppercase text-xs truncate max-w-[250px]">{t.description}</td>
                    <td className="px-12 py-8"><span className="text-[9px] font-black uppercase border border-zinc-200 px-3 py-1 bg-white text-zinc-500">{t.category}</span></td>
                    <td className={`px-12 py-8 text-right font-black text-base ${t.type === 'INCOME' ? 'text-green-800' : 'text-zinc-600'}`}>{t.type === 'INCOME' ? '+' : '-'}{t.currency} {t.amount.toLocaleString()}</td>
                    <td className="px-12 py-8 text-right space-x-6 opacity-0 group-hover:opacity-100 transition-all"><button onClick={() => { setEditingId(t.id); setFormData({ ...t, amount: String(t.amount) }); setShowForm(false); setShowExchange(false); }} className="text-zinc-400 hover:text-black uppercase text-[10px] font-black">Editar</button><button onClick={() => setTransactions((prev: Transaction[]) => prev.filter(tr => tr.id !== t.id))} className="text-zinc-200 hover:text-red-500 uppercase text-[10px] font-black">Borrar</button></td>
                  </tr>
                )}
              </React.Fragment>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

