              </div>
              {(startDate || endDate) && (
                <button onClick={() => {setStartDate(''); setEndDate('');}} className="ml-auto text-red-600 font-black uppercase text-[10px] hover:underline">Reiniciar Filtros</button>
              )}
            </div>
          )}

          <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
            {activeTab === 'dashboard' && <Dashboard totals={totals} events={events} aiInsights={aiInsights} handleAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />}
            {activeTab === 'events' && <EventsManager events={events} setEvents={setEvents} staff={staff} transactions={transactions} setTransactions={setTransactions} />}
            {activeTab === 'personal' && <StaffManager staff={staff} setStaff={setStaff} />}
            {activeTab === 'accounting' && <AccountingManager transactions={filteredTransactions} setTransactions={setTransactions} categories={categories} setCategories={setCategories} />}
          </div>
        </div>
      </main>
    </div>
  );
};

