const cleanNumber = (val: string | number): number => {
  if (val === undefined || val === null || val === '') return 0;
  if (typeof val === 'number') return val;
  let s = val.replace(/\s/g, '').replace(/[^\d,.-]/g, '');
  const hasComma = s.includes(',');
  const hasDot = s.includes('.');
  if (hasComma && hasDot) {
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) s = s.replace(/\./g, '').replace(',', '.');
    else s = s.replace(/,/g, '');
  } else if (hasComma) {
    const parts = s.split(',');
    if (parts.length > 2 || parts[1].length === 3) s = s.replace(/,/g, '');
    else s = s.replace(',', '.');
  } else if (hasDot) {
    const parts = s.split('.');
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3 && parseFloat(parts[0]) >= 1)) s = s.replace(/\./g, '');
  }
  const result = parseFloat(s);
  return isNaN(result) ? 0 : result;
};

