// --- MODULO: EVENTOS ---
const EventsManager: React.FC<{ events: Event[], setEvents: any, staff: Staff[], transactions: Transaction[], setTransactions: any }> = ({ events, setEvents, staff, transactions, setTransactions }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [closingEvent, setClosingEvent] = useState<Event | null>(null);

  const [formData, setFormData] = useState({ 
    title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP' as Currency, assignedStaff: [] as string[] 
  });

  const [closingData, setClosingData] = useState({ fuel: '', toll: '', diet: '', other: '', otherDesc: '' });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const totalPrice = cleanNumber(formData.totalPrice);
    const paidAmount = cleanNumber(formData.paidAmount);
    const eventData = { ...formData, totalPrice, paidAmount, remainingAmount: totalPrice - paidAmount };

    if (editingId) {
      setEvents(events.map(ev => ev.id === editingId ? { ...ev, ...eventData } : ev));
    } else {
      const newId = Date.now().toString();
      setEvents([...events, { ...eventData, id: newId, status: 'PENDING', completed: false }]);
      if (paidAmount > 0) {
        setTransactions([{ 
          id: 't-' + Date.now(), 
          type: 'INCOME', 
          amount: paidAmount, 
          currency: formData.currency, 
          description: `Abono Inicial: ${formData.title}`, 
          date: formData.date, 
          category: 'Fiesta', 
          eventId: newId 
        }, ...transactions]);
      }
    }
    resetForm();
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', date: '', time: '', totalPrice: '', paidAmount: '', currency: 'DOP', assignedStaff: [] });
  };

  const handleLiquidar = (e: React.FormEvent) => {
    e.preventDefault();
    if (!closingEvent) return;
    const date = new Date().toISOString().split('T')[0];
    const newTrans: Transaction[] = [];

    if (closingEvent.remainingAmount > 0) {
      newTrans.push({
        id: `liq-in-${Date.now()}`, type: 'INCOME', amount: closingEvent.remainingAmount, 
        currency: closingEvent.currency, description: `Saldo Final: ${closingEvent.title}`, 
        date, category: 'Fiesta', eventId: closingEvent.id
      });
    }

    const expenses = [
      { val: cleanNumber(closingData.fuel), label: 'Combustible', cat: 'Combustible' },
      { val: cleanNumber(closingData.toll), label: 'Peaje/Taxi', cat: 'Taxi' },
      { val: cleanNumber(closingData.diet), label: 'Dieta', cat: 'Dieta' },
      { val: cleanNumber(closingData.other), label: closingData.otherDesc || 'Extra', cat: 'Otros' }
    ];
    expenses.forEach(ex => {
      if (ex.val > 0) {
        newTrans.push({
          id: `liq-ex-${Date.now()}-${ex.label}`, type: 'EXPENSE', amount: ex.val, 
          currency: closingEvent.currency, description: `${ex.label}: ${closingEvent.title}`, 
          date, category: ex.cat, eventId: closingEvent.id
        });
      }
    });

    closingEvent.assignedStaff.forEach(sid => {
      const s = staff.find(st => st.id === sid);
      if (s) {
        const payValue = s.paymentType === 'FIXED' ? s.paymentValue : (closingEvent.totalPrice * (s.paymentValue / 100));
        newTrans.push({
          id: `liq-nom-${Date.now()}-${s.id}`, type: 'EXPENSE', amount: payValue, 
          currency: s.currency, description: `Pago ${s.name}: ${closingEvent.title}`, 
          date, category: 'Nomina', eventId: closingEvent.id
        });
      }
    });

    setTransactions([...newTrans, ...transactions]);
    setEvents(events.map(ev => ev.id === closingEvent.id ? { ...ev, completed: true, status: 'PAID', paidAmount: ev.totalPrice, remainingAmount: 0 } : ev));
    setClosingEvent(null);
    setClosingData({ fuel: '', toll: '', diet: '', other: '', otherDesc: '' });
  };

  const toggleStaff = (id: string) => {
    setFormData(prev => ({
      ...prev,
      assignedStaff: prev.assignedStaff.includes(id) 
        ? prev.assignedStaff.filter(s => s !== id) 
        : [...prev.assignedStaff, id]
    }));
  };

  return (
    <div className="space-y-12">
      <div className="flex justify-end">
        <button onClick={() => {setShowForm(!showForm); setEditingId(null);}} className="bg-black text-white px-12 py-5 text-xs font-black uppercase tracking-widest shadow-2xl hover:scale-105 transition-all">
          {showForm ? 'Cerrar Registro' : '+ Agendar Nuevo Evento'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSave} className="bg-white p-12 border-2 border-black shadow-[15px_15px_0px_0px_rgba(0,0,0,1)] grid grid-cols-4 gap-8 animate-in zoom-in-95">
          <div className="col-span-4 border-b border-zinc-100 pb-4 mb-4"><h3 className="text-xl font-black uppercase tracking-widest">Configuración de Evento</h3></div>
          <div className="col-span-2"><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Nombre/Cliente</label><input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 border-2 border-zinc-100 font-bold focus:border-black outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Fecha</label><input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 border-2 border-zinc-100 font-bold focus:border-black outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Hora</label><input required type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full p-4 border-2 border-zinc-100 font-bold focus:border-black outline-none" /></div>

          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Moneda</label><select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className="w-full p-4 border-2 border-zinc-100 font-black outline-none"><option value="DOP">DOP (Pesos)</option><option value="USD">USD (Dólares)</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Monto Contrato</label><input required type="text" inputMode="decimal" value={formData.totalPrice} onChange={e => setFormData({...formData, totalPrice: e.target.value})} className="w-full p-4 border-2 border-zinc-100 font-black outline-none focus:border-black" /></div>
          <div><label className="block text-[10px] font-black uppercase text-zinc-400 mb-2">Abono Realizado</label><input required type="text" inputMode="decimal" value={formData.paidAmount} onChange={e => setFormData({...formData, paidAmount: e.target.value})} className="w-full p-4 border-2 border-zinc-100 font-black outline-none focus:border-black" /></div>

          <div className="col-span-4 mt-4">
            <div className="flex justify-between items-center mb-4">
              <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Asignación de Staff & Nómina</label>
              <div className="flex gap-4">
                <button type="button" onClick={() => setFormData({...formData, assignedStaff: staff.map(s => s.id)})} className="text-[9px] font-black uppercase text-zinc-400 hover:text-black">Seleccionar Todo</button>
                <button type="button" onClick={() => setFormData({...formData, assignedStaff: []})} className="text-[9px] font-black uppercase text-zinc-400 hover:text-black">Limpiar</button>
              </div>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {staff.map(s => (
                <button type="button" key={s.id} onClick={() => toggleStaff(s.id)} className={`p-4 border-2 text-[10px] font-black uppercase flex items-center justify-between transition-all ${formData.assignedStaff.includes(s.id) ? 'bg-black text-white border-black' : 'bg-white text-zinc-300 border-zinc-100 hover:border-black'}`}>
                  <span>{s.name} <span className="opacity-50 block text-[8px]">{s.role}</span></span>
                  {formData.assignedStaff.includes(s.id) ? <CheckSquare className="w-4 h-4" /> : <Square className="w-4 h-4 text-zinc-100" />}
                </button>
              ))}
            </div>
          </div>
          <button type="submit" className="col-span-4 bg-black text-white py-6 font-black uppercase tracking-widest hover:bg-zinc-900 shadow-xl transition-all">Guardar Evento en Agenda</button>
        </form>
      )}

      {closingEvent && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-6">
          <form onSubmit={handleLiquidar} className="bg-white p-12 max-w-2xl w-full border-4 border-black animate-in zoom-in-95 shadow-[30px_30px_0px_0px_rgba(0,0,0,0.2)]">
            <h3 className="text-4xl font-black uppercase tracking-tighter mb-8 italic">Liquidar Evento</h3>
            <div className="bg-zinc-50 p-6 border-l-8 border-black mb-10">
              <div className="flex justify-between items-center mb-1">
                <span className="text-[10px] font-black uppercase text-zinc-400">Balance por Cobrar</span>
                <span className="text-2xl font-black text-green-700">{closingEvent.currency} {closingEvent.remainingAmount.toLocaleString()}</span>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-8 mb-10">
              <ExpenseInput label="Combustible" value={closingData.fuel} setter={(v) => setClosingData({...closingData, fuel: v})} />
              <ExpenseInput label="Peajes/Taxi" value={closingData.toll} setter={(v) => setClosingData({...closingData, toll: v})} />
              <ExpenseInput label="Dieta Staff" value={closingData.diet} setter={(v) => setClosingData({...closingData, diet: v})} />
              <ExpenseInput label="Otros Gastos" value={closingData.other} setter={(v) => setClosingData({...closingData, other: v})} />
              <div className="col-span-2">
                <label className="block text-[10px] font-black uppercase text-zinc-500 mb-2">Concepto Extra</label>
                <input type="text" value={closingData.otherDesc} onChange={e => setClosingData({...closingData, otherDesc: e.target.value})} className="w-full p-4 border-2 border-zinc-100 font-bold focus:border-black outline-none" />
              </div>
            </div>
            <div className="flex gap-4">
              <button type="button" onClick={() => setClosingEvent(null)} className="flex-1 py-5 border-2 border-zinc-100 font-black uppercase text-[11px] text-zinc-400">Volver</button>
              <button type="submit" className="flex-1 py-5 bg-black text-white font-black uppercase text-[11px] tracking-widest shadow-xl">Cerrar & Pagar Staff</button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        {events.filter(e => !e.completed).map(event => (
          <div key={event.id} className="bg-white p-10 border border-zinc-200 group hover:border-black transition-all shadow-sm">
            <div className="flex justify-between items-start mb-6">
              <h3 className="text-3xl font-black text-black tracking-tighter uppercase leading-none">{event.title}</h3>
              <div className="flex items-center gap-2 text-[10px] font-black uppercase bg-zinc-50 px-3 py-1 border border-zinc-100">
                <Clock className="w-3 h-3" /> {event.time || '--:--'}
              </div>
            </div>
            <div className="flex items-center gap-2 text-[10px] font-black uppercase text-zinc-400 mb-8 border-b border-zinc-50 pb-4">
              <Calendar className="w-3 h-3" /> {event.date}
            </div>
            <div className="grid grid-cols-3 gap-6 mb-10">
               <EventStatus label="Pactado" amount={event.totalPrice} curr={event.currency} />
               <EventStatus label="Abonado" amount={event.paidAmount} curr={event.currency} green />
               <EventStatus label="Restan" amount={event.remainingAmount} curr={event.currency} red />
            </div>
            <div className="flex gap-4 mt-auto">
               <button onClick={() => { setEditingId(event.id); setFormData({ ...event, totalPrice: String(event.totalPrice), paidAmount: String(event.paidAmount) }); setShowForm(true); }} className="flex-1 p-4 border-2 border-zinc-50 hover:bg-black hover:text-white transition-all text-black font-black uppercase text-[10px] flex items-center justify-center gap-2">Editar</button>
               <button onClick={() => setClosingEvent(event)} className="flex-[2] bg-black text-white p-4 font-black uppercase text-[10px] tracking-widest shadow-lg flex items-center justify-center gap-2 hover:bg-zinc-800 transition-all">Liquidar Nómina <CheckCircle2 className="w-4 h-4" /></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

