  // New Local States for UI Features
  const [searchQuery, setSearchQuery] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('ALL');
  const [typeFilter, setTypeFilter] = useState('ALL');

  const [formData, setFormData] = useState({ 
    type: 'INCOME', amount: '', currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' 
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    let finalCategory = formData.category;
    if (showNewCategoryInput && newCategoryName.trim()) {
      finalCategory = newCategoryName.trim();
      if (!categories.includes(finalCategory)) setCategories([...categories, finalCategory]);
    }
    const finalAmount = cleanNumber(formData.amount);
    const data = { ...formData, category: finalCategory, amount: finalAmount };
    if (editingId) setTransactions((prev: Transaction[]) => prev.map(t => t.id === editingId ? { ...data, id: editingId } : t));
    else setTransactions((prev: Transaction[]) => [{ ...data, id: Date.now().toString() }, ...prev]);
    resetForm();
  };

  const handleExchange = (e: React.FormEvent) => {
    e.preventDefault();
    const usdAmount = cleanNumber(usdToExchange);
    const rate = cleanNumber(exchangeRate);
    if (usdAmount <= 0 || rate <= 0) return;
    const date = new Date().toISOString().split('T')[0];
    const usdOut: Transaction = { id: 'ex-out-' + Date.now(), type: 'EXPENSE', amount: usdAmount, currency: 'USD', description: `Venta Divisa USD @ ${rate}`, date, category: 'Divisas' };
    const dopIn: Transaction = { id: 'ex-in-' + Date.now(), type: 'INCOME', amount: usdAmount * rate, currency: 'DOP', description: `Compra Divisa DOP @ ${rate}`, date, category: 'Divisas' };
    setTransactions((prev: Transaction[]) => [usdOut, dopIn, ...prev]);
    setShowExchange(false); setUsdToExchange(''); setExchangeRate('');
  };

  const resetForm = () => {
    setShowForm(false); setEditingId(null); setShowNewCategoryInput(false); setNewCategoryName('');
    setFormData({ type: 'INCOME', amount: '', currency: 'DOP', description: '', date: new Date().toISOString().split('T')[0], category: categories[0] || 'General' });
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const rows = (event.target?.result as string).split(/\r?\n/);
      const newTransactions: Transaction[] = [];
      const newCats = new Set(categories);
      rows.forEach((row, index) => {
        if (index === 0 && (row.toLowerCase().includes('fecha') || row.toLowerCase().includes('date'))) return;
        if (!row.trim()) return;
        const col = row.split(';').length > 1 ? row.split(';') : row.split(',');
        const cleanCol = col.map(c => c.trim().replace(/^"|"$/g, ''));
        if (cleanCol.length >= 5) {
          const finalAmount = cleanNumber(cleanCol[3]);
          const type: 'INCOME' | 'EXPENSE' = cleanCol[4].toLowerCase().includes('ingreso') || cleanCol[4].toLowerCase().includes('income') ? 'INCOME' : 'EXPENSE';
          newTransactions.push({ 
            id: `i-${Date.now()}-${index}`, 
            date: cleanCol[0], 
            category: cleanCol[1] || 'General', 
            description: cleanCol[2], 
            amount: Math.abs(finalAmount), 
            type, 
            currency: (cleanCol[6]?.toUpperCase() === 'USD' ? 'USD' : 'DOP') as Currency 
          });
          if (cleanCol[1]) newCats.add(cleanCol[1]);
        }
      });
      setTransactions((prev: Transaction[]) => [...newTransactions, ...prev]);
      setCategories(Array.from(newCats));
      alert(`Sincronización de datos CSV completada.`);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const filteredData = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = categoryFilter === 'ALL' || t.category === categoryFilter;
      const matchesType = typeFilter === 'ALL' || t.type === typeFilter;
      return matchesSearch && matchesCategory && matchesType;
    });
  }, [transactions, searchQuery, categoryFilter, typeFilter]);

  const categorySummary = useMemo(() => {
    const summary: Record<string, { income: number, expense: number }> = {};
    filteredData.forEach(t => {
      if (!summary[t.category]) summary[t.category] = { income: 0, expense: 0 };
      if (t.type === 'INCOME') summary[t.category].income += t.amount;
      else summary[t.category].expense += t.amount;
    });
    return summary;
  }, [filteredData]);

  return (
    <div className="bg-white border border-zinc-200 shadow-xl pb-20 overflow-hidden rounded-none">
      <div className="p-12 border-b flex justify-between items-center bg-white font-black">
        <h3 className="text-2xl font-black uppercase tracking-widest flex items-center gap-4">
          <Wallet className="w-8 h-8 text-black" />
          Libro Mayor de Caja
        </h3>
        <div className="flex gap-4">
          <input type="file" ref={fileInputRef} onChange={handleImportCSV} accept=".csv" className="hidden" />
          <button onClick={() => fileInputRef.current?.click()} className="border-4 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all">
            <Upload className="w-4 h-4" /> Importar
          </button>
          <button onClick={() => {setShowExchange(!showExchange); setShowForm(false);}} className="border-4 border-black px-6 py-2 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-50 transition-all">
            <RefreshCcw className="w-4 h-4" /> Cambio Divisa
          </button>
          <button onClick={() => { setShowForm(true); setEditingId(null); setShowExchange(false); }} className="bg-black text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-zinc-800 transition-all">
            + Registro Maestro
          </button>
        </div>
      </div>

      {/* Stats Summary per Category Bar */}
      <div className="bg-zinc-50 p-6 border-b flex gap-6 overflow-x-auto">
        {Object.entries(categorySummary).slice(0, 6).map(([cat, vals]) => (
          <div key={cat} className="flex-shrink-0 bg-white p-4 border border-zinc-200 min-w-[160px]">
            <div className="text-[8px] font-black uppercase text-zinc-400 mb-1">{cat}</div>
            <div className="flex flex-col">
              <span className="text-green-600 text-[10px] font-black tracking-tighter">+{vals.income.toLocaleString()}</span>
              <span className="text-red-500 text-[10px] font-black tracking-tighter">-{vals.expense.toLocaleString()}</span>
            </div>
          </div>
        ))}
      </div>

      {showExchange && (
        <form onSubmit={handleExchange} className="p-12 bg-zinc-900 text-white grid grid-cols-3 gap-10 animate-in slide-in-from-top-10">
           <div className="col-span-3 flex justify-between items-center border-b border-zinc-800 pb-4">
             <h4 className="text-[11px] font-black uppercase tracking-[0.3em] flex items-center gap-3">Operación Cambiaria (USD -> DOP)</h4>
             <button type="button" onClick={() => setShowExchange(false)} className="text-zinc-500 hover:text-white uppercase text-[9px] font-black">Cerrar</button>
           </div>
           <div>
             <label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Cantidad USD Venta</label>
             <input required type="text" inputMode="decimal" value={usdToExchange} onChange={e => setUsdToExchange(e.target.value)} className="w-full bg-zinc-800 border-none p-5 font-black text-white outline-none focus:ring-4 ring-white/10 transition-all text-xl" />
           </div>
           <div>
             <label className="block text-[11px] font-black uppercase text-zinc-500 mb-3 tracking-widest">Tasa Acordada RD$</label>
             <input required type="text" inputMode="decimal" value={exchangeRate} onChange={e => setExchangeRate(e.target.value)} className="w-full bg-zinc-800 border-none p-5 font-black text-white outline-none focus:ring-4 ring-white/10 transition-all text-xl" />
           </div>
           <div className="flex items-end">
             <button type="submit" className="w-full bg-white text-black py-6 text-[11px] font-black uppercase tracking-widest hover:bg-zinc-200 shadow-2xl transition-all font-black">Confirmar Cambio de Divisa</button>
           </div>
        </form>
      )}

      {showForm && !editingId && (
        <div className="p-12 bg-zinc-50 border-b animate-in slide-in-from-top-4">
          <form onSubmit={handleSave} className="grid grid-cols-4 gap-6">
            <FormFields formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
            <div className="col-span-4 flex gap-4 pt-4">
              <button type="button" onClick={resetForm} className="flex-1 border-2 border-zinc-200 py-4 text-[11px] font-black uppercase text-zinc-400">Descartar</button>
              <button type="submit" className="flex-[2] bg-black text-white py-4 text-[11px] font-black uppercase tracking-widest shadow-xl">Confirmar Registro</button>
            </div>
          </form>
        </div>
      )}

      {/* Search & Internal Filters */}
      <div className="px-12 py-6 bg-white border-b flex gap-6 items-center">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-300" />
          <input 
            type="text" 
            placeholder="Buscar por descripción o concepto..." 
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="w-full pl-12 pr-4 py-3 border-2 border-zinc-100 font-bold text-xs focus:border-black outline-none"
          />
        </div>
        <select 
          value={categoryFilter} 
          onChange={e => setCategoryFilter(e.target.value)}
          className="p-3 border-2 border-zinc-100 font-black uppercase text-[10px] outline-none"
        >
          <option value="ALL">Todas las Categorías</option>
          {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
        </select>
        <select 
          value={typeFilter} 
          onChange={e => setTypeFilter(e.target.value)}
          className="p-3 border-2 border-zinc-100 font-black uppercase text-[10px] outline-none"
        >
          <option value="ALL">Todos los Movimientos</option>
          <option value="INCOME">Solo Ingresos (+)</option>
          <option value="EXPENSE">Solo Gastos (-)</option>
        </select>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-zinc-50 border-b font-black text-[11px] uppercase tracking-widest text-zinc-400">
            <tr>
              <th className="px-12 py-6">Fecha</th>
              <th className="px-12 py-6">Concepto Maestro</th>
              <th className="px-12 py-6">Categoría</th>
              <th className="px-12 py-6 text-right">Monto Operativo</th>
              <th className="px-12 py-6 text-right">Acción</th>
            </tr>
          </thead>
          <tbody>
            {filteredData.map(t => (
              <React.Fragment key={t.id}>
                {editingId === t.id ? (
                  <tr className="bg-zinc-900 text-white animate-in fade-in duration-300">
                    <td colSpan={5} className="p-10">
                      <form onSubmit={handleSave} className="grid grid-cols-4 gap-6">
                        <div className="col-span-4 flex justify-between items-center mb-4">
                          <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500 flex items-center gap-2">
                            <Pencil className="w-3 h-3" /> Modo Edición de Registro
                          </span>
                          <div className="flex gap-4">
                            <button type="button" onClick={resetForm} className="text-zinc-500 hover:text-white uppercase text-[10px] font-black px-4 py-2 border border-zinc-700 transition-colors">Cancelar</button>
                            <button type="submit" className="bg-white text-black uppercase text-[10px] font-black px-6 py-2 shadow-lg hover:bg-zinc-200 transition-all">Sincronizar Cambios</button>
                          </div>
                        </div>
                        <FormFields inline formData={formData} setFormData={setFormData} categories={categories} showNewCategoryInput={showNewCategoryInput} setShowNewCategoryInput={setShowNewCategoryInput} newCategoryName={newCategoryName} setNewCategoryName={setNewCategoryName} />
                      </form>
                    </td>
                  </tr>
                ) : (
                  <tr className="hover:bg-zinc-50 group transition-all border-b last:border-0 border-zinc-100">
                    <td className="px-12 py-8 text-[10px] font-black text-zinc-400 uppercase tracking-tighter">
                      {t.date}
                    </td>
                    <td className="px-12 py-8 font-black text-black uppercase text-xs truncate max-w-[300px] flex items-center gap-3">
                      {t.type === 'INCOME' ? <ArrowUpRight className="w-4 h-4 text-green-600" /> : <ArrowDownLeft className="w-4 h-4 text-red-500" />}
                      {t.description}
                    </td>
                    <td className="px-12 py-8">
                      <span className="text-[9px] font-black uppercase border-2 border-zinc-100 px-3 py-1 bg-white text-zinc-700 tracking-widest">
                        {t.category}
                      </span>
                    </td>
                    <td className={`px-12 py-8 text-right font-black text-base ${t.type === 'INCOME' ? 'text-black' : 'text-zinc-400'}`}>
                      <span className="text-[10px] mr-1 opacity-40">{t.currency}</span>
                      {t.type === 'INCOME' ? '+' : '-'}{t.amount.toLocaleString()}
                    </td>
                    <td className="px-12 py-8 text-right space-x-6 opacity-0 group-hover:opacity-100 transition-all">
                      <button onClick={() => { setEditingId(t.id); setFormData({ ...t, amount: String(t.amount) }); setShowForm(false); setShowExchange(false); }} className="text-zinc-400 hover:text-black uppercase text-[10px] font-black border-b border-transparent hover:border-black transition-all">Editar</button>
                      <button onClick={() => setTransactions((prev: Transaction[]) => prev.filter(tr => tr.id !== t.id))} className="text-zinc-200 hover:text-red-600 uppercase text-[10px] font-black transition-all">Borrar</button>
                    </td>
                  </tr>
                )}
              </React.Fragment>
            ))}
            {filteredData.length === 0 && (
              <tr>
                <td colSpan={5} className="p-32 text-center font-black uppercase text-zinc-200 tracking-[0.4em]">
                  Sin registros que coincidan con la búsqueda
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const FormFields: React.FC<{ inline?: boolean, formData: any, setFormData: any, categories: string[], showNewCategoryInput: boolean, setShowNewCategoryInput: any, newCategoryName: string, setNewCategoryName: any }> = ({ inline, formData, setFormData, categories, showNewCategoryInput, setShowNewCategoryInput, newCategoryName, setNewCategoryName }) => {
  const inputClass = `w-full p-4 border-2 font-black outline-none transition-all ${inline ? 'bg-zinc-800 border-zinc-700 text-white focus:border-white' : 'bg-white border-zinc-200 text-black focus:border-black'}`;
  const labelClass = `block text-[9px] font-black uppercase mb-2 text-zinc-500 tracking-widest`;
  return (
    <>
      <div>
        <label className={labelClass}>Sentido del Movimiento</label>
        <select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className={inputClass}>
          <option value="INCOME">Ingreso de Caja (+)</option>
          <option value="EXPENSE">Gasto Operativo (-)</option>
        </select>
      </div>
      <div>
        <label className={labelClass}>Divisa de Operación</label>
        <select value={formData.currency} onChange={e => setFormData({...formData, currency: e.target.value as Currency})} className={inputClass}>
          <option value="DOP">DOP (Pesos)</option>
          <option value="USD">USD (Dólares)</option>
        </select>
      </div>
      <div>
        <label className={labelClass}>Monto Exacto</label>
        <input required type="text" inputMode="decimal" value={formData.amount} onChange={e => setFormData({...formData, amount: e.target.value})} className={inputClass} />
      </div>
      <div>
        <label className={labelClass}>Categorización del Gasto/Ingreso</label>
        <select value={showNewCategoryInput ? "NEW" : formData.category} onChange={e => { if (e.target.value === "NEW") setShowNewCategoryInput(true); else { setShowNewCategoryInput(false); setFormData({...formData, category: e.target.value}); } }} className={inputClass}>
          {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
          <option value="NEW">+ Añadir Nueva Categoría...</option>
        </select>
        {showNewCategoryInput && <input autoFocus placeholder="Nombre de Categoría..." type="text" value={newCategoryName} onChange={e => setNewCategoryName(e.target.value)} className={`w-full mt-2 p-3 text-[10px] font-black uppercase border-2 ${inline ? 'bg-black border-zinc-500 text-white' : 'bg-white border-black text-black'}`} />}
      </div>
      <div className="col-span-2">
        <label className={labelClass}>Concepto o Descripción</label>
        <input required type="text" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className={inputClass} />
      </div>
      <div className="col-span-2">
        <label className={labelClass}>Fecha de Registro Contable</label>
        <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className={inputClass} />
      </div>
    </>
  );
};

export default App;

